import React, { useState, useEffect, useRef } from 'react';
import { Store } from '../types';
import { Bell, Lock, Unlock, Coins } from 'lucide-react';

interface StoreCardProps {
  store: Store;
  onClick: (store: Store) => void;
}

const StoreCard: React.FC<StoreCardProps> = ({ store, onClick }) => {
  const [animateSuccess, setAnimateSuccess] = useState(false);
  const prevIsLinked = useRef(store.isLinked);

  useEffect(() => {
    if (!prevIsLinked.current && store.isLinked) {
        setAnimateSuccess(true);
        const timer = setTimeout(() => setAnimateSuccess(false), 2000);
        return () => clearTimeout(timer);
    }
    prevIsLinked.current = store.isLinked;
  }, [store.isLinked]);

  // Conversion: 100 points = R1.00
  const randValue = (store.loyaltyPoints / 100).toFixed(2);

  const renderCardContent = () => {
    switch(store.id) {
      case 'picknpay':
        return (
          <div className="h-full w-full bg-[#0b1f3f] text-white p-4 relative overflow-hidden border border-white/5">
             <div className="absolute -right-6 -top-6 w-32 h-32 rounded-full border-[16px] border-[#b91c68] opacity-15"></div>

             <div className="relative z-10 flex flex-col h-full justify-between">
                <div className="flex justify-between items-start">
                    <div>
                        <div className="text-[9px] font-bold uppercase tracking-widest mb-1 text-slate-400">Pick n Pay</div>
                        <div className="text-xl font-bold italic tracking-tighter leading-none font-sans text-slate-200">
                            smart<br/>shopper
                        </div>
                    </div>
                    <div className="bg-[#b91c68] w-6 h-6 rounded-full flex items-center justify-center text-[8px] opacity-90 font-bold">
                        PnP
                    </div>
                </div>

                <div className="flex justify-between items-end">
                    <div className="text-[10px] font-mono tracking-wider text-slate-500">
                        {store.isLinked ? '6007 **** 1234' : 'Not Linked'}
                    </div>
                    {store.isLinked && (
                        <div className="text-right">
                            <div className="text-[10px] font-bold text-white leading-none">{store.loyaltyPoints} pts</div>
                            <div className="text-[9px] font-medium text-amber-400">R {randValue}</div>
                        </div>
                    )}
                </div>
             </div>
          </div>
        );

      case 'shoprite':
        return (
           <div className="h-full w-full bg-[#00857b] text-white p-4 relative overflow-hidden border border-white/5">
               <div className="absolute -bottom-8 -right-8 w-32 h-32 rounded-full bg-[#e53935] opacity-10"></div>

               <div className="relative z-10 flex flex-col h-full justify-between">
                  <div className="flex items-center justify-between">
                     <div className="text-[#ffebee] font-bold text-[10px] tracking-widest uppercase">
                        Shoprite
                     </div>
                     {store.isLinked && (
                         <div className="bg-white/10 px-2 py-0.5 rounded text-[8px] font-bold text-amber-300 border border-white/10">
                            VALUE: R {randValue}
                         </div>
                     )}
                  </div>

                  <div className="mb-1 flex justify-between items-end">
                     <div className="text-2xl font-black italic tracking-tighter text-white leading-none">
                        Xtra<br/>Savings
                     </div>
                     {store.isLinked && <div className="text-[10px] font-bold">{store.loyaltyPoints} pts</div>}
                  </div>
               </div>
           </div>
        );

      case 'clicks':
         return (
            <div className="h-full w-full bg-[#005ca8] text-white p-4 relative overflow-hidden border-t-4 border-[#c2a87c]">
                <div className="relative z-10 flex flex-col h-full justify-between pt-1">
                   <div className="flex justify-between items-start">
                       <div className="font-serif font-bold text-lg tracking-wide text-white">
                          CLICKS
                       </div>
                       {store.isLinked && (
                           <div className="text-right">
                               <div className="text-[10px] font-bold">{store.loyaltyPoints} pts</div>
                               <div className="text-[9px] text-[#c2a87c] font-bold">R {randValue}</div>
                           </div>
                       )}
                   </div>

                   <div className="flex flex-col items-end">
                      <div className="text-xl font-bold tracking-tight text-white">ClubCard</div>
                      <div className="text-[6px] uppercase tracking-[0.25em] text-[#c2a87c] font-bold mt-1">
                        Feel Good Pay Less
                      </div>
                   </div>
                </div>
            </div>
         );

      default:
        return (
            <div className="h-full w-full p-4 relative overflow-hidden text-white bg-slate-600">
                <div className="absolute inset-0 bg-black/10"></div>
                <div className="relative z-10 flex flex-col h-full justify-between">
                    <div className="flex justify-between items-start">
                        <div className="flex items-center space-x-2">
                            <div className="w-8 h-8 bg-black/20 rounded-full flex items-center justify-center text-sm shadow-sm">
                               {store.logo}
                            </div>
                            <span className="font-bold tracking-wide text-sm">{store.name}</span>
                        </div>
                        {store.isLinked && (
                            <div className="text-right">
                                <div className="text-xs font-bold">{store.loyaltyPoints} pts</div>
                                <div className="text-[10px] text-amber-400">R {randValue}</div>
