import React, { useState, useEffect } from 'react';
import { User } from '../types';
import WalletCard from './WalletCard';
import { Settings, ArrowRight, Banknote, Coins, CheckCircle, Ticket, X, ShoppingCart, Calculator, Lock, QrCode, Smartphone, Scan, Power, RefreshCw, Timer } from 'lucide-react';

interface WalletViewProps {
  user: User;
  onUpdateSettings: (target: number) => void;
  onUpdateBalance: (amount: number) => void;
  onToggleAutoSave: () => void;
}

type WithdrawType = 'STORE' | null;

const WalletView: React.FC<WalletViewProps> = ({ user, onUpdateSettings, onUpdateBalance, onToggleAutoSave }) => {
  const [withdrawType, setWithdrawType] = useState<WithdrawType>(null);
  const [amount, setAmount] = useState<string>('');
  const [processing, setProcessing] = useState(false);
  const [generatedToken, setGeneratedToken] = useState<string | null>(null);
  const [tokenExpiry, setTokenExpiry] = useState<number | null>(null);
  const [timeLeft, setTimeLeft] = useState<string>('30:00');
  const [isRotating, setIsRotating] = useState(false);

  const MIN_WITHDRAWAL = 10;
  const ROTATION_INTERVAL_MS = 30 * 60 * 1000; // 30 minutes

  // Handle countdown and auto-rotation
  useEffect(() => {
    if (!generatedToken || !tokenExpiry) return;

    const interval = setInterval(() => {
      const now = Date.now();
      const diff = tokenExpiry - now;

      if (diff <= 0) {
        // Time is up, rotate the token
        const newToken = Math.floor(10000 + Math.random() * 90000).toString();
        setIsRotating(true);
        setGeneratedToken(newToken);
        setTokenExpiry(Date.now() + ROTATION_INTERVAL_MS);
        setTimeout(() => setIsRotating(false), 1000);
      } else {
        // Update countdown string
        const mins = Math.floor(diff / 60000);
        const secs = Math.floor((diff % 60000) / 1000);
        setTimeLeft(`${mins}:${secs.toString().padStart(2, '0')}`);
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [generatedToken, tokenExpiry]);

  // Dynamic Calculation for Explanation
  const examplePrice = 96.50; 
  const examplePayment = 100.00;
  const roundUpTarget = 1; 
  const roundedUpBill = Math.ceil(examplePrice / roundUpTarget) * roundUpTarget;
  const savingsAmount = roundedUpBill - examplePrice;
  const normalChange = examplePayment - examplePrice; 

  const handleWithdraw = () => {
      if (!amount) return;
      const withdrawAmount = parseFloat(amount);

      if (withdrawAmount < MIN_WITHDRAWAL) return;
      if (withdrawAmount > user.miCoinBalance) return;

      setProcessing(true);

      // Generate initial token
      const token = Math.floor(10000 + Math.random() * 90000).toString();

      setTimeout(() => {
          onUpdateBalance(-withdrawAmount);
          setProcessing(false);
          setGeneratedToken(token);
          setTokenExpiry(Date.now() + ROTATION_INTERVAL_MS);
          // Amount state is cleared but kept for the receipt view
      }, 2000);
  };

  const handleCloseToken = () => {
      setGeneratedToken(null);
      setTokenExpiry(null);
      setWithdrawType(null);
      setAmount('');
  };

  // Store Cashout Token Modal
  if (generatedToken && withdrawType === 'STORE') {
      return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-900/90 backdrop-blur-sm animate-in fade-in duration-300">
            <div className="w-full max-w-sm relative">
                 <button 
                    onClick={handleCloseToken}
                    className="absolute -top-12 right-0 p-2 bg-white/10 rounded-full text-white hover:bg-white/20"
                >
                    <X className="w-6 h-6" />
                </button>

                <div className="bg-white rounded-[2rem] shadow-2xl overflow-hidden relative">
                    {/* Ticket Header */}
                    <div className="bg-stone-900 p-6 text-center pt-8 pb-10 relative overflow-hidden">
                        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-brand-400 via-brand-500 to-brand-400"></div>
                        <div className="absolute -left-4 top-1/2 -translate-y-1/2 w-8 h-8 bg-slate-900/90 rounded-full"></div>
                        <div className="absolute -right-4 top-1/2 -translate-y-1/2 w-8 h-8 bg-slate-900/90 rounded-full"></div>

                        <h3 className="text-white font-black text-xl uppercase tracking-[0.2em] mb-1">Cash Voucher</h3>
                        <p className="text-stone-400 text-[10px] uppercase tracking-wider">Secure Rotating Token</p>
                    </div>

                    {/* Dotted Line */}
                    <div className="border-b-2 border-dashed border-stone-200 mx-6 -mt-[1px]"></div>

                    <div className="p-8 text-center bg-white">
                        <div className="mb-6">
                            <p className="text-stone-400 text-[10px] uppercase tracking-widest font-bold mb-1">Amount</p>
                            <div className="flex items-baseline justify-center text-stone-900">
                                <span className="text-xl font-medium mr-1">R</span>
                                <span className="text-5xl font-black tracking-tight">{parseFloat(amount || '0').toFixed(2)}</span>
                            </div>
                        </div>

                        {/* QR Code Area - Updates when token rotates */}
                        <div className="flex justify-center mb-8 relative">
                             <div className={`relative group transition-transform duration-500 ${isRotating ? 'scale-95 opacity-50' : 'scale-100'}`}>
                                <div className="bg-white p-4 rounded-2xl border-2 border-stone-900 shadow-[0_8px_30px_rgb(0,0,0,0.12)]">
                                    {/* QR content is effectively the token */}
                                    <QrCode className="w-40 h-40 text-stone-900" />
                                </div>
                                <div className="absolute -bottom-3 left-1/2 -translate-x-1/2 bg-stone-900 text-white text-[10px] px-3 py-1 rounded-full font-bold shadow-md flex items-center whitespace-nowrap">
                                    <Scan className="w-3 h-3 mr-1" /> Scan at Till
                                </div>
                             </div>
                        </div>

                        {/* PIN Code with Rotation Indicator */}
                        <div className="mb-8">
                            <div className="flex items-center justify-center space-x-2 mb-3">
                                <p className="text-stone-400 text-[10px] uppercase tracking-widest font-bold">5-Digit PIN</p>
                                <div className="flex items-center space-x-1 bg-stone-100 px-2 py-0.5 rounded-full text-brand-600 font-bold text-[9px]">
                                    <Timer className="w-2.5 h-2.5" />
                                    <span>{timeLeft}</span>
                                </div>
                            </div>
                            <div className={`flex justify-center space-x-2 transition-all duration-500 ${isRotating ? 'scale-110 blur-sm' : ''}`}>
                                {generatedToken.split('').map((digit, i) => (
                                    <div key={i} className="w-10 h-14 flex items-center justify-center bg-stone-100 rounded-lg border border-stone-200 text-2xl font-bold text-stone-800 shadow-sm">
                                        {digit}
                                    </div>
                                ))}
                            </div>
                        </div>

                        {/* Instructions */}
                        <div className="bg-brand-50 rounded-xl p-4 text-left flex items-start space-x-3 mb-6">
                             <RefreshCw className={`w-5 h-5 text-brand-600 flex-shrink-0 mt-0.5 ${isRotating ? 'animate-spin' : ''}`} />
                             <div className="space-y-1">
                                <p className="text-xs font-bold text-brand-900">Security Rotation:</p>
                                <p className="text-[11px] text-brand-700 leading-tight">
                                    For your protection, this code refreshes every 30 minutes. Ensure the cashier scans the latest version.
                                </p>
                             </div>
                        </div>

                        <div className="flex items-center justify-center space-x-2 text-stone-400 text-[10px] font-medium bg-stone-50 py-2 rounded-lg">
                             <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                             <span>Voucher stays valid for 3 hours</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
      );
  }

  // Withdrawal Modal
  if (withdrawType) {
      const currentAmount = parseFloat(amount || '0');
      const isInvalidAmount = currentAmount < MIN_WITHDRAWAL;
      const hasInsufficientFunds = currentAmount > user.miCoinBalance;

      return (
          <div className="h-full p-5 flex flex-col bg-white dark:bg-slate-900 animate-in slide-in-from-bottom-10">
               <div className="flex justify-between items-center mb-6">
                  <h2 className="text-xl font-bold text-gray-900 dark:text-white">
                      Store Cashout
                  </h2>
                  <button onClick={() => setWithdrawType(null)} className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full">
                      <X className="w-5 h-5 text-gray-500" />
                  </button>
              </div>

              <div className="mb-6 p-4 bg-brand-50 dark:bg-brand-900/20 border border-brand-200 dark:border-brand-700/50 rounded-2xl flex items-start shadow-sm">
                  <div className="bg-white dark:bg-slate-800 p-2 rounded-xl mr-3 shadow-sm">
                    <QrCode className="w-6 h-6 text-brand-600 dark:text-brand-400" />
                  </div>
                  <div>
                      <h4 className="text-sm font-bold text-brand-900 dark:text-brand-300">New: Secure Rotating QR</h4>
                      <p className="text-xs text-brand-700 dark:text-brand-400/80 mt-1 leading-relaxed">
                          Your withdrawal PIN and QR code will rotate every 30 minutes for maximum security at the point of sale.
                      </p>
                  </div>
              </div>

              <div className="flex-1">
                  <label className="block text-sm font-medium text-gray-700 dark:text-slate-300 mb-2">Withdrawal Amount</label>
                  <div className="relative group">
                      <span className="absolute left-4 top-4 text-gray-400 font-bold group-focus-within:text-brand-500 transition-colors">R</span>
                      <input 
                        type="number" 
                        value={amount}
                        onChange={(e) => setAmount(e.target.value)}
                        className="w-full p-4 pl-8 bg-slate-50 dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 outline-none focus:ring-2 focus:ring-brand-500 text-xl font-mono dark:text-white font-bold transition-all shadow-sm"
                        placeholder="0.00"
                        autoFocus
                      />
                  </div>

                  <div className="flex justify-between items-start mt-3 px-1">
                    {isInvalidAmount && amount ? (
                        <p className="text-xs text-red-500 font-medium bg-red-50 px-2 py-1 rounded-md">Min withdrawal R{MIN_WITHDRAWAL}</p>
                    ) : (
                        <span></span>
                    )}
                    <p className="text-xs text-gray-500 dark:text-slate-400 text-right">
                      Balance: <span className="font-bold text-gray-700 dark:text-white">R {user.miCoinBalance.toFixed(2)}</span>
                    </p>
                  </div>
              </div>

              <div className="mt-auto">
                <button 
                    disabled={!amount || isInvalidAmount || hasInsufficientFunds || processing}
                    onClick={handleWithdraw}
                    className="w-full py-4 bg-brand-600 disabled:bg-slate-200 dark:disabled:bg-slate-800 disabled:text-gray-400 dark:disabled:text-slate-600 text-white rounded-2xl font-bold shadow-xl shadow-brand-500/20 text-lg transition-all active:scale-[0.98]"
                >
                    {processing ? 'Generating...' : 'Confirm Cashout'}
                </button>
              </div>
          </div>
      );
  }

  return (
    <div className="flex flex-col h-full pb-24">
      <div className="p-5 space-y-6">
        <div className="flex justify-between items-center">
             <h2 className="text-2xl font-bold text-gray-900 dark:text-white">MiCOINBANK</h2>
        </div>

        <WalletCard user={user} />

        <div className="w-full bg-white dark:bg-slate-800 p-1 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-700">
            <button 
                onClick={() => setWithdrawType('STORE')}
                className="w-full flex flex-row items-center justify-between p-5 rounded-[1.4rem] bg-gradient-to-br from-brand-50 to-white dark:from-slate-800 dark:to-slate-800/50 hover:from-brand-100 dark:hover:from-slate-700 transition-all group"
            >
                <div className="flex items-center">
                    <div className="w-12 h-12 bg-white dark:bg-slate-700 rounded-2xl flex items-center justify-center shadow-sm mr-4 group-hover:scale-110 transition-transform text-brand-600">
