                <div key={tx.id} className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 transition-colors">
                  <div className="flex justify-between items-center mb-2">
                    <span className="font-semibold text-gray-800 dark:text-white">{tx.store}</span>
                    <span className={`text-xs px-2 py-1 rounded-full ${tx.type === 'CASHBACK' ? 'bg-accent-500/10 text-accent-500' : 'bg-slate-100 dark:bg-slate-700 text-gray-500 dark:text-slate-400'}`}>
                        {tx.type === 'CASHBACK' ? 'Cashback Reward' : tx.category}
                    </span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <div className="text-gray-500 dark:text-slate-400">
                      {tx.type === 'CASHBACK' ? (
                          <span>Promo Item</span>
                      ) : (
                          <span>Original: R {tx.amount.toFixed(2)}</span>
                      )}
                    </div>
                    <div className="font-medium text-brand-600 dark:text-brand-400">
                      {tx.type === 'CASHBACK' ? '+' : ''} R {tx.savings.toFixed(2)} {tx.type === 'CASHBACK' ? 'Added' : 'Saved'}
