          {/* Bottom Navigation */}
          {activeTab !== AppTab.STORE_VIEW && (
            <nav className="bg-white dark:bg-slate-800 border-t border-gray-200 dark:border-slate-700 fixed bottom-0 w-full max-w-lg pb-safe z-30 transition-colors">
              <div className="flex justify-around items-center h-16">
                <button 
                  onClick={() => setActiveTab(AppTab.DASHBOARD)}
                  className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${activeTab === AppTab.DASHBOARD ? 'text-brand-600 dark:text-brand-400' : 'text-gray-400 dark:text-slate-500'}`}
                >
                  <Home className="w-6 h-6" />
