                            <div className="inline-flex items-center space-x-2 bg-green-50 text-green-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest mb-4">
                                <CheckCircle className="w-3 h-3" />
                                <span>Transaction Recorded</span>
