                            </div>
                        </div>

                        <div className="flex justify-center mb-8 relative">
                             <div className={`relative group transition-transform duration-500 ${isRotating ? 'scale-95 opacity-50' : 'scale-100'}`}>
                                <div className="bg-white p-5 rounded-3xl border-2 border-stone-900 shadow-[0_15px_40px_rgba(0,0,0,0.1)]">
                                    <QrCode className="w-40 h-40 text-stone-900" />
                                </div>
                                <div className="absolute -bottom-3 left-1/2 -translate-x-1/2 bg-stone-900 text-white text-[10px] px-4 py-1.5 rounded-full font-bold shadow-lg flex items-center whitespace-nowrap">
                                    <Scan className="w-3 h-3 mr-2" /> Scan at Point of Sale
                                </div>
                             </div>
                        </div>

                        <div className="mb-8">
                            <div className="flex items-center justify-center space-x-2 mb-4">
                                <p className="text-stone-400 text-[10px] uppercase tracking-widest font-bold">5-Digit PIN</p>
                                <div className="flex items-center space-x-1.5 bg-brand-50 px-3 py-1 rounded-full text-brand-600 font-black text-[10px] shadow-sm">
                                    <Timer className="w-3 h-3" />
                                    <span>REFRESHES IN {timeLeft}</span>
                                </div>
                            </div>
                            <div className={`flex justify-center space-x-2 transition-all duration-500 ${isRotating ? 'scale-110 blur-md' : ''}`}>
                                {generatedToken.split('').map((digit, i) => (
                                    <div key={i} className="w-11 h-16 flex items-center justify-center bg-stone-50 rounded-xl border-2 border-stone-100 text-3xl font-black text-stone-900 shadow-sm">
                                        {digit}
                                    </div>
                                ))}
                            </div>
                        </div>

                        <div className="bg-stone-50 rounded-2xl p-5 text-left flex items-start space-x-4 mb-6">
                             <div className="bg-brand-500 p-2 rounded-xl text-white shadow-md">
                                <RefreshCw className={`w-5 h-5 ${isRotating ? 'animate-spin' : ''}`} />
                             </div>
                             <div className="space-y-1">
                                <p className="text-xs font-black text-stone-900 uppercase">Always Live</p>
                                <p className="text-[11px] text-stone-500 leading-tight">
                                    This voucher rotates every 30 minutes for your protection. You can see this cashout in your <b>Activity History</b>.
                                </p>
                             </div>
                        </div>

                        <button 
                            onClick={handleCloseToken}
                            className="w-full py-4 bg-brand-600 text-white rounded-2xl font-black text-sm uppercase tracking-[0.1em] shadow-xl shadow-brand-500/20 active:scale-95 transition-transform"
                        >
                            Done - Return to Wallet
                        </button>
                    </div>
                </div>
            </div>
        </div>
      );
  }

  // Withdrawal Modal
  if (withdrawType) {
      const currentAmount = parseFloat(amount || '0');
      const isInvalidAmount = currentAmount < MIN_WITHDRAWAL;
      const hasInsufficientFunds = currentAmount > user.miCoinBalance;

      return (
          <div className="h-full p-5 flex flex-col bg-white dark:bg-slate-900 animate-in slide-in-from-bottom-10">
