import React, { useEffect, useState } from 'react';
import { ReceiptData, Store } from '../types';
import { X, Share2, Download, ScanLine, CheckCircle, Sparkles, ArrowLeft, Coins } from 'lucide-react';

interface DigitalReceiptProps {
  data: ReceiptData;
  store: Store;
  onClose: () => void;
}

const DigitalReceipt: React.FC<DigitalReceiptProps> = ({ data, store, onClose }) => {
  const [scanning, setScanning] = useState(true);
  const [scanProgress, setScanProgress] = useState(0);
  const [cashbackFound, setCashbackFound] = useState<number | null>(null);
  const [showNotification, setShowNotification] = useState(false);

  useEffect(() => {
    // Simulate scanning process
    const duration = 2000; // 2 seconds scan
    const interval = 20;
    const steps = duration / interval;
    let currentStep = 0;

    const timer = setInterval(() => {
      currentStep++;
      setScanProgress((currentStep / steps) * 100);

      if (currentStep >= steps) {
        clearInterval(timer);
        setScanning(false);

        // Calculate cashback from promo items
        const cashbackTotal = data.items.reduce((acc, item) => acc + (item.isPromo ? (item.price * 0.1) : 0), 0); // Mock logic: 10% cashback on promos

        if (cashbackTotal > 0) {
          setCashbackFound(cashbackTotal);
          setTimeout(() => setShowNotification(true), 500);
        }
      }
    }, interval);

    return () => clearInterval(timer);
  }, [data]);

  return (
    <div 
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200"
      onClick={onClose}
    >

      {/* Notification Overlay */}
      {showNotification && (
        <div className="absolute top-10 left-0 right-0 flex justify-center z-[60] animate-in slide-in-from-top-5 duration-500 pointer-events-none">
          <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl p-4 flex items-center space-x-4 max-w-xs border-l-4" style={{ borderLeftColor: store.color }}>
             <div className="bg-accent-500/10 p-2 rounded-full">
                <Sparkles className="w-6 h-6 text-accent-500 animate-pulse" />
             </div>
             <div>
                <h4 className="font-bold text-gray-900 dark:text-white text-sm">Cashback Processed!</h4>
                <p className="text-xs text-gray-500 dark:text-slate-300">
                  R {cashbackFound?.toFixed(2)} has been added to your MiCOIN wallet from {store.name}.
                </p>
             </div>
          </div>
        </div>
      )}

      <div 
        className="relative w-full max-w-md bg-white p-1 rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]"
        onClick={(e) => e.stopPropagation()} // Prevent click from closing when clicking the receipt itself
      >
        {/* Fixed Header with Close Button */}
        <div className="flex items-center justify-between p-4 bg-white border-b border-gray-100 z-50">
            <button 
                onClick={onClose}
                className="flex items-center space-x-2 text-gray-500 hover:text-gray-900 transition-colors py-2"
            >
                <ArrowLeft className="w-5 h-5" />
                <span className="text-sm font-bold uppercase tracking-wider">Back</span>
            </button>
            <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-sm shadow-inner">
                {store.logo}
            </div>
            <button 
                onClick={onClose}
                className="p-2 bg-gray-100 rounded-full hover:bg-gray-200 transition-colors"
            >
                <X className="w-5 h-5 text-gray-600" />
            </button>
        </div>

        {/* Receipt Container (Scrollable) */}
        <div 
            className="overflow-y-auto relative flex-1 font-mono text-xs text-gray-800 leading-tight transition-colors duration-700 pb-10" 
            style={{ 
                fontFamily: '"Courier Prime", "Courier New", monospace',
                backgroundColor: '#ffffff',
                backgroundImage: `radial-gradient(circle at top right, ${store.color}15, transparent 60%), radial-gradient(circle at bottom left, ${store.color}10, transparent 60%)`
            }}
        >

            {/* Watermark */}
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-0 overflow-hidden">
                 <div className="opacity-[0.04] transform -rotate-12 scale-150 flex flex-col items-center" style={{ color: store.color }}>
                     <div className="text-8xl mb-4">{store.logo}</div>
                     <div className="text-6xl font-black uppercase whitespace-nowrap">{store.name}</div>
                 </div>
            </div>

            {/* Scanning Laser Effect */}
            {scanning && (
              <div 
                className="absolute left-0 right-0 h-1 bg-red-500/50 shadow-[0_0_15px_rgba(239,68,68,0.8)] z-20 pointer-events-none transition-all ease-linear"
                style={{ top: `${scanProgress}%` }}
              >
                 <div className="absolute right-0 -top-3 bg-red-600 text-white text-[9px] px-1 py-0.5 rounded font-sans font-bold opacity-80">
                    ANALYZING
                 </div>
              </div>
            )}

            {/* Receipt Content */}
            <div className="p-6 pt-10 flex flex-col items-center text-center relative z-10">
                {/* Branding Header */}
                <div className="mb-2 flex flex-col items-center">
                   <div className="text-4xl mb-2">{store.logo}</div>
                   <div className="font-bold text-xl uppercase tracking-tighter">{store.name}</div>
                </div>

                <div className="mb-4 grayscale opacity-80 text-[10px]">
                    <div className="text-xs font-bold uppercase tracking-widest mb-1">{data.merchantName}</div>
                    {data.address.map((line, i) => <div key={i}>{line}</div>)}
                    <div className="mt-2">VAT NO: {data.vatNo}</div>
                    <div>TEL: {data.tel}</div>
                </div>

                <div className="w-full flex justify-between mb-2 border-b border-dashed border-gray-300 pb-2 text-[10px]">
                    <span>CASHIER: {data.cashier}</span>
                    <span>TAX INVOICE</span>
                </div>

                {/* Items List */}
                <div className="w-full space-y-3 mb-4 text-left">
                    {data.items.map((item, idx) => (
                        <div key={idx} className={`relative transition-colors duration-500 p-1 ${!scanning && item.isPromo ? 'bg-accent-500/10 -mx-1 px-1 rounded' : ''}`}>
                            <div className="flex justify-between font-bold text-gray-700">
                                <span className="max-w-[80%] uppercase">{item.description}</span>
                                <div className="flex items-center">
                                    {!scanning && item.isPromo && (
                                        <div className="flex items-center mr-1 animate-bounce">
                                            <Coins className="w-3 h-3 text-accent-500" />
                                        </div>
                                    )}
                                    <span className="flex-shrink-0">{item.total.toFixed(2)}</span>
                                </div>
                            </div>
                            <div className="flex justify-between text-gray-500 text-[10px]">
                                <span>{item.quantity} @ {item.price.toFixed(2)}</span>
                                <span>{item.isPromo ? '*' : ' '}</span>
                            </div>
                            {/* Promo Indicator found after scan */}
                            {!scanning && item.isPromo && (
                                <div className="flex items-center text-accent-600 font-bold text-[9px] mt-1 animate-pulse font-sans">
                                    <Sparkles className="w-3 h-3 mr-1" />
                                    <span>SMART SAVE DETECTED</span>
                                </div>
                            )}
                        </div>
                    ))}
                </div>

                {/* Totals */}
                <div className="w-full border-t border-dashed border-gray-400 pt-3 space-y-1 mb-4">
                    <div className="flex justify-between">
                        <span>SUBTOTAL</span>
                        <span>{data.subtotal.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between">
                        <span>VAT @ 15%</span>
                        <span>{data.vat.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between text-lg font-bold mt-2">
                        <span>TOTAL</span>
                        <span>R {data.total.toFixed(2)}</span>
                    </div>
                </div>

                {/* Payment Info */}
                <div className="w-full border-t border-dashed border-gray-400 pt-2 space-y-1 mb-6 text-left text-[10px]">
                    <div className="flex justify-between">
                        <span>{data.tender}</span>
                        <span>{data.total.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between font-bold">
                        <span>CHANGE</span>
                        <span>{data.change.toFixed(2)}</span>
                    </div>
                    <div className="mt-4 text-[9px] text-gray-400 break-all">
                        {data.barcode}
                    </div>
                </div>

                {/* Barcode Mock */}
                <div className="w-full h-12 bg-gray-900 mb-2 opacity-90 items-center justify-center flex text-white text-[8px] tracking-[0.4em]">
                    ||| || |||| || | || |||| || |
                </div>
                <div className="text-[10px] text-gray-500">{data.date}  {data.time}</div>

                {/* Footer */}
                <div className="mt-8 text-center max-w-[220px] text-[10px] text-gray-400 uppercase">
                    <p>THANK YOU FOR SHOPPING WITH US</p>
                    <p className="mt-1">RETAIN SLIP FOR RETURNS</p>
                </div>

                {/* Jagged Bottom Decoration */}
                <div className="absolute bottom-0 left-0 w-full h-2 bg-gray-100/20" style={{ clipPath: 'polygon(0% 100%, 5% 0%, 10% 100%, 15% 0%, 20% 100%, 25% 0%, 30% 100%, 35% 0%, 40% 100%, 45% 0%, 50% 100%, 55% 0%, 60% 100%, 65% 0%, 70% 100%, 75% 0%, 80% 100%, 85% 0%, 90% 100%, 95% 0%, 100% 100%)' }}></div>
            </div>
        </div>

        {/* Action Bar */}
        <div className="bg-slate-50 p-4 flex justify-between items-center border-t border-gray-200 shadow-[0_-4px_10px_rgba(0,0,0,0.05)]">
             <div className="flex space-x-6">
                 <button className="flex flex-col items-center text-gray-500 hover:text-brand-600 transition-colors">
                     <Share2 className="w-5 h-5 mb-1" />
                     <span className="text-[10px] font-bold uppercase">Share</span>
                 </button>
                 <button className="flex flex-col items-center text-gray-500 hover:text-brand-600 transition-colors">
                     <Download className="w-5 h-5 mb-1" />
                     <span className="text-[10px] font-bold uppercase">PDF</span>
                 </button>
             </div>
             {cashbackFound && !scanning && (
                 <div className="bg-brand-600 text-white px-4 py-2 rounded-xl text-xs font-black shadow-lg shadow-brand-500/30 flex items-center">
                     <CheckCircle className="w-4 h-4 mr-2" />
                     EARNED R{cashbackFound.toFixed(2)}
                 </div>
             )}
        </div>
      </div>
