import React, { useState, useEffect } from 'react';
import { Store, Transaction } from '../types';
import { ArrowLeft, ShoppingBag, Receipt, Percent, Star, CheckCircle, Clock, Search, AlertTriangle, ChevronRight, Sparkles, Download, ScanLine, QrCode, Loader2, Coins, Zap } from 'lucide-react';
import DigitalReceipt from './DigitalReceipt';

interface StoreDetailProps {
  store: Store;
  transactions: Transaction[];
  onBack: () => void;
  onUpdateStore: (updatedStore: Store) => void;
}

type Tab = 'SHOP' | 'RECEIPTS' | 'PROMOS' | 'LOYALTY';

const StoreDetail: React.FC<StoreDetailProps> = ({ store, transactions, onBack, onUpdateStore }) => {
  const [activeTab, setActiveTab] = useState<Tab>('SHOP');
  const [isRegistering, setIsRegistering] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [viewingReceipt, setViewingReceipt] = useState<Transaction | null>(null);

  useEffect(() => {
    if (store.tabAlerts.slips > 0) {
      setActiveTab('RECEIPTS');
    } else if (store.tabAlerts.promos > 0) {
      setActiveTab('PROMOS');
    } else if (store.tabAlerts.loyalty > 0) {
      setActiveTab('LOYALTY');
    } else {
      setActiveTab('SHOP');
    }
  }, [store.id]);

  const storeTransactions = transactions.filter(t => t.store === store.name || t.storeId === store.id);

  const handleRegister = () => {
    setIsRegistering(true);
    setTimeout(() => {
      onUpdateStore({ ...store, isLinked: true });
      setIsRegistering(false);
    }, 1500);
  };

  const handleScanCard = () => {
      setIsScanning(true);
      setTimeout(() => {
          setIsScanning(false);
          handleRegister();
      }, 2000);
  };

  const renderRegistration = () => (
    <div className="flex flex-col items-center justify-center h-full p-6 text-center space-y-6 animate-in fade-in zoom-in duration-300">
      {isScanning ? (
          <div className="flex flex-col items-center justify-center space-y-4 py-10">
              <div className="relative w-48 h-48 border-2 border-brand-500 rounded-3xl overflow-hidden flex items-center justify-center bg-black">
                  <div className="absolute top-0 left-0 w-full h-1 bg-red-500 shadow-[0_0_15px_rgba(239,68,68,1)] animate-[scan_1.5s_ease-in-out_infinite]"></div>
                  <p className="text-white/70 text-xs">Align Card Here</p>
              </div>
              <p className="text-gray-600 dark:text-slate-300 animate-pulse">Scanning Loyalty Card...</p>
          </div>
      ) : (
          <>
            <div className="w-24 h-24 rounded-full bg-slate-100 dark:bg-slate-700 flex items-center justify-center text-4xl shadow-inner mb-4">
                {store.logo}
            </div>
            <div>
                <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">Connect to {store.name}</h2>
                <p className="text-gray-500 dark:text-slate-400">
                Link your account to enter the virtual store, view real-time stock, track digital receipts, and manage loyalty points.
                </p>
            </div>
            <div className="w-full bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 text-left">
                <h4 className="font-semibold text-sm mb-3 dark:text-white">Benefits of linking:</h4>
                <ul className="space-y-2 text-sm text-gray-600 dark:text-slate-300">
                <li className="flex items-center"><CheckCircle className="w-4 h-4 mr-2 text-green-500" /> Real-time stock check</li>
                <li className="flex items-center"><CheckCircle className="w-4 h-4 mr-2 text-green-500" /> Automatic digital receipts</li>
                <li className="flex items-center"><CheckCircle className="w-4 h-4 mr-2 text-green-500" /> Exclusive MiCOIN cashback deals</li>
                <li className="flex items-center"><CheckCircle className="w-4 h-4 mr-2 text-green-500" /> Auto-roundup savings</li>
                </ul>
            </div>
            <div className="w-full space-y-3">
                <button onClick={handleRegister} disabled={isRegistering} className="w-full py-4 rounded-xl text-white font-bold shadow-lg hover:opacity-90 transition-opacity flex items-center justify-center" style={{ backgroundColor: store.color }}>
                    {isRegistering ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" />Connecting...</> : <>Link Manually</>}
                </button>
                <button onClick={handleScanCard} disabled={isRegistering} className="w-full py-4 rounded-xl bg-white dark:bg-slate-800 text-gray-700 dark:text-white font-bold border border-gray-200 dark:border-slate-700 shadow-sm hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors flex items-center justify-center">
                    <QrCode className="w-5 h-5 mr-2 opacity-70" />Scan Loyalty Card
                </button>
            </div>
          </>
      )}
    </div>
  );

  const renderShop = () => (
    <div className="space-y-4">
      <div className="relative">
        <Search className="absolute left-3 top-3 w-4 h-4 text-gray-400" />
        <input type="text" placeholder={`Search ${store.name} Virtual Store...`} className="w-full bg-slate-100 dark:bg-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-brand-500 dark:text-white" />
      </div>
      <div className="grid grid-cols-2 gap-3">
        {store.inventory.map(item => (
          <div key={item.id} className="bg-white dark:bg-slate-800 p-3 rounded-xl border border-slate-100 dark:border-slate-700 shadow-sm relative group">
            <div className="absolute top-2 right-2 flex items-center space-x-1 bg-white/80 dark:bg-black/50 px-2 py-1 rounded-full backdrop-blur-sm">
              <div className={`w-2 h-2 rounded-full ${item.inStock ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`}></div>
              <span className="text-[10px] font-medium dark:text-white">{item.inStock ? 'In Stock' : 'Out of Stock'}</span>
            </div>
            <div className="h-24 w-full bg-slate-50 dark:bg-slate-700 rounded-lg mb-3 flex items-center justify-center text-2xl">{item.image || '📦'}</div>
            <h4 className="font-medium text-sm text-gray-800 dark:text-white line-clamp-2">{item.name}</h4>
            <div className="flex justify-between items-end mt-2">
