                        className="w-full p-5 pl-10 bg-slate-50 dark:bg-slate-800 rounded-3xl border border-slate-200 dark:border-slate-700 outline-none focus:ring-2 focus:ring-brand-500 text-3xl font-mono dark:text-white font-black transition-all shadow-sm"
                        placeholder="0.00"
                        autoFocus
                      />
