interface WalletViewProps {
  user: User;
  onUpdateSettings: (target: number) => void;
  onUpdateBalance: (amount: number) => void;
  onAddTransaction: (tx: Transaction) => void;
  onToggleAutoSave: () => void;
  onBack?: () => void;
}

type WithdrawType = 'STORE' | null;

const WalletView: React.FC<WalletViewProps> = ({ user, onUpdateSettings, onUpdateBalance, onAddTransaction, onToggleAutoSave, onBack }) => {
  const [withdrawType, setWithdrawType] = useState<WithdrawType>(null);
  const [amount, setAmount] = useState<string>('');
  const [processing, setProcessing] = useState(false);
  const [generatedToken, setGeneratedToken] = useState<string | null>(null);
  const [tokenExpiry, setTokenExpiry] = useState<number | null>(null);
  const [timeLeft, setTimeLeft] = useState<string>('30:00');
  const [isRotating, setIsRotating] = useState(false);

  const MIN_WITHDRAWAL = 10;
  const ROTATION_INTERVAL_MS = 30 * 60 * 1000; // 30 minutes

  // Handle countdown and auto-rotation
  useEffect(() => {
    if (!generatedToken || !tokenExpiry) return;

    const interval = setInterval(() => {
      const now = Date.now();
      const diff = tokenExpiry - now;

      if (diff <= 0) {
        // Time is up, rotate the token
        const newToken = Math.floor(10000 + Math.random() * 90000).toString();
        setIsRotating(true);
        setGeneratedToken(newToken);
        setTokenExpiry(Date.now() + ROTATION_INTERVAL_MS);
        setTimeout(() => setIsRotating(false), 1000);
      } else {
        // Update countdown string
        const mins = Math.floor(diff / 60000);
        const secs = Math.floor((diff % 60000) / 1000);
        setTimeLeft(`${mins}:${secs.toString().padStart(2, '0')}`);
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [generatedToken, tokenExpiry]);

  // Dynamic Calculation for Explanation
  const examplePrice = 96.50; 
  const examplePayment = 100.00;
  const activeThreshold = user.roundUpTarget || 1; 
  const roundedUpBill = Math.ceil(examplePrice / activeThreshold) * activeThreshold;
  const savingsAmount = roundedUpBill - examplePrice;
  const normalChange = examplePayment - examplePrice; 

  const handleWithdraw = () => {
      if (!amount) return;
      const withdrawAmount = parseFloat(amount);

      if (withdrawAmount < MIN_WITHDRAWAL) return;
      if (withdrawAmount > user.miCoinBalance) return;

      setProcessing(true);

      // Generate initial token
      const token = Math.floor(10000 + Math.random() * 90000).toString();

      setTimeout(() => {
          // Record the transaction
          const now = new Date();
          const dateStr = now.toLocaleDateString('en-ZA', { day: 'numeric', month: 'short' });
          const timeStr = now.toLocaleTimeString('en-ZA', { hour: '2-digit', minute: '2-digit' });

          const cashoutTx: Transaction = {
              id: Date.now().toString(),
              store: 'Store Cashout',
              amount: 0,
              savings: withdrawAmount, // Used for the display amount
              date: `Today, ${timeStr}`,
              category: 'Withdrawal',
              type: 'CASHOUT'
          };

          onAddTransaction(cashoutTx);
          onUpdateBalance(-withdrawAmount);
          setProcessing(false);
          setGeneratedToken(token);
          setTokenExpiry(Date.now() + ROTATION_INTERVAL_MS);
      }, 2000);
  };

  const handleCloseToken = () => {
      setGeneratedToken(null);
      setTokenExpiry(null);
      setWithdrawType(null);
      setAmount('');
  };

  const thresholdOptions = [1, 2, 5, 10];

  // Store Cashout Token Modal
  if (generatedToken && withdrawType === 'STORE') {
      return (
        <div 
          className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/95 backdrop-blur-md animate-in fade-in duration-300"
          onClick={handleCloseToken}
        >
            <div 
              className="w-full max-w-sm relative"
              onClick={(e) => e.stopPropagation()}
            >
                <div className="absolute -top-10 left-1/2 -translate-x-1/2 text-white/40 text-[10px] font-bold uppercase tracking-widest pointer-events-none">
