             {appStep === 1 && <UserPlus className="w-10 h-10 text-brand-600 animate-pulse" />}
             {appStep === 2 && <ShieldCheck className="w-10 h-10 text-brand-600 animate-bounce" />}
             {appStep === 3 && <Loader2 className="w-10 h-10 text-brand-600 animate-spin" />}
          </div>

          <h3 className="text-2xl font-black text-slate-900 dark:text-white mb-3">
              {appStep === 1 && "Secure Connection"}
              {appStep === 2 && "Verifying Identity"}
              {appStep === 3 && "Issuing Digital Card"}
