            ))}
        </div>
      </div>
      <div className="flex-1 overflow-y-auto p-5 pb-20">
         {activeTab === 'SHOP' && renderShop()}
         {activeTab === 'RECEIPTS' && renderReceipts()}
         {activeTab === 'PROMOS' && renderPromos()}
         {activeTab === 'LOYALTY' && renderLoyalty()}
      </div>
    </div>
  );
};

