import React, { useState, useEffect } from 'react';
import { Store, Transaction } from '../types';
import { ArrowLeft, ShoppingBag, Receipt, Percent, Star, CheckCircle, Clock, Search, AlertTriangle, ChevronRight, Sparkles, Download, ScanLine, QrCode, Loader2, Coins, Zap, UserPlus, ShieldCheck, Gift } from 'lucide-react';
import DigitalReceipt from './DigitalReceipt';

interface StoreDetailProps {
  store: Store;
  transactions: Transaction[];
  onBack: () => void;
  onUpdateStore: (updatedStore: Store) => void;
  onUpdateBalance?: (amount: number) => void;
  onAddTransaction?: (tx: Transaction) => void;
}

type Tab = 'SHOP' | 'RECEIPTS' | 'PROMOS' | 'LOYALTY';

const StoreDetail: React.FC<StoreDetailProps> = ({ store, transactions, onBack, onUpdateStore, onUpdateBalance, onAddTransaction }) => {
  const [activeTab, setActiveTab] = useState<Tab>('SHOP');
  const [isRegistering, setIsRegistering] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [isApplying, setIsApplying] = useState(false);
  const [appStep, setAppStep] = useState(0);
  const [viewingReceipt, setViewingReceipt] = useState<Transaction | null>(null);

  useEffect(() => {
    if (store.isLinked) {
        if (store.tabAlerts.slips > 0) {
            setActiveTab('RECEIPTS');
        } else if (store.tabAlerts.promos > 0) {
            setActiveTab('PROMOS');
        } else if (store.tabAlerts.loyalty > 0) {
            setActiveTab('LOYALTY');
        } else {
            setActiveTab('SHOP');
        }
    }
  }, [store.id, store.isLinked]);

  const storeTransactions = transactions.filter(t => t.store === store.name || t.storeId === store.id);

  const handleRegister = () => {
    setIsRegistering(true);
    setTimeout(() => {
      onUpdateStore({ ...store, isLinked: true });
      setIsRegistering(false);
    }, 1500);
  };

  const handleScanCard = () => {
      setIsScanning(true);
      setTimeout(() => {
          setIsScanning(false);
          handleRegister();
      }, 2000);
  };

  const handleAffiliateRegister = () => {
      setIsApplying(true);
      setAppStep(1);

      // Simulate multi-step registration (Affiliate commission is processed by the company backend)
      setTimeout(() => setAppStep(2), 1500);
      setTimeout(() => setAppStep(3), 3000);
      setTimeout(() => {
          onUpdateStore({ ...store, isLinked: true, loyaltyPoints: 0 });
          setIsApplying(false);
          setAppStep(0);
      }, 4500);
  };

  const renderApplicationFlow = () => (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center animate-in fade-in slide-in-from-bottom-5">
          <div className="w-20 h-20 bg-brand-50 rounded-3xl flex items-center justify-center mb-8 shadow-inner">
             {appStep === 1 && <UserPlus className="w-10 h-10 text-brand-600 animate-pulse" />}
             {appStep === 2 && <ShieldCheck className="w-10 h-10 text-brand-600 animate-bounce" />}
             {appStep === 3 && <Loader2 className="w-10 h-10 text-brand-600 animate-spin" />}
          </div>

          <h3 className="text-2xl font-black text-slate-900 dark:text-white mb-3">
              {appStep === 1 && "Secure Connection"}
              {appStep === 2 && "Verifying Identity"}
              {appStep === 3 && "Issuing Digital Card"}
          </h3>

          <p className="text-slate-500 dark:text-slate-400 text-sm mb-10 max-w-xs leading-relaxed">
              {appStep === 1 && `Initializing secure registration with ${store.name} servers.`}
              {appStep === 2 && "Linking your CarditOe identity to your new retail account."}
              {appStep === 3 && `Hang tight! We're generating your virtual barcode for ${store.name}.`}
          </p>

          <div className="w-full max-w-xs bg-slate-100 dark:bg-slate-800 h-2 rounded-full overflow-hidden mb-4">
              <div 
                className="h-full bg-brand-500 transition-all duration-500" 
                style={{ width: `${(appStep / 3) * 100}%` }}
              ></div>
          </div>
          <span className="text-[10px] font-black uppercase text-brand-600 tracking-widest">
              Step {appStep} of 3
          </span>
      </div>
  );

  const renderRegistration = () => (
    <div className="flex flex-col items-center justify-center h-full p-6 text-center space-y-6 animate-in fade-in zoom-in duration-300">
      {isScanning ? (
          <div className="flex flex-col items-center justify-center space-y-4 py-10">
              <div className="relative w-48 h-48 border-2 border-brand-500 rounded-3xl overflow-hidden flex items-center justify-center bg-black">
                  <div className="absolute top-0 left-0 w-full h-1 bg-red-500 shadow-[0_0_15px_rgba(239,68,68,1)] animate-[scan_1.5s_ease-in-out_infinite]"></div>
                  <p className="text-white/70 text-xs">Align Card Here</p>
              </div>
              <p className="text-gray-600 dark:text-slate-300 animate-pulse">Scanning Loyalty Card...</p>
          </div>
      ) : (
          <>
            <div className="w-24 h-24 rounded-[2rem] bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-4xl shadow-inner mb-4">
                {store.logo}
            </div>
            <div>
                <h2 className="text-2xl font-black text-gray-900 dark:text-white mb-2 uppercase tracking-tight">Connect {store.name}</h2>
                <p className="text-gray-500 dark:text-slate-400 text-sm px-4">
                    Link your existing card or register a new one to unlock automatic digital receipts and cashback.
                </p>
            </div>

            <div className="w-full space-y-3 px-4">
                <button onClick={handleRegister} disabled={isRegistering} className="w-full py-4 rounded-2xl text-white font-black text-sm uppercase tracking-widest shadow-lg hover:opacity-90 transition-opacity flex items-center justify-center" style={{ backgroundColor: store.color }}>
                    {isRegistering ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" />Connecting...</> : <>Link Existing Card</>}
                </button>
                <button onClick={handleScanCard} disabled={isRegistering} className="w-full py-4 rounded-2xl bg-white dark:bg-slate-800 text-gray-700 dark:text-white font-black text-sm uppercase tracking-widest border border-gray-200 dark:border-slate-700 shadow-sm hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors flex items-center justify-center">
                    <QrCode className="w-5 h-5 mr-2 opacity-70" />Scan Plastic Card
                </button>
            </div>

            <div className="w-full pt-8 mt-8 border-t border-slate-200 dark:border-slate-800">
                <div className="bg-slate-100 dark:bg-slate-800/50 rounded-3xl p-6 border border-slate-200 dark:border-slate-700 relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-4 opacity-5">
                        <UserPlus className="w-20 h-20" />
                    </div>
                    <div className="flex flex-col items-center">
                        <div className="flex items-center space-x-2 bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest mb-4">
                            <Zap className="w-3 h-3" />
                            <span>CarditOe Instant Apply</span>
                        </div>
                        <h4 className="text-lg font-black text-slate-900 dark:text-white mb-1">No card? No problem.</h4>
                        <p className="text-xs text-slate-500 dark:text-slate-400 mb-6 text-center max-w-[220px]">
                            Apply for a new <b>{store.name}</b> digital card directly through CarditOe for seamless savings and automatic receipt tracking.
                        </p>
                        <button 
                            onClick={handleAffiliateRegister}
                            className="w-full py-4 bg-brand-600 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-brand-500/20 active:scale-95 transition-transform"
                        >
                            Apply for Digital Card
                        </button>
                    </div>
                </div>
                <p className="text-[10px] text-slate-400 mt-4 uppercase font-bold tracking-widest">Official Digital Partnership</p>
            </div>
          </>
      )}
    </div>
  );

  const renderShop = () => (
    <div className="space-y-4">
      <div className="relative">
        <Search className="absolute left-3 top-3 w-4 h-4 text-gray-400" />
        <input type="text" placeholder={`Search ${store.name} Virtual Store...`} className="w-full bg-slate-100 dark:bg-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-brand-500 dark:text-white" />
      </div>
      <div className="grid grid-cols-2 gap-3">
        {store.inventory.map(item => (
          <div key={item.id} className="bg-white dark:bg-slate-800 p-3 rounded-xl border border-slate-100 dark:border-slate-700 shadow-sm relative group">
            <div className="absolute top-2 right-2 flex items-center space-x-1 bg-white/80 dark:bg-black/50 px-2 py-1 rounded-full backdrop-blur-sm">
              <div className={`w-2 h-2 rounded-full ${item.inStock ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`}></div>
              <span className="text-[10px] font-medium dark:text-white">{item.inStock ? 'In Stock' : 'Out of Stock'}</span>
            </div>
            <div className="h-24 w-full bg-slate-50 dark:bg-slate-700 rounded-lg mb-3 flex items-center justify-center text-2xl">{item.image || '📦'}</div>
            <h4 className="font-medium text-sm text-gray-800 dark:text-white line-clamp-2">{item.name}</h4>
            <div className="flex justify-between items-end mt-2">
              <div>
                {item.oldPrice && <span className="text-xs text-gray-400 line-through block">R {item.oldPrice.toFixed(2)}</span>}
                <span className="font-bold" style={{ color: store.color }}>R {item.price.toFixed(2)}</span>
              </div>
              <button className="w-6 h-6 rounded-full flex items-center justify-center text-white hover:opacity-90 transition-opacity" style={{ backgroundColor: store.color }}>+</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderReceipts = () => (
    <div className="space-y-3">
       {storeTransactions.length === 0 ? (
         <div className="text-center py-10 text-gray-500 dark:text-slate-400">
           <Receipt className="w-12 h-12 mx-auto mb-3 opacity-30" />
           <p>No recent digital receipts found for {store.name}.</p>
         </div>
       ) : (
         storeTransactions.map(tx => (
          <div key={tx.id} onClick={() => tx.receiptData && setViewingReceipt(tx)} className={`bg-white dark:bg-slate-800 p-4 rounded-xl border-l-4 shadow-sm relative overflow-hidden transition-transform active:scale-95 ${tx.receiptData ? 'cursor-pointer hover:shadow-md' : ''}`} style={{ borderLeftColor: store.color }}>
            <div className="flex justify-between items-start mb-2">
               <div>
                  <h4 className="font-bold text-gray-900 dark:text-white">{store.name}</h4>
                  <p className="text-xs text-gray-500 dark:text-slate-400">{tx.date}</p>
               </div>
               <div className="text-right">
                  {tx.type === 'CASHBACK' ? <div className="flex items-center text-accent-500 font-bold"><Sparkles className="w-4 h-4 mr-1" />+ R {tx.savings.toFixed(2)}</div> : <><span className="block font-bold text-lg dark:text-white">R {tx.amount.toFixed(2)}</span><span className="text-xs font-medium" style={{ color: store.color }}>Saved R {tx.savings.toFixed(2)}</span></>}
               </div>
            </div>
            <div className="border-t border-dashed border-gray-200 dark:border-slate-700 my-2"></div>
            <div className="space-y-1">
                {(tx.receiptData ? tx.receiptData.items.map(i => i.description) : (tx.items || ['Assorted Items'])).slice(0, 3).map((item, i) => <div key={i} className="flex justify-between text-xs text-gray-600 dark:text-slate-300"><span>{item}</span></div>)}
                {(tx.receiptData?.items.length || 0) > 3 && <div className="text-xs text-gray-400 italic">...and more</div>}
            </div>
            <div className="mt-3 flex justify-between items-center">
                {tx.receiptData ? <span className="text-[10px] bg-slate-100 dark:bg-slate-700 text-gray-500 px-2 py-0.5 rounded">Tap to view original slip</span> : <span></span>}
                <button className="text-xs font-medium flex items-center" style={{ color: store.color }}>View Full Slip <ChevronRight className="w-3 h-3 ml-1" /></button>
            </div>
          </div>
         ))
       )}
    </div>
  );

  const renderLoyalty = () => {
    const randValue = (store.loyaltyPoints / 100).toFixed(2);
    const expiringRand = ((store.pointsExpiring || 0) / 100).toFixed(2);

    return (
      <div className="space-y-6">
          <div className="rounded-2xl p-6 text-white shadow-xl relative overflow-hidden" style={{ backgroundColor: store.color }}>
              <div className="absolute top-0 right-0 w-48 h-48 bg-white opacity-10 rounded-full -mr-12 -mt-12"></div>
              <div className="absolute top-0 right-0 p-4 opacity-10"><Star className="w-24 h-24" /></div>
              <p className="text-sm text-white/80 uppercase tracking-widest mb-1">Loyalty Balance</p>
              <h3 className="text-4xl font-mono font-bold mb-1">{store.loyaltyPoints} <span className="text-lg font-sans font-normal text-white/70">pts</span></h3>
              <div className="flex items-center text-amber-300 font-bold text-lg mb-4">
                  <Coins className="w-5 h-5 mr-2" />
                  R {randValue} Spendable
              </div>

              <div className="bg-white/10 rounded-lg p-3 backdrop-blur-sm border border-white/20">
                  <div className="flex items-start space-x-3">
                      <AlertTriangle className="w-5 h-5 text-yellow-300 flex-shrink-0" />
                      <div>
                          <p className="text-sm font-medium text-white">Expiring Soon</p>
                          <p className="text-xs text-white/80">
                              {store.pointsExpiring || 0} points (R {expiringRand}) will expire in 5 days. Use them on your next virtual shop!
                          </p>
                      </div>
                  </div>
              </div>
          </div>

          <div>
              <h4 className="font-bold text-gray-800 dark:text-white mb-3">Redeem Rewards</h4>
              <div className="space-y-3">
                  {[
                      { name: 'R10 Airtime Voucher', cost: 1000 },
                      { name: 'R50 Shopping Voucher', cost: 5000 },
                  ].map((reward, i) => (
                      <div key={i} className="flex items-center p-3 bg-white dark:bg-slate-800 rounded-xl border border-slate-100 dark:border-slate-700">
                          <div className="w-12 h-12 bg-opacity-10 rounded-lg flex items-center justify-center font-bold" style={{ backgroundColor: `${store.color}20`, color: store.color }}>
                              R{(reward.cost/100)}
                          </div>
                          <div className="ml-3 flex-1">
                              <p className="font-medium text-sm dark:text-white">{reward.name}</p>
                              <p className="text-xs text-gray-500">{reward.cost} pts</p>
                          </div>
                          <button 
                            disabled={store.loyaltyPoints < reward.cost}
                            className={`px-3 py-1 text-xs font-medium rounded-full text-white ${store.loyaltyPoints < reward.cost ? 'opacity-50 grayscale' : ''}`} 
                            style={{ backgroundColor: store.color }}
                          >
                            Redeem
                          </button>
                      </div>
                  ))}
              </div>
          </div>
      </div>
    );
  };

  const renderPromos = () => (
      <div className="space-y-4">
         <div className="p-4 rounded-xl text-white shadow-lg relative overflow-hidden" style={{ background: `linear-gradient(to right, ${store.color}, ${store.color}dd)` }}>
            <div className="absolute right-0 top-0 w-24 h-24 bg-white opacity-10 rounded-full -mr-8 -mt-8"></div>
            <div className="flex items-center space-x-2">
                <span className="bg-white text-xs font-black px-2 py-1 rounded uppercase flex items-center" style={{ color: store.color }}>
                    <Zap className="w-3 h-3 mr-1" /> Auto-Save Active
                </span>
            </div>
            <h3 className="text-xl font-bold mt-2">Automatic Cash Back</h3>
            <p className="text-sm opacity-90 leading-tight">No booking needed. Our Smart Assistant automatically detects these deals when you scan any {store.name} slip.</p>
         </div>
         <div className="grid grid-cols-1 gap-3">
            {store.promos.map(item => (
                <div key={item.id} className="flex bg-white dark:bg-slate-800 p-3 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden relative">
                     <div className="w-24 h-24 bg-slate-100 dark:bg-slate-700 rounded-xl flex-shrink-0 flex items-center justify-center text-3xl relative overflow-hidden">
                        <div className="absolute inset-0 bg-gradient-to-br from-white/20 to-transparent"></div>
                        {item.image}
                        {item.cashbackAmount && (
                            <div className="absolute -bottom-1 left-0 right-0 bg-accent-500 text-white text-[9px] font-black py-1 text-center uppercase tracking-tighter">
                                Earn R{item.cashbackAmount}
                            </div>
                        )}
                     </div>
                     <div className="ml-3 flex-1 flex flex-col justify-between py-1">
                        <div>
                            <div className="flex justify-between items-start">
                                <h4 className="font-bold text-gray-800 dark:text-white text-sm leading-tight">{item.name}</h4>
                            </div>
                            <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest mt-1">{item.category}</p>
                        </div>
                        <div className="flex justify-between items-end mt-2">
                             <div className="flex flex-col">
                                 {item.oldPrice && <span className="text-xs text-gray-400 line-through">R {item.oldPrice?.toFixed(2)}</span>}
                                 <span className="font-black text-lg text-gray-900 dark:text-white">R {item.price.toFixed(2)}</span>
                             </div>

                             <div className="bg-brand-50 dark:bg-brand-900/30 px-3 py-1.5 rounded-xl border border-brand-100 dark:border-brand-800/50 flex flex-col items-center">
                                <div className="text-[8px] font-black text-brand-600 dark:text-brand-400 uppercase leading-none mb-0.5">Auto-Earn</div>
                                <div className="flex items-center text-accent-600 dark:text-accent-500">
                                    <Sparkles className="w-3 h-3 mr-1" />
                                    <span className="text-[10px] font-black">R{item.cashbackAmount?.toFixed(0)}</span>
                                </div>
                             </div>
                        </div>
                     </div>
                </div>
            ))}
         </div>

         <div className="mt-4 p-4 bg-slate-100 dark:bg-slate-800/50 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 text-center">
            <p className="text-xs text-gray-500 dark:text-slate-400 font-medium">
                Our Gemini-powered engine scans every line item on your receipt to find matches automatically. You never miss a saving.
            </p>
         </div>
      </div>
  );

  if (!store.isLinked) {
      return (
        <div className="h-full flex flex-col bg-gray-50 dark:bg-slate-900">
            <div className="p-4"><button onClick={onBack} className="p-2 bg-white dark:bg-slate-800 rounded-full shadow-sm"><ArrowLeft className="w-5 h-5 text-gray-600 dark:text-white" /></button></div>
            {isApplying ? renderApplicationFlow() : renderRegistration()}
        </div>
      );
  }

  return (
    <div className="flex flex-col h-full bg-gray-50 dark:bg-slate-900 relative">
      {viewingReceipt && viewingReceipt.receiptData && <DigitalReceipt data={viewingReceipt.receiptData} store={store} onClose={() => setViewingReceipt(null)} />}
      <div className="relative text-white p-6 pb-10 rounded-b-[2.5rem] shadow-lg transition-colors" style={{ backgroundColor: store.color }}>
         <div className="flex justify-between items-center mb-4">
            <button onClick={onBack} className="p-2 bg-white/20 backdrop-blur-sm rounded-full hover:bg-white/30"><ArrowLeft className="w-5 h-5 text-white" /></button>
            <span className="font-bold tracking-wide">Virtual Store</span>
            <div className="w-9 h-9 bg-white/20 rounded-full flex items-center justify-center backdrop-blur-sm border border-white/30">{store.logo}</div>
         </div>
         <div className="mt-2"><h1 className="text-2xl font-bold">{store.name}</h1><p className="text-white/80 text-sm flex items-center mt-1"><Clock className="w-3 h-3 mr-1" /> Open Now • Closing at 20:00</p></div>
      </div>
      <div className="px-6 -mt-8">
        <div className="bg-white dark:bg-slate-800 rounded-xl shadow-md p-1.5 flex justify-between items-center">
            {[
                { id: 'SHOP', icon: ShoppingBag, label: 'Shop', alertCount: store.tabAlerts?.shop || 0 },
                { id: 'RECEIPTS', icon: Receipt, label: 'Slips', alertCount: store.tabAlerts?.slips || 0 },
                { id: 'PROMOS', icon: Percent, label: 'Cashback', alertCount: store.tabAlerts?.promos || 0 },
                { id: 'LOYALTY', icon: Star, label: 'Points', alertCount: store.tabAlerts?.loyalty || 0 },
            ].map((tab) => (
                <button key={tab.id} onClick={() => setActiveTab(tab.id as Tab)} className={`flex-1 flex flex-col items-center py-2 rounded-lg transition-all relative ${activeTab === tab.id ? 'bg-slate-100 dark:bg-slate-700 shadow-sm' : 'text-gray-400 dark:text-slate-500'}`} style={activeTab === tab.id ? { color: store.color } : {}}>{tab.alertCount > 0 && <span className="absolute top-1 right-2 min-w-[14px] h-3.5 bg-red-500 rounded-full text-[9px] flex items-center justify-center text-white px-0.5 animate-pulse z-10">{tab.alertCount}</span>}<tab.icon className="w-5 h-5 mb-0.5" /><span className="text-[10px] font-medium">{tab.label}</span></button>
            ))}
        </div>
      </div>
      <div className="flex-1 overflow-y-auto p-5 pb-20">
         {activeTab === 'SHOP' && renderShop()}
         {activeTab === 'RECEIPTS' && renderReceipts()}
         {activeTab === 'PROMOS' && renderPromos()}
         {activeTab === 'LOYALTY' && renderLoyalty()}
      </div>
    </div>
  );
};

export default StoreDetail;

