                    <p className="text-xs text-center text-gray-500 dark:text-slate-400 leading-relaxed font-medium">
                        We round your <span className="font-black text-stone-800 dark:text-stone-200">R{examplePrice.toFixed(2)}</span> shop to the nearest <span className="font-black text-stone-800 dark:text-stone-200">R{activeThreshold} (R{roundedUpBill.toFixed(2)})</span>. The extra <span className="font-black text-brand-600 dark:text-brand-400">R{savingsAmount.toFixed(2)}</span> goes directly to your MiCOINBANK wallet.
                    </p>
                </div>
            </div>

            {/* Wallet Activity Section (Collapsible) */}
            <div className="mt-2 space-y-4">
                <button 
                    onClick={() => setIsActivityExpanded(!isActivityExpanded)}
                    className="w-full flex items-center justify-between px-1 hover:bg-slate-50 dark:hover:bg-slate-800/50 p-2 rounded-xl transition-colors group"
                >
                    <div className="flex items-center">
                        <h3 className="font-black text-gray-900 dark:text-white flex items-center text-lg uppercase tracking-tight">
                            <History className="w-5 h-5 mr-3 text-brand-500" />
