                            {walletActivity.length} Total
                        </span>
                    </div>
                    <ChevronDown className={`w-5 h-5 text-slate-400 transition-transform duration-300 ${isActivityExpanded ? 'rotate-180' : ''}`} />
                </button>

                <div className={`space-y-3 transition-all duration-300 origin-top overflow-hidden ${isActivityExpanded ? 'max-h-[1000px] opacity-100' : 'max-h-0 opacity-0 pointer-events-none'}`}>
                    {walletActivity.length === 0 ? (
                        <div className="text-center py-10 bg-slate-50 dark:bg-slate-800/30 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-700">
                            <p className="text-xs text-slate-400 font-medium">No wallet activity yet.</p>
                        </div>
                    ) : (
                        walletActivity.slice(0, 10).map((tx) => (
                            <div key={tx.id} className="bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-100 dark:border-slate-700 flex items-center justify-between shadow-sm animate-in fade-in slide-in-from-top-2">
                                <div className="flex items-center space-x-3">
