                        ))
                    )}
                </div>
            </div>

            {!user.isAutoSaveEnabled && (
                <div className="mt-8 p-5 rounded-2xl bg-slate-100 dark:bg-slate-800/50 border-2 border-dashed border-slate-200 dark:border-slate-700 flex items-center justify-center animate-in fade-in">
                    <Power className="w-5 h-5 text-gray-400 mr-3" />
