                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default WalletView;

import React, { useState, useEffect } from 'react';
import { User, Transaction } from '../types';
import WalletCard from './WalletCard';
import { Settings, ArrowRight, Banknote, Coins, CheckCircle, Ticket, X, ShoppingCart, Calculator, Lock, QrCode, Smartphone, Scan, Power, RefreshCw, Timer, ArrowLeft, Target, Info, ListTodo, History, ArrowUpRight, ChevronDown } from 'lucide-react';

interface WalletViewProps {
  user: User;
  transactions: Transaction[];
  onUpdateSettings: (target: number) => void;
  onUpdateBalance: (amount: number) => void;
  onAddTransaction: (tx: Transaction) => void;
  onToggleAutoSave: () => void;
  onBack?: () => void;
}

type WithdrawType = 'STORE' | null;

const WalletView: React.FC<WalletViewProps> = ({ user, transactions, onUpdateSettings, onUpdateBalance, onAddTransaction, onToggleAutoSave, onBack }) => {
  const [withdrawType, setWithdrawType] = useState<WithdrawType>(null);
  const [amount, setAmount] = useState<string>('');
  const [processing, setProcessing] = useState(false);
  const [generatedToken, setGeneratedToken] = useState<string | null>(null);
  const [tokenExpiry, setTokenExpiry] = useState<number | null>(null);
  const [timeLeft, setTimeLeft] = useState<string>('30:00');
  const [isRotating, setIsRotating] = useState(false);
  const [isActivityExpanded, setIsActivityExpanded] = useState(false);

  const MIN_WITHDRAWAL = 20;
  const ROTATION_INTERVAL_MS = 30 * 60 * 1000; // 30 minutes

  // Filter for wallet-specific transactions (Cashouts and Savings)
  const walletActivity = transactions.filter(tx => 
    tx.type === 'CASHOUT' || tx.type === 'ROUND_UP' || tx.type === 'CASHBACK'
  );

  // Handle countdown and auto-rotation
  useEffect(() => {
    if (!generatedToken || !tokenExpiry) return;

    const interval = setInterval(() => {
      const now = Date.now();
      const diff = tokenExpiry - now;

      if (diff <= 0) {
        // Time is up, rotate the token
        const newToken = Math.floor(10000 + Math.random() * 90000).toString();
        setIsRotating(true);
        setGeneratedToken(newToken);
        setTokenExpiry(Date.now() + ROTATION_INTERVAL_MS);
        setTimeout(() => setIsRotating(false), 1000);
      } else {
        // Update countdown string
        const mins = Math.floor(diff / 60000);
        const secs = Math.floor((diff % 60000) / 1000);
        setTimeLeft(`${mins}:${secs.toString().padStart(2, '0')}`);
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [generatedToken, tokenExpiry]);

  // Dynamic Calculation for Explanation
  const examplePrice = 96.50; 
  const examplePayment = 100.00;
  const activeThreshold = user.roundUpTarget || 1; 
  const roundedUpBill = Math.ceil(examplePrice / activeThreshold) * activeThreshold;
  const savingsAmount = roundedUpBill - examplePrice;
  const normalChange = examplePayment - examplePrice; 

  const handleWithdraw = () => {
      if (!amount) return;
      const withdrawAmount = parseFloat(amount);

      if (withdrawAmount < MIN_WITHDRAWAL) return;
      if (withdrawAmount > user.miCoinBalance) return;

      setProcessing(true);

      // Generate initial token
      const token = Math.floor(10000 + Math.random() * 90000).toString();

      setTimeout(() => {
          // Record the transaction
          const now = new Date();
          const dateStr = now.toLocaleDateString('en-ZA', { day: 'numeric', month: 'short' });
          const timeStr = now.toLocaleTimeString('en-ZA', { hour: '2-digit', minute: '2-digit' });

          const cashoutTx: Transaction = {
              id: Date.now().toString(),
              store: 'Store Cashout',
              amount: 0,
              savings: withdrawAmount, // Used for the display amount
              date: `Today, ${timeStr}`,
              category: 'Withdrawal',
              type: 'CASHOUT'
          };

          onAddTransaction(cashoutTx);
          onUpdateBalance(-withdrawAmount);
          setProcessing(false);
          setGeneratedToken(token);
          setTokenExpiry(Date.now() + ROTATION_INTERVAL_MS);
      }, 2000);
  };

  const handleCloseToken = () => {
      setGeneratedToken(null);
      setTokenExpiry(null);
      setWithdrawType(null);
      setAmount('');
  };

  const thresholdOptions = [1, 2, 5, 10];

  // Store Cashout Token Modal
  if (generatedToken && withdrawType === 'STORE') {
      return (
        <div 
          className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/95 backdrop-blur-md animate-in fade-in duration-300"
          onClick={handleCloseToken}
        >
            <div 
              className="w-full max-w-sm relative"
              onClick={(e) => e.stopPropagation()}
            >
                <div className="absolute -top-8 left-1/2 -translate-x-1/2 text-white/40 text-[9px] font-bold uppercase tracking-widest pointer-events-none">
                    Scroll to see button or tap outside to exit
                </div>

                <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden relative max-h-[85vh] flex flex-col">
                    <div className="bg-stone-900 p-6 text-center pt-8 pb-10 relative overflow-hidden flex-shrink-0">
                        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-brand-400 via-brand-500 to-brand-400"></div>

                        <button 
                            onClick={handleCloseToken}
                            className="absolute top-6 right-6 p-2 bg-white/10 rounded-full text-white hover:bg-white/20 transition-all z-50 flex items-center justify-center"
                        >
                            <X className="w-5 h-5" />
                        </button>

                        <button 
                            onClick={handleCloseToken}
                            className="absolute top-6 left-6 p-2 bg-white/10 rounded-full text-white hover:bg-white/20 transition-all z-50 flex items-center justify-center"
                        >
                            <ArrowLeft className="w-5 h-5" />
                        </button>

                        <h3 className="text-white font-black text-xl uppercase tracking-[0.2em] mb-1">Cash Voucher</h3>
                        <p className="text-stone-400 text-[10px] uppercase tracking-wider">Secure Rotating Token</p>
                    </div>

                    <div className="relative h-4 bg-white flex-shrink-0">
                        <div className="absolute top-1/2 left-0 right-0 border-b-2 border-dashed border-stone-200 -translate-y-1/2 mx-8"></div>
                        <div className="absolute -left-4 top-1/2 -translate-y-1/2 w-8 h-8 bg-slate-900 rounded-full"></div>
                        <div className="absolute -right-4 top-1/2 -translate-y-1/2 w-8 h-8 bg-slate-900 rounded-full"></div>
                    </div>

                    <div className="overflow-y-auto flex-1 p-8 pt-4 pb-12 text-center bg-white">
                        <div className="mb-6 text-center">
                            <div className="inline-flex items-center space-x-2 bg-green-50 text-green-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest mb-4">
                                <CheckCircle className="w-3 h-3" />
                                <span>Transaction Recorded</span>
                            </div>
                            <p className="text-stone-400 text-[10px] uppercase tracking-widest font-bold mb-1">Voucher Value</p>
                            <div className="flex items-baseline justify-center text-stone-900">
                                <span className="text-xl font-medium mr-1">R</span>
                                <span className="text-5xl font-black tracking-tight">{parseFloat(amount || '0').toFixed(2)}</span>
                            </div>
                        </div>

                        <div className="flex justify-center mb-8 relative">
                             <div className={`relative group transition-transform duration-500 ${isRotating ? 'scale-95 opacity-50' : 'scale-100'}`}>
                                <div className="bg-white p-5 rounded-3xl border-2 border-stone-900 shadow-[0_15px_40px_rgba(0,0,0,0.1)]">
                                    <QrCode className="w-40 h-40 text-stone-900" />
                                </div>
                                <div className="absolute -bottom-3 left-1/2 -translate-x-1/2 bg-stone-900 text-white text-[10px] px-4 py-1.5 rounded-full font-bold shadow-lg flex items-center whitespace-nowrap">
                                    <Scan className="w-3 h-3 mr-2" /> Scan at Point of Sale
                                </div>
                             </div>
                        </div>

                        <div className="mb-8">
                            <div className="flex items-center justify-center space-x-2 mb-4">
                                <p className="text-stone-400 text-[10px] uppercase tracking-widest font-bold">5-Digit PIN</p>
                                <div className="flex items-center space-x-1.5 bg-brand-50 px-3 py-1 rounded-full text-brand-600 font-black text-[10px] shadow-sm">
                                    <Timer className="w-3 h-3" />
                                    <span>REFRESHES IN {timeLeft}</span>
                                </div>
                            </div>
                            <div className={`flex justify-center space-x-2 transition-all duration-500 ${isRotating ? 'scale-110 blur-md' : ''}`}>
                                {generatedToken.split('').map((digit, i) => (
                                    <div key={i} className="w-11 h-16 flex items-center justify-center bg-stone-50 rounded-xl border-2 border-stone-100 text-3xl font-black text-stone-900 shadow-sm">
                                        {digit}
                                    </div>
                                ))}
                            </div>
                        </div>

                        <div className="bg-stone-50 rounded-2xl p-5 text-left flex items-start space-x-4 mb-8">
                             <div className="bg-brand-500 p-2 rounded-xl text-white shadow-md">
                                <RefreshCw className={`w-5 h-5 ${isRotating ? 'animate-spin' : ''}`} />
                             </div>
                             <div className="space-y-1">
                                <p className="text-xs font-black text-stone-900 uppercase">Always Live</p>
                                <p className="text-[11px] text-stone-500 leading-tight">
                                    This voucher rotates every 30 minutes for your protection.
                                </p>
                             </div>
                        </div>

                        <button 
                            onClick={handleCloseToken}
                            className="w-full py-4 bg-brand-600 text-white rounded-2xl font-black text-sm uppercase tracking-[0.1em] shadow-xl shadow-brand-500/20 active:scale-95 transition-transform"
                        >
                            Done - Return to Wallet
                        </button>
                    </div>
                </div>
            </div>
        </div>
      );
  }

  // Withdrawal Modal (Amount Entry)
  if (withdrawType) {
      const currentAmount = parseFloat(amount || '0');
      const isInvalidAmount = currentAmount < MIN_WITHDRAWAL;
      const hasInsufficientFunds = currentAmount > user.miCoinBalance;

      return (
          <div className="min-h-full p-5 pb-36 flex flex-col bg-white dark:bg-slate-900 animate-in slide-in-from-bottom-10">
               <div className="flex justify-between items-center mb-6">
                  <div className="flex items-center space-x-3">
                    <button onClick={() => setWithdrawType(null)} className="p-3 -ml-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
                        <ArrowLeft className="w-6 h-6 text-gray-900 dark:text-white" />
                    </button>
                    <h2 className="text-xl font-bold text-gray-900 dark:text-white">
                        Store Cashout
                    </h2>
                  </div>
              </div>

              <div className="mb-6 p-4 bg-brand-50 dark:bg-brand-900/20 border border-brand-200 dark:border-brand-700/50 rounded-2xl flex items-start shadow-sm">
                  <div className="bg-white dark:bg-slate-800 p-2 rounded-xl mr-3 shadow-sm flex-shrink-0">
                    <QrCode className="w-6 h-6 text-brand-600 dark:text-brand-400" />
                  </div>
                  <div>
                      <h4 className="text-sm font-bold text-brand-900 dark:text-brand-300">Secure Rotating QR</h4>
                      <p className="text-[11px] text-brand-700 dark:text-brand-400/80 mt-1 leading-relaxed">
                          Your withdrawal QR will rotate every 30 minutes for security at the point of sale.
                      </p>
                  </div>
              </div>

              <div className="flex-1">
                  <label className="block text-[10px] font-black text-gray-400 dark:text-slate-500 mb-2 uppercase tracking-widest">Withdrawal Amount</label>
                  <div className="relative group">
                      <span className="absolute left-4 top-5 text-2xl text-gray-400 font-bold group-focus-within:text-brand-500 transition-colors">R</span>
                      <input 
                        type="number" 
                        value={amount}
                        onChange={(e) => setAmount(e.target.value)}
                        className="w-full p-5 pl-10 bg-slate-50 dark:bg-slate-800 rounded-3xl border border-slate-200 dark:border-slate-700 outline-none focus:ring-2 focus:ring-brand-500 text-3xl font-mono dark:text-white font-black transition-all shadow-sm"
                        placeholder="0.00"
                        autoFocus
                      />
                  </div>

                  <div className="flex justify-between items-start mt-4 px-1">
                    {isInvalidAmount && amount ? (
                        <p className="text-[10px] text-red-500 font-black uppercase bg-red-50 px-3 py-1 rounded-lg tracking-tight">Minimum withdrawal is R{MIN_WITHDRAWAL}</p>
                    ) : (
                        <span></span>
                    )}
                    <div className="text-right">
                      <p className="text-[9px] text-gray-400 uppercase font-black tracking-widest leading-none mb-1">Available</p>
                      <p className="text-sm font-black text-gray-900 dark:text-white">R {user.miCoinBalance.toFixed(2)}</p>
                    </div>
                  </div>
              </div>

              <div className="mt-8">
                <button 
                    disabled={!amount || isInvalidAmount || hasInsufficientFunds || processing}
                    onClick={handleWithdraw}
                    className="w-full py-5 bg-brand-600 disabled:bg-slate-200 dark:disabled:bg-slate-800 disabled:text-gray-400 dark:disabled:text-slate-600 text-white rounded-3xl font-black shadow-2xl shadow-brand-500/20 text-lg transition-all active:scale-[0.98]"
                >
                    {processing ? 'Generating Voucher...' : 'Confirm Cashout'}
                </button>
              </div>
          </div>
      );
  }

  return (
    <div className="flex flex-col h-full pb-24">
      <div className="p-5 space-y-6">
        <div className="flex justify-between items-center">
             <div className="flex items-center space-x-3">
                {onBack && (
                  <button onClick={onBack} className="p-3 -ml-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors text-gray-400 dark:text-slate-500">
                      <ArrowLeft className="w-6 h-6" />
                  </button>
                )}
                <h2 className="text-2xl font-bold text-gray-900 dark:text-white">MiCOINBANK</h2>
             </div>
        </div>

        <WalletCard user={user} />

        <div className="w-full bg-white dark:bg-slate-800 p-1.5 rounded-[2rem] shadow-sm border border-slate-100 dark:border-slate-700">
            <button 
                onClick={() => setWithdrawType('STORE')}
                className="w-full flex flex-row items-center justify-between p-5 rounded-[1.6rem] bg-gradient-to-br from-brand-50 to-white dark:from-slate-800 dark:to-slate-800/50 hover:from-brand-100 dark:hover:from-slate-700 transition-all group"
            >
                <div className="flex items-center">
                    <div className="w-14 h-14 bg-white dark:bg-slate-700 rounded-2xl flex items-center justify-center shadow-sm mr-5 group-hover:scale-110 transition-transform text-brand-600">
                        <Banknote className="w-7 h-7" />
                    </div>
                    <div className="text-left">
                        <span className="font-black text-xl text-gray-900 dark:text-white block tracking-tight">Cashout</span>
                        <span className="text-xs text-gray-500 dark:text-slate-400 font-medium">Withdraw at any partner store</span>
                    </div>
                </div>
                <div className="w-10 h-10 rounded-full bg-white dark:bg-slate-700 shadow-sm flex items-center justify-center group-hover:bg-brand-500 group-hover:text-white transition-all">
                    <ArrowRight className="w-5 h-5" />
                </div>
            </button>
        </div>

        <div className="bg-white dark:bg-slate-800 p-7 rounded-[2rem] shadow-sm border border-slate-100 dark:border-slate-700 transition-colors">
            <div className="flex justify-between items-center mb-8">
                <h3 className="font-black text-gray-900 dark:text-white flex items-center text-lg uppercase tracking-tight">
                    <Settings className="w-5 h-5 mr-3 text-brand-500" />
                    Auto-Save Engine
                </h3>

                <button 
                  onClick={onToggleAutoSave}
                  className={`relative inline-flex h-7 w-13 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-brand-500 focus:ring-offset-2 ${user.isAutoSaveEnabled ? 'bg-brand-500 shadow-lg shadow-brand-500/30' : 'bg-slate-200 dark:bg-slate-700'}`}
                >
                    <span className="sr-only">Enable Auto-Save</span>
                    <span
                        className={`inline-block h-5 w-5 transform rounded-full bg-white shadow-md transition-transform duration-200 ease-in-out ${user.isAutoSaveEnabled ? 'translate-x-7' : 'translate-x-1'}`}
                    />
                </button>
            </div>

            <div className={`transition-all duration-300 ${user.isAutoSaveEnabled ? 'opacity-100' : 'opacity-40 grayscale pointer-events-none'}`}>
                <div className="mb-8">
                    <div className="flex justify-between items-start mb-4">
                        <div>
                            <p className="text-sm text-gray-900 dark:text-slate-200 font-black uppercase tracking-tight">
                                Savings Threshold
                            </p>
                            <p className="text-[10px] text-gray-500 dark:text-slate-400 mt-1 font-medium">
                                Save small change up to this amount
                            </p>
                        </div>
                        <div className="bg-brand-50 dark:bg-brand-900/40 px-3 py-1.5 rounded-xl border border-brand-100 dark:border-brand-800 flex items-center">
                            <Target className="w-3 h-3 mr-2 text-brand-500" />
                            <span className="text-lg font-black text-brand-600 dark:text-brand-400">R {activeThreshold.toFixed(2)}</span>
                        </div>
                    </div>

                    <div className="flex bg-slate-100 dark:bg-slate-700 p-1 rounded-2xl space-x-1 mb-4">
                        {thresholdOptions.map((val) => (
                            <button
                                key={val}
                                onClick={() => onUpdateSettings(val)}
                                className={`flex-1 py-3 rounded-xl text-xs font-black transition-all ${activeThreshold === val ? 'bg-white dark:bg-slate-600 text-brand-600 dark:text-brand-400 shadow-sm scale-100' : 'text-gray-400 hover:text-gray-600 dark:hover:text-slate-300'}`}
                            >
                                R{val}
                            </button>
                        ))}
                    </div>
                    <div className="bg-blue-50 dark:bg-blue-900/20 p-3 rounded-xl flex items-start space-x-3 border border-blue-100 dark:border-blue-800">
                        <Info className="w-4 h-4 text-blue-500 mt-0.5" />
                        <p className="text-[10px] text-blue-700 dark:text-blue-300 leading-tight">
                            Any change amount <b>below R{activeThreshold}</b> will be automatically rounded up and saved. {activeThreshold === 1 ? 'Round to the nearest Rand.' : `Round to the nearest R${activeThreshold}.`}
                        </p>
                    </div>
                </div>

                <div className="bg-slate-50 dark:bg-slate-700/30 p-6 rounded-[2rem] border border-slate-100 dark:border-slate-700 relative overflow-hidden mb-10">
                    <h4 className="text-[10px] font-black uppercase tracking-widest text-gray-400 dark:text-slate-500 mb-6 text-center">Auto-Save Visualizer (R100 payment)</h4>

                    <div className="flex justify-between items-center mb-8 relative">
                        <div className="absolute left-10 right-10 top-1/2 h-0.5 bg-slate-200 dark:bg-slate-600 -z-10"></div>

                        <div className="flex flex-col items-center bg-white dark:bg-slate-800 p-3 rounded-2xl border border-slate-100 dark:border-slate-600 shadow-sm z-10 w-24">
                            <div className="w-10 h-10 bg-orange-100 dark:bg-orange-900/30 rounded-xl flex items-center justify-center mb-2 text-orange-600">
                                <ShoppingCart className="w-5 h-5" />
                            </div>
                            <span className="text-[9px] font-bold text-gray-400 dark:text-slate-500 uppercase">Total</span>
                            <span className="font-black text-xs text-gray-900 dark:text-white">R{examplePrice.toFixed(2)}</span>
                        </div>

                        <div className="flex flex-col items-center z-10">
                            <div className="bg-brand-500 text-white text-[10px] font-black px-3 py-1 rounded-full shadow-lg shadow-brand-500/30 mb-2">
                                + R{savingsAmount.toFixed(2)}
                            </div>
                            <div className="w-2 h-2 bg-brand-500 rounded-full animate-ping"></div>
                        </div>

                        <div className="flex flex-col items-center bg-white dark:bg-slate-800 p-3 rounded-2xl border border-slate-100 dark:border-slate-600 shadow-sm z-10 w-24 opacity-60">
                            <div className="w-10 h-10 bg-gray-100 dark:bg-slate-700 rounded-xl flex items-center justify-center mb-2 text-gray-500">
                                <Calculator className="w-5 h-5" />
                            </div>
                            <span className="text-[9px] font-bold text-gray-400 dark:text-slate-500 uppercase">Change</span>
                            <span className="font-black text-xs text-gray-500 dark:text-slate-400 line-through">R{normalChange.toFixed(2)}</span>
                        </div>
                    </div>

                    <p className="text-xs text-center text-gray-500 dark:text-slate-400 leading-relaxed font-medium">
                        We round your <span className="font-black text-stone-800 dark:text-stone-200">R{examplePrice.toFixed(2)}</span> shop to the nearest <span className="font-black text-stone-800 dark:text-stone-200">R{activeThreshold} (R{roundedUpBill.toFixed(2)})</span>. The extra <span className="font-black text-brand-600 dark:text-brand-400">R{savingsAmount.toFixed(2)}</span> goes directly to your MiCOINBANK wallet.
                    </p>
                </div>
            </div>

            {/* Wallet Activity Section (Collapsible & Scrollable) */}
            <div className="mt-2 space-y-4">
                <button 
                    onClick={() => setIsActivityExpanded(!isActivityExpanded)}
                    className="w-full flex items-center justify-between px-1 hover:bg-slate-50 dark:hover:bg-slate-800/50 p-2 rounded-xl transition-colors group"
                >
                    <div className="flex items-center">
                        <h3 className="font-black text-gray-900 dark:text-white flex items-center text-lg uppercase tracking-tight">
                            <History className="w-5 h-5 mr-3 text-brand-500" />
                            Wallet Activity
                        </h3>
                        <span className="ml-3 text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-100 dark:bg-slate-800 px-2 py-0.5 rounded-md">
                            {walletActivity.length} Total
                        </span>
                    </div>
                    <ChevronDown className={`w-5 h-5 text-slate-400 transition-transform duration-300 ${isActivityExpanded ? 'rotate-180' : ''}`} />
                </button>

                <div 
                    className={`transition-all duration-500 origin-top overflow-hidden ${isActivityExpanded ? 'max-h-[400px] opacity-100' : 'max-h-0 opacity-0 pointer-events-none'}`}
                >
                    <div className="overflow-y-auto max-h-[400px] pr-2 scrollbar-hide space-y-3 pb-4">
                        {walletActivity.length === 0 ? (
                            <div className="text-center py-10 bg-slate-50 dark:bg-slate-800/30 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-700">
                                <p className="text-xs text-slate-400 font-medium">No wallet activity yet.</p>
                            </div>
                        ) : (
                            walletActivity.map((tx) => (
                                <div key={tx.id} className="bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-100 dark:border-slate-700 flex items-center justify-between shadow-sm animate-in fade-in slide-in-from-top-2">
                                    <div className="flex items-center space-x-3">
                                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${
                                            tx.type === 'CASHOUT' ? 'bg-slate-100 text-slate-500' : 'bg-brand-50 text-brand-600'
                                        }`}>
                                            {tx.type === 'CASHOUT' ? <Banknote className="w-5 h-5" /> : <Coins className="w-5 h-5" />}
                                        </div>
                                        <div className="text-left">
                                            <p className="font-black text-sm text-gray-900 dark:text-white uppercase tracking-tight">
                                                {tx.type === 'CASHOUT' ? 'Store Cashout' : tx.store}
                                            </p>
                                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{tx.date}</p>
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <p className={`font-black text-sm ${tx.type === 'CASHOUT' ? 'text-gray-900 dark:text-white' : 'text-brand-600'}`}>
                                            {tx.type === 'CASHOUT' ? '-' : '+'} R {tx.savings.toFixed(2)}
                                        </p>
                                        <span className={`text-[8px] font-black uppercase tracking-widest ${
                                            tx.type === 'CASHOUT' ? 'text-slate-400' : 'text-brand-400'
                                        }`}>
                                            {tx.type === 'CASHOUT' ? 'Withdrawal' : 'Saved'}
                                        </span>
                                    </div>
                                </div>
                            ))
                        )}
                        {walletActivity.length > 5 && (
                             <div className="text-center pt-2">
                                 <p className="text-[9px] font-black text-slate-300 uppercase tracking-[0.2em]">End of History</p>
                             </div>
                        )}
                    </div>
                </div>
            </div>

            {!user.isAutoSaveEnabled && (
                <div className="mt-8 p-5 rounded-2xl bg-slate-100 dark:bg-slate-800/50 border-2 border-dashed border-slate-200 dark:border-slate-700 flex items-center justify-center animate-in fade-in">
                    <Power className="w-5 h-5 text-gray-400 mr-3" />
                    <span className="text-sm font-black text-gray-400 dark:text-slate-500 uppercase tracking-tight">Auto-Save is Standby</span>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default WalletView;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Transaction } from '../types';
import WalletCard from './WalletCard';
import { Settings, ArrowRight, Banknote, Coins, CheckCircle, Ticket, X, ShoppingCart, Calculator, Lock, QrCode, Smartphone, Scan, Power, RefreshCw, Timer, ArrowLeft, Target, Info, ListTodo, History, ArrowUpRight, ChevronRight, Calendar, Filter, Search } from 'lucide-react';

interface WalletViewProps {
  user: User;
  transactions: Transaction[];
  onUpdateSettings: (target: number) => void;
  onUpdateBalance: (amount: number) => void;
  onAddTransaction: (tx: Transaction) => void;
  onToggleAutoSave: () => void;
  onBack?: () => void;
}

type WithdrawType = 'STORE' | null;
type DateFilter = 'ALL' | '7D' | '30D' | 'THIS_MONTH';

const WalletView: React.FC<WalletViewProps> = ({ user, transactions, onUpdateSettings, onUpdateBalance, onAddTransaction, onToggleAutoSave, onBack }) => {
  const [withdrawType, setWithdrawType] = useState<WithdrawType>(null);
  const [amount, setAmount] = useState<string>('');
  const [processing, setProcessing] = useState(false);
  const [generatedToken, setGeneratedToken] = useState<string | null>(null);
  const [tokenExpiry, setTokenExpiry] = useState<number | null>(null);
  const [timeLeft, setTimeLeft] = useState<string>('30:00');
  const [isRotating, setIsRotating] = useState(false);

  // Detailed Activity View States
  const [isDetailedActivityOpen, setIsDetailedActivityOpen] = useState(false);
  const [activeDateFilter, setActiveDateFilter] = useState<DateFilter>('ALL');

  const MIN_WITHDRAWAL = 20;
  const ROTATION_INTERVAL_MS = 30 * 60 * 1000; // 30 minutes

  // Filter for wallet-specific transactions (Cashouts and Savings)
  const walletActivity = useMemo(() => {
    return transactions.filter(tx => 
        tx.type === 'CASHOUT' || tx.type === 'ROUND_UP' || tx.type === 'CASHBACK'
    );
  }, [transactions]);

  // Handle countdown and auto-rotation for withdrawal tokens
  useEffect(() => {
    if (!generatedToken || !tokenExpiry) return;

    const interval = setInterval(() => {
      const now = Date.now();
      const diff = tokenExpiry - now;

      if (diff <= 0) {
        const newToken = Math.floor(10000 + Math.random() * 90000).toString();
        setIsRotating(true);
        setGeneratedToken(newToken);
        setTokenExpiry(Date.now() + ROTATION_INTERVAL_MS);
        setTimeout(() => setIsRotating(false), 1000);
      } else {
        const mins = Math.floor(diff / 60000);
        const secs = Math.floor((diff % 60000) / 1000);
        setTimeLeft(`${mins}:${secs.toString().padStart(2, '0')}`);
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [generatedToken, tokenExpiry]);

  // Dynamic Calculation for Explanation
  const examplePrice = 96.50; 
  const examplePayment = 100.00;
  const activeThreshold = user.roundUpTarget || 1; 
  const roundedUpBill = Math.ceil(examplePrice / activeThreshold) * activeThreshold;
  const savingsAmount = roundedUpBill - examplePrice;
  const normalChange = examplePayment - examplePrice; 

  const handleWithdraw = () => {
      if (!amount) return;
      const withdrawAmount = parseFloat(amount);

      if (withdrawAmount < MIN_WITHDRAWAL) return;
      if (withdrawAmount > user.miCoinBalance) return;

      setProcessing(true);
      const token = Math.floor(10000 + Math.random() * 90000).toString();

      setTimeout(() => {
          const timeStr = new Date().toLocaleTimeString('en-ZA', { hour: '2-digit', minute: '2-digit' });
          const cashoutTx: Transaction = {
              id: Date.now().toString(),
              store: 'Store Cashout',
              amount: 0,
              savings: withdrawAmount,
              date: `Today, ${timeStr}`,
              category: 'Withdrawal',
              type: 'CASHOUT'
          };

          onAddTransaction(cashoutTx);
          onUpdateBalance(-withdrawAmount);
          setProcessing(false);
          setGeneratedToken(token);
          setTokenExpiry(Date.now() + ROTATION_INTERVAL_MS);
      }, 2000);
  };

  const handleCloseToken = () => {
      setGeneratedToken(null);
      setTokenExpiry(null);
      setWithdrawType(null);
      setAmount('');
  };

  const thresholdOptions = [1, 2, 5, 10];

  // Detailed Activity Modal (Internal Routing)
  if (isDetailedActivityOpen) {
      return (
          <div className="min-h-full flex flex-col bg-white dark:bg-slate-900 animate-in slide-in-from-right-10 duration-300">
              <div className="bg-white dark:bg-slate-900 p-5 sticky top-0 z-50 border-b border-slate-100 dark:border-slate-800">
                  <div className="flex items-center justify-between mb-6">
                      <div className="flex items-center space-x-3">
                        <button onClick={() => setIsDetailedActivityOpen(false)} className="p-3 -ml-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
                            <ArrowLeft className="w-6 h-6 text-gray-900 dark:text-white" />
                        </button>
                        <h2 className="text-xl font-bold text-gray-900 dark:text-white">Wallet History</h2>
                      </div>
                      <div className="bg-brand-50 dark:bg-brand-900/30 px-3 py-1 rounded-full text-[10px] font-black text-brand-600 dark:text-brand-400 uppercase tracking-widest">
                          {walletActivity.length} Events
                      </div>
                  </div>

                  {/* Date Filter Tabs */}
                  <div className="flex space-x-2 overflow-x-auto scrollbar-hide pb-2">
                      {[
                          { id: 'ALL', label: 'All Time' },
                          { id: '7D', label: 'Last 7 Days' },
                          { id: '30D', label: 'Last 30 Days' },
                          { id: 'THIS_MONTH', label: 'This Month' },
                      ].map((filter) => (
                          <button
                            key={filter.id}
                            onClick={() => setActiveDateFilter(filter.id as DateFilter)}
                            className={`whitespace-nowrap px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                                activeDateFilter === filter.id 
                                ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/20 scale-105' 
                                : 'bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400'
                            }`}
                          >
                            {filter.label}
                          </button>
                      ))}
                  </div>
              </div>

              <div className="flex-1 overflow-y-auto p-5 pb-24">
                  {walletActivity.length === 0 ? (
                      <div className="flex flex-col items-center justify-center h-full py-20 text-center">
                          <History className="w-16 h-16 text-slate-200 dark:text-slate-800 mb-4" />
                          <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-1">No Activity</h3>
                          <p className="text-sm text-slate-500 dark:text-slate-400">Your savings and withdrawals will appear here.</p>
                      </div>
                  ) : (
                      <div className="space-y-4">
                          {walletActivity.map((tx) => (
                              <div key={tx.id} className="bg-white dark:bg-slate-800 p-5 rounded-[2rem] border border-slate-100 dark:border-slate-700 flex items-center justify-between shadow-sm transition-transform active:scale-95">
                                  <div className="flex items-center space-x-4">
                                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${
                                          tx.type === 'CASHOUT' ? 'bg-slate-100 text-slate-500' : 'bg-brand-50 text-brand-600'
                                      }`}>
                                          {tx.type === 'CASHOUT' ? <Banknote className="w-6 h-6" /> : <Coins className="w-6 h-6" />}
                                      </div>
                                      <div className="text-left">
                                          <p className="font-black text-sm text-gray-900 dark:text-white uppercase tracking-tight">
                                              {tx.type === 'CASHOUT' ? 'Store Cashout' : tx.store}
                                          </p>
                                          <div className="flex items-center space-x-2 text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">
                                              <span>{tx.date}</span>
                                              <span className="opacity-30">•</span>
                                              <span>{tx.category || 'Savings'}</span>
                                          </div>
                                      </div>
                                  </div>
                                  <div className="text-right">
                                      <p className={`font-black text-lg ${tx.type === 'CASHOUT' ? 'text-gray-900 dark:text-white' : 'text-brand-600'}`}>
                                          {tx.type === 'CASHOUT' ? '-' : '+'} R {tx.savings.toFixed(2)}
                                      </p>
                                      <span className={`text-[8px] font-black uppercase tracking-widest ${
                                          tx.type === 'CASHOUT' ? 'text-slate-400' : 'text-brand-400'
                                      }`}>
                                          {tx.type === 'CASHOUT' ? 'Withdrawn' : 'Accumulated'}
                                      </span>
                                  </div>
                              </div>
                          ))}

                          <div className="pt-10 flex flex-col items-center">
                              <div className="w-1.5 h-1.5 bg-slate-200 dark:bg-slate-800 rounded-full mb-2"></div>
                              <p className="text-[10px] font-black text-slate-300 dark:text-slate-700 uppercase tracking-[0.3em]">End of Records</p>
                          </div>
                      </div>
                  )}
              </div>
          </div>
      );
  }

  // Store Cashout Token Modal
  if (generatedToken && withdrawType === 'STORE') {
      return (
        <div 
          className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/95 backdrop-blur-md animate-in fade-in duration-300"
          onClick={handleCloseToken}
        >
            <div className="w-full max-w-sm relative" onClick={(e) => e.stopPropagation()}>
                <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden relative max-h-[85vh] flex flex-col">
                    <div className="bg-stone-900 p-6 text-center pt-8 pb-10 relative overflow-hidden flex-shrink-0">
                        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-brand-400 via-brand-500 to-brand-400"></div>
                        <button onClick={handleCloseToken} className="absolute top-6 right-6 p-2 bg-white/10 rounded-full text-white hover:bg-white/20 z-50"><X className="w-5 h-5" /></button>
                        <h3 className="text-white font-black text-xl uppercase tracking-[0.2em] mb-1">Cash Voucher</h3>
                        <p className="text-stone-400 text-[10px] uppercase tracking-wider">Secure Rotating Token</p>
                    </div>

                    <div className="overflow-y-auto flex-1 p-8 pt-4 pb-12 text-center bg-white">
                        <div className="mb-6 text-center">
                            <div className="inline-flex items-center space-x-2 bg-green-50 text-green-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest mb-4">
                                <CheckCircle className="w-3 h-3" />
                                <span>Transaction Recorded</span>
                            </div>
                            <div className="flex items-baseline justify-center text-stone-900">
                                <span className="text-xl font-medium mr-1">R</span>
                                <span className="text-5xl font-black tracking-tight">{parseFloat(amount || '0').toFixed(2)}</span>
                            </div>
                        </div>

                        <div className="flex justify-center mb-8 relative">
                            <div className={`bg-white p-5 rounded-3xl border-2 border-stone-900 shadow-xl transition-all ${isRotating ? 'scale-95 blur-sm' : ''}`}>
                                <QrCode className="w-40 h-40 text-stone-900" />
                            </div>
                        </div>

                        <div className="mb-8">
                            <div className="flex items-center justify-center space-x-2 mb-4">
                                <div className="flex items-center space-x-1.5 bg-brand-50 px-3 py-1 rounded-full text-brand-600 font-black text-[10px] shadow-sm">
                                    <Timer className="w-3 h-3" />
                                    <span>REFRESHES IN {timeLeft}</span>
                                </div>
                            </div>
                            <div className={`flex justify-center space-x-2 transition-all duration-500 ${isRotating ? 'scale-110 blur-md' : ''}`}>
                                {generatedToken.split('').map((digit, i) => (
                                    <div key={i} className="w-11 h-16 flex items-center justify-center bg-stone-50 rounded-xl border-2 border-stone-100 text-3xl font-black text-stone-900 shadow-sm">{digit}</div>
                                ))}
                            </div>
                        </div>

                        <button onClick={handleCloseToken} className="w-full py-4 bg-brand-600 text-white rounded-2xl font-black text-sm uppercase tracking-[0.1em] shadow-xl shadow-brand-500/20 active:scale-95 transition-transform">
                            Done - Return to Wallet
                        </button>
                    </div>
                </div>
            </div>
        </div>
      );
  }

  // Withdrawal Amount Entry Modal
  if (withdrawType) {
      const currentAmount = parseFloat(amount || '0');
      const isInvalidAmount = currentAmount < MIN_WITHDRAWAL;
      const hasInsufficientFunds = currentAmount > user.miCoinBalance;

      return (
          <div className="min-h-full p-5 pb-36 flex flex-col bg-white dark:bg-slate-900 animate-in slide-in-from-bottom-10">
               <div className="flex justify-between items-center mb-6">
                  <div className="flex items-center space-x-3">
                    <button onClick={() => setWithdrawType(null)} className="p-3 -ml-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
                        <ArrowLeft className="w-6 h-6 text-gray-900 dark:text-white" />
                    </button>
                    <h2 className="text-xl font-bold text-gray-900 dark:text-white">Store Cashout</h2>
                  </div>
              </div>

              <div className="flex-1">
                  <label className="block text-[10px] font-black text-gray-400 dark:text-slate-500 mb-2 uppercase tracking-widest">Withdrawal Amount</label>
                  <div className="relative group">
                      <span className="absolute left-4 top-5 text-2xl text-gray-400 font-bold group-focus-within:text-brand-500 transition-colors">R</span>
                      <input 
                        type="number" 
                        value={amount}
                        onChange={(e) => setAmount(e.target.value)}
                        className="w-full p-5 pl-10 bg-slate-50 dark:bg-slate-800 rounded-3xl border border-slate-200 dark:border-slate-700 outline-none focus:ring-2 focus:ring-brand-500 text-3xl font-mono dark:text-white font-black transition-all shadow-sm"
                        placeholder="0.00"
                        autoFocus
                      />
                  </div>

                  <div className="flex justify-between items-start mt-4 px-1">
                    {isInvalidAmount && amount ? <p className="text-[10px] text-red-500 font-black uppercase bg-red-50 px-3 py-1 rounded-lg">Minimum is R{MIN_WITHDRAWAL}</p> : <span></span>}
                    <div className="text-right"><p className="text-sm font-black text-gray-900 dark:text-white">Avail: R {user.miCoinBalance.toFixed(2)}</p></div>
                  </div>
              </div>

              <div className="mt-8">
                <button 
                    disabled={!amount || isInvalidAmount || hasInsufficientFunds || processing}
                    onClick={handleWithdraw}
                    className="w-full py-5 bg-brand-600 disabled:bg-slate-200 dark:disabled:bg-slate-800 disabled:text-gray-400 text-white rounded-3xl font-black shadow-2xl shadow-brand-500/20 text-lg transition-all active:scale-[0.98]"
                >
                    {processing ? 'Generating Voucher...' : 'Confirm Cashout'}
                </button>
              </div>
          </div>
      );
  }

  return (
    <div className="flex flex-col h-full pb-24">
      <div className="p-5 space-y-6">
        <div className="flex justify-between items-center">
             <div className="flex items-center space-x-3">
                {onBack && (
                  <button onClick={onBack} className="p-3 -ml-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors text-gray-400 dark:text-slate-500">
                      <ArrowLeft className="w-6 h-6" />
                  </button>
                )}
                <h2 className="text-2xl font-bold text-gray-900 dark:text-white">MiCOINBANK</h2>
             </div>
        </div>

        <WalletCard user={user} />

        <div className="w-full bg-white dark:bg-slate-800 p-1.5 rounded-[2rem] shadow-sm border border-slate-100 dark:border-slate-700">
            <button 
                onClick={() => setWithdrawType('STORE')}
                className="w-full flex flex-row items-center justify-between p-5 rounded-[1.6rem] bg-gradient-to-br from-brand-50 to-white dark:from-slate-800 dark:to-slate-800/50 hover:from-brand-100 dark:hover:from-slate-700 transition-all group"
            >
                <div className="flex items-center">
                    <div className="w-14 h-14 bg-white dark:bg-slate-700 rounded-2xl flex items-center justify-center shadow-sm mr-5 group-hover:scale-110 transition-transform text-brand-600">
                        <Banknote className="w-7 h-7" />
                    </div>
                    <div className="text-left">
                        <span className="font-black text-xl text-gray-900 dark:text-white block tracking-tight">Cashout</span>
                        <span className="text-xs text-gray-500 dark:text-slate-400 font-medium">Withdraw at any partner store</span>
                    </div>
                </div>
                <div className="w-10 h-10 rounded-full bg-white dark:bg-slate-700 shadow-sm flex items-center justify-center group-hover:bg-brand-500 group-hover:text-white transition-all">
                    <ArrowRight className="w-5 h-5" />
                </div>
            </button>
        </div>

        {/* Wallet Activity Section (Clickable Entry) */}
        <div className="bg-white dark:bg-slate-800 p-1.5 rounded-[2rem] shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden">
            <button 
                onClick={() => setIsDetailedActivityOpen(true)}
                className="w-full flex items-center justify-between p-5 rounded-[1.6rem] hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors group"
            >
                <div className="flex items-center">
                    <div className="w-14 h-14 bg-brand-500/10 dark:bg-brand-500/20 text-brand-600 dark:text-brand-400 rounded-2xl flex items-center justify-center mr-5 shadow-sm group-hover:scale-110 transition-transform">
                        <History className="w-7 h-7" />
                    </div>
                    <div className="text-left">
                        <div className="flex items-center space-x-2">
                            <span className="font-black text-xl text-gray-900 dark:text-white block tracking-tight">Wallet Activity</span>
                            <div className="bg-brand-50 dark:bg-brand-900/30 px-2 py-0.5 rounded-lg text-[10px] font-black text-brand-600 dark:text-brand-400">
                                {walletActivity.length}
                            </div>
                        </div>
                        <span className="text-xs text-gray-500 dark:text-slate-400 font-medium">View detailed savings & withdrawals</span>
                    </div>
                </div>
                <div className="w-10 h-10 rounded-full bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-600 shadow-sm flex items-center justify-center group-hover:bg-brand-500 group-hover:text-white transition-all">
                    <ChevronRight className="w-5 h-5" />
                </div>
            </button>
        </div>

        <div className="bg-white dark:bg-slate-800 p-7 rounded-[2rem] shadow-sm border border-slate-100 dark:border-slate-700 transition-colors">
            <div className="flex justify-between items-center mb-8">
                <h3 className="font-black text-gray-900 dark:text-white flex items-center text-lg uppercase tracking-tight">
                    <Settings className="w-5 h-5 mr-3 text-brand-500" />
                    Auto-Save Engine
                </h3>
                <button 
                  onClick={onToggleAutoSave}
                  className={`relative inline-flex h-7 w-13 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-brand-500 focus:ring-offset-2 ${user.isAutoSaveEnabled ? 'bg-brand-500 shadow-lg shadow-brand-500/30' : 'bg-slate-200 dark:bg-slate-700'}`}
                >
                    <span className="sr-only">Enable Auto-Save</span>
                    <span className={`inline-block h-5 w-5 transform rounded-full bg-white shadow-md transition-transform duration-200 ease-in-out ${user.isAutoSaveEnabled ? 'translate-x-7' : 'translate-x-1'}`} />
                </button>
            </div>

            <div className={`transition-all duration-300 ${user.isAutoSaveEnabled ? 'opacity-100' : 'opacity-40 grayscale pointer-events-none'}`}>
                <div className="mb-8">
                    <div className="flex justify-between items-start mb-4">
                        <div>
                            <p className="text-sm text-gray-900 dark:text-slate-200 font-black uppercase tracking-tight">Savings Threshold</p>
                            <p className="text-[10px] text-gray-500 dark:text-slate-400 mt-1 font-medium">Save small change up to this amount</p>
                        </div>
                        <div className="bg-brand-50 dark:bg-brand-900/40 px-3 py-1.5 rounded-xl border border-brand-100 dark:border-brand-800 flex items-center">
                            <Target className="w-3 h-3 mr-2 text-brand-500" />
                            <span className="text-lg font-black text-brand-600 dark:text-brand-400">R {activeThreshold.toFixed(2)}</span>
                        </div>
                    </div>

                    <div className="flex bg-slate-100 dark:bg-slate-700 p-1 rounded-2xl space-x-1 mb-4">
                        {thresholdOptions.map((val) => (
                            <button key={val} onClick={() => onUpdateSettings(val)} className={`flex-1 py-3 rounded-xl text-xs font-black transition-all ${activeThreshold === val ? 'bg-white dark:bg-slate-600 text-brand-600 shadow-sm scale-100' : 'text-gray-400 hover:text-gray-600'}`}>R{val}</button>
                        ))}
                    </div>
                </div>

                <div className="bg-slate-50 dark:bg-slate-700/30 p-6 rounded-[2rem] border border-slate-100 dark:border-slate-700 relative overflow-hidden mb-10">
                    <h4 className="text-[10px] font-black uppercase tracking-widest text-gray-400 dark:text-slate-500 mb-6 text-center">Auto-Save Visualizer (R100 payment)</h4>
                    <div className="flex justify-between items-center mb-8 relative">
                        <div className="absolute left-10 right-10 top-1/2 h-0.5 bg-slate-200 dark:bg-slate-600 -z-10"></div>
                        <div className="flex flex-col items-center bg-white dark:bg-slate-800 p-3 rounded-2xl border border-slate-100 dark:border-slate-600 shadow-sm z-10 w-24">
                            <div className="w-10 h-10 bg-orange-100 dark:bg-orange-900/30 rounded-xl flex items-center justify-center mb-2 text-orange-600"><ShoppingCart className="w-5 h-5" /></div>
                            <span className="text-[9px] font-bold text-gray-400 uppercase">Total</span>
                            <span className="font-black text-xs text-gray-900 dark:text-white">R{examplePrice.toFixed(2)}</span>
                        </div>
                        <div className="flex flex-col items-center z-10">
                            <div className="bg-brand-500 text-white text-[10px] font-black px-3 py-1 rounded-full shadow-lg shadow-brand-500/30 mb-2">+ R{savingsAmount.toFixed(2)}</div>
                            <div className="w-2 h-2 bg-brand-500 rounded-full animate-ping"></div>
                        </div>
                        <div className="flex flex-col items-center bg-white dark:bg-slate-800 p-3 rounded-2xl border border-slate-100 dark:border-slate-600 shadow-sm z-10 w-24 opacity-60">
                            <div className="w-10 h-10 bg-gray-100 dark:bg-slate-700 rounded-xl flex items-center justify-center mb-2 text-gray-500"><Calculator className="w-5 h-5" /></div>
                            <span className="text-[9px] font-bold text-gray-400 uppercase">Change</span>
                            <span className="font-black text-xs text-gray-500 line-through">R{normalChange.toFixed(2)}</span>
                        </div>
                    </div>
                    <p className="text-xs text-center text-gray-500 dark:text-slate-400 leading-relaxed font-medium">
                        We round your <span className="font-black text-stone-800 dark:text-stone-200">R{examplePrice.toFixed(2)}</span> shop to the nearest <span className="font-black text-stone-800 dark:text-stone-200">R{activeThreshold} (R{roundedUpBill.toFixed(2)})</span>.
                    </p>
                </div>
            </div>

            {!user.isAutoSaveEnabled && (
                <div className="mt-8 p-5 rounded-2xl bg-slate-100 dark:bg-slate-800/50 border-2 border-dashed border-slate-200 dark:border-slate-700 flex items-center justify-center">
                    <Power className="w-5 h-5 text-gray-400 mr-3" />
                    <span className="text-sm font-black text-gray-400 dark:text-slate-500 uppercase tracking-tight">Auto-Save is Standby</span>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

