import React, { useState } from 'react';
import { User, Transaction } from '../types';
import { ArrowLeft, Smartphone, Wifi, Ticket, ChevronRight, CheckCircle, Loader2, Zap, CreditCard, ShieldCheck } from 'lucide-react';

interface BuyStoreProps {
  user: User;
  onBack: () => void;
  onUpdateBalance: (amount: number) => void;
  onAddTransaction: (tx: Transaction) => void;
}

type Category = 'AIRTIME' | 'DATA' | 'VOUCHERS' | null;

interface Provider {
  id: string;
  name: string;
  logo: string;
  color: string;
}

const PROVIDERS: Provider[] = [
  { id: 'vodacom', name: 'Vodacom', logo: '🔴', color: '#e60000' },
  { id: 'mtn', name: 'MTN', logo: '🟡', color: '#ffcc00' },
  { id: 'telkom', name: 'Telkom', logo: '🔵', color: '#0090d3' },
  { id: 'cellc', name: 'Cell C', logo: '⚪', color: '#000000' },
];

const VOUCHER_TYPES = [
  { id: 'netflix', name: 'Netflix', logo: '🎬', color: '#E50914' },
  { id: 'uber', name: 'Uber / Eats', logo: '🚗', color: '#000000' },
  { id: 'takealot', name: 'Takealot', logo: '📦', color: '#0b79bf' },
  { id: 'spotify', name: 'Spotify', logo: '🎵', color: '#1DB954' },
];

const BuyStore: React.FC<BuyStoreProps> = ({ user, onBack, onUpdateBalance, onAddTransaction }) => {
  const [category, setCategory] = useState<Category>(null);
  const [selectedProvider, setSelectedProvider] = useState<any>(null);
  const [amount, setAmount] = useState<string>('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const handlePurchase = () => {
    const cost = parseFloat(amount);
    if (isNaN(cost) || cost <= 0 || cost > user.miCoinBalance) return;

    setIsProcessing(true);
    setTimeout(() => {
      const tx: Transaction = {
        id: Date.now().toString(),
        store: selectedProvider?.name || category || 'Purchase',
        amount: 0,
        savings: cost,
        date: 'Just Now',
        category: category === 'VOUCHERS' ? 'Voucher' : 'Mobile',
        type: 'CASHOUT'
      };

      onAddTransaction(tx);
      onUpdateBalance(-cost);
      setIsProcessing(false);
      setIsSuccess(true);
    }, 2000);
  };

  const reset = () => {
    setCategory(null);
    setSelectedProvider(null);
    setAmount('');
    setIsSuccess(false);
  };

  if (isSuccess) {
    return (
      <div className="h-full flex flex-col items-center justify-center p-8 text-center animate-in zoom-in-95 duration-300">
        <div className="w-24 h-24 bg-green-50 rounded-full flex items-center justify-center mb-6 shadow-xl shadow-green-500/10">
          <CheckCircle className="w-12 h-12 text-green-500" />
        </div>
        <h2 className="text-2xl font-black text-slate-900 dark:text-white mb-2 uppercase tracking-tight">Purchase Successful!</h2>
        <p className="text-slate-500 dark:text-slate-400 text-sm mb-10 max-w-xs">
          Your {category?.toLowerCase()} has been issued. Check your SMS or email for details.
        </p>
        <button 
          onClick={onBack}
          className="w-full py-4 bg-brand-600 text-white rounded-2xl font-black text-sm uppercase tracking-widest shadow-lg active:scale-95 transition-transform"
        >
          Return to Wallet
        </button>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-white dark:bg-slate-900 animate-in slide-in-from-right-10 duration-300">
      <div className="p-5 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-white dark:bg-slate-900 sticky top-0 z-10">
        <div className="flex items-center space-x-3">
          <button onClick={category ? () => { if(selectedProvider) setSelectedProvider(null); else setCategory(null); } : onBack} className="p-2 -ml-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
            <ArrowLeft className="w-6 h-6 text-slate-900 dark:text-white" />
          </button>
          <h2 className="text-xl font-bold text-slate-900 dark:text-white">
            {selectedProvider ? selectedProvider.name : category ? category.charAt(0) + category.slice(1).toLowerCase() : 'Buy Services'}
          </h2>
        </div>
        <div className="text-right">
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Balance</p>
          <p className="text-sm font-black text-brand-600">R {user.miCoinBalance.toFixed(2)}</p>
        </div>
      </div>

