import React, { useState, useEffect } from 'react';
import { ArrowLeft, Scan, CreditCard, ShieldCheck, CheckCircle, Loader2, Info, Smartphone, HelpCircle } from 'lucide-react';

interface LinkPhysicalCardProps {
  onBack: () => void;
  onSuccess: () => void;
}

const LinkPhysicalCard: React.FC<LinkPhysicalCardProps> = ({ onBack, onSuccess }) => {
  const [step, setStep] = useState<'CHOICE' | 'SCAN' | 'MANUAL' | 'PROCESSING' | 'SUCCESS'>('CHOICE');
  const [cardNumber, setCardNumber] = useState('');
  const [scanProgress, setScanProgress] = useState(0);

  useEffect(() => {
    if (step === 'SCAN') {
      const interval = setInterval(() => {
        setScanProgress(prev => {
          if (prev >= 100) {
            clearInterval(interval);
            setStep('PROCESSING');
            return 100;
          }
          return prev + 2;
        });
      }, 50);
      return () => clearInterval(interval);
    }

    if (step === 'PROCESSING') {
      const timer = setTimeout(() => {
        setStep('SUCCESS');
      }, 2500);
      return () => clearTimeout(timer);
    }
  }, [step]);

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (cardNumber.length >= 8) {
      setStep('PROCESSING');
    }
  };

  if (step === 'SUCCESS') {
    return (
      <div className="h-full flex flex-col items-center justify-center p-8 text-center animate-in zoom-in-95 duration-500">
        <div className="w-24 h-24 bg-brand-50 rounded-full flex items-center justify-center mb-6 shadow-xl shadow-brand-500/10">
          <CheckCircle className="w-12 h-12 text-brand-500" />
        </div>
        <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-2 uppercase tracking-tight">Card Linked!</h2>
        <p className="text-slate-500 dark:text-slate-400 text-sm mb-10 max-w-xs leading-relaxed">
          Your physical card is now synced with your online MiCOINBANK. All your round-ups will update in real-time.
        </p>
        <button 
          onClick={onSuccess}
          className="w-full py-5 bg-brand-600 text-white rounded-[2rem] font-black text-sm uppercase tracking-widest shadow-xl shadow-brand-500/20 active:scale-95 transition-transform"
        >
          Go to My Wallet
        </button>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-white dark:bg-slate-900 animate-in slide-in-from-right-10 duration-300">
      {/* Header */}
      <div className="p-5 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-white dark:bg-slate-900 sticky top-0 z-10">
        <div className="flex items-center space-x-3">
          <button 
            onClick={step === 'CHOICE' ? onBack : () => setStep('CHOICE')} 
            className="p-2 -ml-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"
          >
            <ArrowLeft className="w-6 h-6 text-slate-900 dark:text-white" />
          </button>
          <h2 className="text-xl font-bold text-slate-900 dark:text-white">
            Link Physical Card
          </h2>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto">
        {step === 'CHOICE' && (
          <div className="p-6 space-y-8">
            <div className="text-center pt-6">
                <div className="w-20 h-20 bg-brand-50 dark:bg-brand-900/20 rounded-[2rem] flex items-center justify-center mx-auto mb-6 text-brand-600 dark:text-brand-400 shadow-inner">
                    <CreditCard className="w-10 h-10" />
                </div>
                <h3 className="text-2xl font-black text-slate-900 dark:text-white mb-2 tracking-tight uppercase">Found your Card?</h3>
                <p className="text-slate-500 dark:text-slate-400 text-sm max-w-[280px] mx-auto mb-8">
                    Lost your phone or just got a new physical card? Link it here to sync your balance.
                </p>
            </div>

            <div className="grid grid-cols-1 gap-4">
                <button 
                  onClick={() => setStep('SCAN')}
                  className="flex items-center p-6 bg-slate-50 dark:bg-slate-800 rounded-[2.5rem] border border-slate-100 dark:border-slate-700 hover:shadow-md transition-all group text-left"
                >
                    <div className="bg-brand-600 w-14 h-14 rounded-2xl flex items-center justify-center text-white shadow-lg mr-5 group-hover:scale-110 transition-transform">
                        <Scan className="w-7 h-7" />
                    </div>
                    <div className="flex-1">
                        <h4 className="font-black text-lg text-slate-900 dark:text-white uppercase tracking-tight">Scan Barcode</h4>
                        <p className="text-xs text-slate-500 dark:text-slate-400 font-medium">Use camera to link instantly</p>
                    </div>
                </button>

                <button 
                  onClick={() => setStep('MANUAL')}
                  className="flex items-center p-6 bg-slate-50 dark:bg-slate-800 rounded-[2.5rem] border border-slate-100 dark:border-slate-700 hover:shadow-md transition-all group text-left"
                >
                    <div className="bg-slate-200 dark:bg-slate-700 w-14 h-14 rounded-2xl flex items-center justify-center text-slate-600 dark:text-slate-400 shadow-inner mr-5 group-hover:scale-110 transition-transform">
                        <CreditCard className="w-7 h-7" />
                    </div>
                    <div className="flex-1">
                        <h4 className="font-black text-lg text-slate-900 dark:text-white uppercase tracking-tight">Enter Manually</h4>
                        <p className="text-xs text-slate-500 dark:text-slate-400 font-medium">Type in your Member ID</p>
                    </div>
                </button>
            </div>

            <div className="bg-blue-50 dark:bg-blue-900/20 p-5 rounded-[2rem] border border-blue-100 dark:border-blue-800 flex items-start space-x-4">
                <Info className="w-5 h-5 text-blue-500 mt-0.5 flex-shrink-0" />
                <div className="space-y-1">
                    <p className="text-xs font-black text-blue-900 dark:text-blue-300 uppercase">Security Note</p>
                    <p className="text-[11px] text-blue-700 dark:text-blue-400/80 leading-relaxed">
                        Linking a physical card will deactivate any previously linked lost cards for your safety.
                    </p>
                </div>
            </div>
          </div>
        )}

        {step === 'SCAN' && (
          <div className="flex flex-col items-center justify-center p-8 h-full">
            <div className="relative w-full aspect-square max-w-[300px] border-4 border-brand-500 rounded-[3rem] overflow-hidden bg-black shadow-2xl">
                {/* Simulated Camera View */}
                <div className="absolute inset-0 opacity-40 bg-[url('https://images.unsplash.com/photo-1556742044-3c52d6e88c62?auto=format&fit=crop&q=80&w=400')] bg-cover bg-center"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                    <div className="w-[80%] h-[20%] border-2 border-brand-400 rounded-lg shadow-[0_0_20px_rgba(20,184,166,0.5)] flex items-center justify-center">
                        <div className="w-full h-0.5 bg-brand-400 animate-[scan_2s_ease-in-out_infinite]"></div>
                    </div>
                </div>
                {/* Progress Overlay */}
                <div className="absolute bottom-0 left-0 right-0 h-1.5 bg-slate-800">
                    <div className="h-full bg-brand-500 transition-all duration-100" style={{ width: `${scanProgress}%` }}></div>
                </div>
            </div>
            <p className="mt-8 text-slate-500 dark:text-slate-400 font-black uppercase tracking-widest text-sm animate-pulse">Scanning Barcode...</p>
            <style>{`
              @keyframes scan {
                0%, 100% { transform: translateY(-30px); opacity: 0.5; }
                50% { transform: translateY(30px); opacity: 1; }
              }
            `}</style>
          </div>
        )}

        {step === 'MANUAL' && (
          <div className="p-8 space-y-8 animate-in slide-in-from-bottom-5">
            <div className="text-center">
                <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tight mb-2">Enter Member ID</h3>
                <p className="text-xs text-slate-500 font-medium">Find the 12-digit code on the back of your card.</p>
            </div>

            <form onSubmit={handleManualSubmit} className="space-y-6">
                <div className="relative group">
                    <input 
                      type="text"
                      value={cardNumber}
                      onChange={(e) => setCardNumber(e.target.value.replace(/\D/g, '').slice(0, 12))}
                      placeholder="8842 0000 0000"
                      className="w-full bg-slate-100 dark:bg-slate-800 p-6 rounded-[2rem] border-2 border-transparent focus:border-brand-500 outline-none font-mono text-2xl text-center font-black dark:text-white transition-all shadow-inner tracking-[0.1em]"
                      autoFocus
                    />
                </div>

                <button 
                  disabled={cardNumber.length < 8}
                  className="w-full py-5 bg-brand-600 disabled:bg-slate-200 dark:disabled:bg-slate-800 disabled:text-slate-400 text-white rounded-[2rem] font-black shadow-2xl shadow-brand-500/20 text-lg transition-all active:scale-[0.98]"
                >
                  Verify and Link Card
                </button>
            </form>

            <div className="flex flex-col items-center space-y-4 pt-10">
                <div className="flex -space-x-2">
                    {['🅿️', '🛒', '💊'].map((emoji, i) => (
                        <div key={i} className="w-10 h-10 bg-white dark:bg-slate-800 rounded-full flex items-center justify-center shadow-md border-2 border-slate-50 dark:border-slate-700 text-sm">
                            {emoji}
                        </div>
                    ))}
                </div>
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] text-center max-w-[200px]">
                    Works with all partner loyalty cards
                </p>
            </div>
          </div>
        )}

        {step === 'PROCESSING' && (
          <div className="h-full flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-500">
             <div className="relative mb-8">
                 <div className="absolute inset-0 bg-brand-500 rounded-full blur-xl opacity-20 animate-pulse"></div>
                 <div className="w-24 h-24 bg-white dark:bg-slate-800 rounded-[2.5rem] flex items-center justify-center shadow-2xl relative">
                    <Loader2 className="w-12 h-12 text-brand-500 animate-spin" />
                 </div>
             </div>
             <h3 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tight mb-2">Syncing Data...</h3>
             <p className="text-slate-500 dark:text-slate-400 text-sm font-medium">Verifying your savings identity across our secure network.</p>
          </div>
        )}
      </div>

      {step === 'CHOICE' && (
          <div className="p-8 pb-12 flex justify-center">
              <button className="flex items-center space-x-2 text-slate-400 hover:text-slate-600 transition-colors">
                  <HelpCircle className="w-4 h-4" />
                  <span className="text-[10px] font-black uppercase tracking-widest">Need help with your card?</span>
              </button>
          </div>
      )}
    </div>
  );
};

export default LinkPhysicalCard;

export interface Transaction {
  id: string;
  storeId?: string; // Link to a specific store
  store: string;
  amount: number;
  roundedAmount?: number; // Optional, only for purchases
  savings: number; // The difference or cashback amount
  date: string;
  category: string;
  items?: string[]; // Simple list for dashboard
  receiptData?: ReceiptData; // Full detailed receipt
  type: 'PURCHASE' | 'ROUND_UP' | 'CASHBACK' | 'CASHOUT';
}

export interface ReceiptItem {
  description: string;
  quantity: number;
  price: number;
  total: number;
  isPromo?: boolean; // Triggers cashback
  promoDescription?: string;
}

export interface ReceiptData {
  merchantName: string;
  address: string[];
  vatNo: string;
  tel: string;
  cashier: string;
  items: ReceiptItem[];
  subtotal: number;
  vat: number;
  total: number;
  tender: string;
  change: number;
  barcode: string;
  date: string;
  time: string;
}

export interface User {
  name: string;
  miCoinBalance: number;
  totalSaved: number;
  roundUpTarget: number; // 1 to 20 (Round up to nearest X)
  isAutoSaveEnabled: boolean; // Toggle for MiCOINBANK feature
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  isThinking?: boolean;
  image?: string; // Base64 string for display
}

export interface Product {
  id: string;
  name: string;
  price: number;
  oldPrice?: number;
  inStock: boolean;
  image?: string;
  category: string;
  cashbackAmount?: number; // New: For SnapSave feature
}

export interface ShoppingListItem extends Product {
  storeId: string;
  storeName: string;
  storeColor: string;
  quantity: number;
}

export interface SavedList {
  id: string;
  name: string;
  date: string;
  items: ShoppingListItem[];
  total: number;
  totalSavings: number;
}

export interface Store {
  id: string;
  name: string;
  color: string; // Tailwind bg class or hex
  logo: string; // Emoji or URL
  isLinked: boolean;
  loyaltyPoints: number;
  pointsExpiring?: number;
  notificationCount: number; // Total notifications
  tabAlerts: {
    shop: number;
    slips: number;
    promos: number; // Cashback/Deals
    loyalty: number;
  };
  promos: Product[];
  inventory: Product[];
}

