const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [stores, setStores] = useState<Store[]>(INITIAL_STORES);
  const [transactions, setTransactions] = useState<Transaction[]>(INITIAL_TRANSACTIONS);
  const [selectedStore, setSelectedStore] = useState<Store | null>(null);
  const [user, setUser] = useState<User>(MOCK_USER);
  const [showBalance, setShowBalance] = useState(true);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleStoreClick = (store: Store) => {
    setSelectedStore(store);
    setActiveTab(AppTab.STORE_VIEW);
  };

  const handleBackFromStore = () => {
    setSelectedStore(null);
    setActiveTab(AppTab.DASHBOARD);
  };

  const handleUpdateStore = (updatedStore: Store) => {
    setStores(stores.map(s => s.id === updatedStore.id ? updatedStore : s));
    setSelectedStore(updatedStore); // Update the currently viewed store
  };

  const handleUpdateSettings = (roundUpTarget: number) => {
    setUser({ ...user, roundUpTarget });
  };

  const handleToggleAutoSave = () => {
      setUser(prev => ({ ...prev, isAutoSaveEnabled: !prev.isAutoSaveEnabled }));
  };

  const handleUpdateBalance = (amount: number) => {
      setUser(prev => ({
          ...prev,
          miCoinBalance: prev.miCoinBalance + amount
      }));
  };

  const handleAddTransaction = (tx: Transaction) => {
      setTransactions(prev => [tx, ...prev]);
  };

  const handleLinkPhysicalCard = (newId: string) => {
      // Format ID to 8842 XXXX XXXX if raw
      let formattedId = newId;
      if (newId.length === 12) {
          formattedId = `${newId.slice(0, 4)} ${newId.slice(4, 8)} ${newId.slice(8, 12)}`;
      }

      setUser(prev => ({
          ...prev,
          memberId: formattedId,
          isAutoSaveEnabled: false // Disable auto-save engine as requested for physical cards
      }));
      setActiveTab(AppTab.WALLET);
  };

  const handleGoBack = () => {
    setActiveTab(AppTab.DASHBOARD);
    setSelectedStore(null);
  };

  const renderContent = () => {
    switch (activeTab) {
      case AppTab.DASHBOARD:
        return (
          <Dashboard 
            user={user} 
            recentTransactions={transactions} 
            stores={stores}
            onStoreClick={handleStoreClick}
            showBalance={showBalance}
            onToggleBalance={() => setShowBalance(!showBalance)}
          />
        );
      case AppTab.STORE_VIEW:
        if (!selectedStore) return null;
        return (
          <StoreDetail 
            store={selectedStore} 
            transactions={transactions}
            onBack={handleBackFromStore}
            onUpdateStore={handleUpdateStore}
            onUpdateBalance={handleUpdateBalance}
            onAddTransaction={handleAddTransaction}
          />
        );
      case AppTab.WALLET:
        return (
          <WalletView 
            user={user} 
            transactions={transactions}
            onUpdateSettings={handleUpdateSettings}
            onToggleAutoSave={handleToggleAutoSave}
            onUpdateBalance={handleUpdateBalance}
            onAddTransaction={handleAddTransaction}
            onBack={handleGoBack}
            onOpenBuy={() => setActiveTab(AppTab.BUY)}
            onOpenLinkCard={() => setActiveTab(AppTab.LINK_CARD)}
          />
        );
      case AppTab.BUY:
        return (
          <BuyStore 
            user={user}
            onBack={() => setActiveTab(AppTab.WALLET)}
            onUpdateBalance={handleUpdateBalance}
            onAddTransaction={handleAddTransaction}
          />
        );
      case AppTab.LINK_CARD:
        return (
          <LinkPhysicalCard 
            onBack={() => setActiveTab(AppTab.WALLET)}
            onSuccess={handleLinkPhysicalCard}
          />
        );
      case AppTab.ASSISTANT:
        return <ReceiptAssistant onBack={handleGoBack} />;
      case AppTab.HISTORY:
        return (
          <div className="p-5 pb-20">
            <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-4 px-1">Activity History</h2>
            <div className="space-y-3">
              {transactions.map((tx) => (
                <div key={tx.id} className={`bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 transition-colors ${tx.type === 'CASHOUT' ? 'border-l-4 border-l-slate-400' : ''}`}>
                  <div className="flex justify-between items-center mb-2">
                    <div className="flex items-center space-x-2">
                        {tx.type === 'CASHOUT' && <ArrowUpRight className="w-4 h-4 text-slate-400" />}
                        <span className="font-semibold text-gray-800 dark:text-white">{tx.store}</span>
                    </div>
                    <span className={`text-[10px] font-bold uppercase tracking-wider px-2 py-1 rounded-md ${
                        tx.type === 'CASHBACK' ? 'bg-accent-500/10 text-accent-500' : 
                        tx.type === 'CASHOUT' ? 'bg-slate-100 dark:bg-slate-700 text-gray-500 dark:text-slate-400' :
                        'bg-brand-50 dark:bg-brand-900/30 text-brand-600 dark:text-brand-400'
                    }`}>
                        {tx.type === 'CASHBACK' ? 'Cashback' : tx.type === 'CASHOUT' ? 'Withdrawal' : tx.category}
                    </span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <div className="text-gray-500 dark:text-slate-400">
                      {tx.type === 'CASHBACK' ? (
                          <span>Promo Reward</span>
                      ) : tx.type === 'CASHOUT' ? (
                          <span>Payment / Withdrawal</span>
                      ) : (
                          <span>Paid: R {tx.amount.toFixed(2)}</span>
                      )}
                    </div>
                    <div className={`font-black ${tx.type === 'CASHOUT' ? 'text-gray-900 dark:text-white' : 'text-brand-600 dark:text-brand-400'}`}>
                      {tx.type === 'CASHOUT' ? '-' : tx.type === 'CASHBACK' ? '+' : ''} R {tx.savings.toFixed(2)} {tx.type === 'CASHOUT' ? 'Used' : 'Saved'}
                    </div>
                  </div>
                  <div className="mt-2 text-[10px] text-gray-400 dark:text-slate-500 flex justify-between">
                     <span>{tx.date}</span>
                     {tx.type === 'ROUND_UP' && <span>Rounded from: R {tx.amount.toFixed(2)}</span>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      default:
        return (
          <Dashboard 
            user={user} 
            recentTransactions={transactions} 
            stores={stores} 
            onStoreClick={handleStoreClick}
            showBalance={showBalance}
            onToggleBalance={() => setShowBalance(!showBalance)}
          />
        );
    }
  };

  return (
    <div className={isDarkMode ? 'dark' : ''}>
      <div className="min-h-screen bg-gray-50 dark:bg-slate-900 font-sans text-slate-900 dark:text-slate-100 flex justify-center transition-colors duration-300">
        {/* Mobile Container Limit */}
        <div className="w-full max-w-lg bg-gray-50 dark:bg-slate-900 min-h-screen relative flex flex-col transition-colors duration-300">

          {/* Top Navbar */}
          {activeTab !== AppTab.STORE_VIEW && (
            <header className="bg-white dark:bg-slate-800 px-5 py-4 flex justify-between items-center sticky top-0 z-20 shadow-sm border-b border-transparent dark:border-slate-700 transition-colors">
              <div className="flex items-center space-x-3">
                {activeTab !== AppTab.DASHBOARD && (
                  <button 
                    onClick={handleGoBack}
                    className="p-2 -ml-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full transition-colors text-gray-600 dark:text-slate-300"
                  >
                    <ArrowLeft className="w-5 h-5" />
                  </button>
                )}
                <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white font-bold">C</div>
                <div className="text-lg font-bold tracking-tight font-sans flex items-baseline">
                    <span className="text-gray-900 dark:text-white">Cardit</span>
                    <span className="text-[#22c55e]">Oe'</span>
                </div>
              </div>
              <div className="flex items-center space-x-4">
                <button 
                  onClick={toggleTheme} 
                  className="p-1 text-gray-600 dark:text-slate-300 hover:text-brand-600 dark:hover:text-brand-400 transition-colors"
                >
                  {isDarkMode ? <Sun className="w-6 h-6" /> : <Moon className="w-6 h-6" />}
                </button>
                <button className="relative p-1">
                    <Bell className="w-6 h-6 text-gray-600 dark:text-slate-300" />
                    <span className="absolute top-0 right-0 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white dark:border-slate-800"></span>
                </button>
                <button>
                    <Menu className="w-6 h-6 text-gray-600 dark:text-slate-300" />
                </button>
              </div>
            </header>
          )}

          {/* Main Content Area */}
          <main className="flex-1 overflow-y-auto">
            {renderContent()}
          </main>

          {/* Bottom Navigation */}
          {activeTab !== AppTab.STORE_VIEW && (
            <nav className="bg-white dark:bg-slate-800 border-t border-gray-200 dark:border-slate-700 fixed bottom-0 w-full max-w-lg pb-safe z-30 transition-colors">
              <div className="flex justify-around items-center h-16">
                <button 
                  onClick={() => setActiveTab(AppTab.DASHBOARD)}
                  className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${activeTab === AppTab.DASHBOARD ? 'text-brand-600 dark:text-brand-400' : 'text-gray-400 dark:text-slate-500'}`}
                >
