interface LinkPhysicalCardProps {
  onBack: () => void;
  onSuccess: (cardNumber: string) => void;
}

const LinkPhysicalCard: React.FC<LinkPhysicalCardProps> = ({ onBack, onSuccess }) => {
  const [step, setStep] = useState<'CHOICE' | 'SCAN' | 'MANUAL' | 'PROCESSING' | 'SUCCESS'>('CHOICE');
  const [cardNumber, setCardNumber] = useState('');
  const [scanProgress, setScanProgress] = useState(0);

  useEffect(() => {
    if (step === 'SCAN') {
      const interval = setInterval(() => {
        setScanProgress(prev => {
          if (prev >= 100) {
            clearInterval(interval);
            // Simulate a detected ID
            setCardNumber(Math.floor(884200000000 + Math.random() * 99999999).toString());
            setStep('PROCESSING');
            return 100;
          }
          return prev + 2;
        });
      }, 50);
      return () => clearInterval(interval);
    }

    if (step === 'PROCESSING') {
      const timer = setTimeout(() => {
        setStep('SUCCESS');
      }, 2500);
      return () => clearTimeout(timer);
    }
  }, [step]);

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (cardNumber.length >= 8) {
      setStep('PROCESSING');
    }
  };

  if (step === 'SUCCESS') {
    return (
      <div className="h-full flex flex-col items-center justify-center p-8 text-center animate-in zoom-in-95 duration-500">
        <div className="w-24 h-24 bg-brand-50 rounded-full flex items-center justify-center mb-6 shadow-xl shadow-brand-500/10">
