                </button>
                <button>
                    <Menu className="w-6 h-6 text-gray-600 dark:text-slate-300" />
                </button>
              </div>
            </header>
          )}

          {/* Main Content Area */}
          <main className="flex-1 overflow-y-auto">
            {renderContent()}
          </main>

          {/* Bottom Navigation */}
          {activeTab !== AppTab.STORE_VIEW && (
            <nav className="bg-white dark:bg-slate-800 border-t border-gray-200 dark:border-slate-700 fixed bottom-0 w-full max-w-lg pb-safe z-30 transition-colors">
