  WALLET = 'WALLET',
  ASSISTANT = 'ASSISTANT',
  HISTORY = 'HISTORY',
  STORE_VIEW = 'STORE_VIEW',
  GROCERY_LIST = 'GROCERY_LIST',
  BUY = 'BUY',
  LINK_CARD = 'LINK_CARD'
}

import React, { useState } from 'react';
import { Fingerprint, Smartphone, ShieldCheck, Loader2 } from 'lucide-react';

interface LoginProps {
  onLogin: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isAuthenticating, setIsAuthenticating] = useState(false);
  const [pin, setPin] = useState('');

  const handleBiometric = () => {
    setIsAuthenticating(true);
    // Simulate FaceID/Fingerprint delay
    setTimeout(() => {
      setIsAuthenticating(false);
      onLogin();
    }, 1500);
  };

  const handlePinInput = (num: number) => {
    if (pin.length < 6) {
      const newPin = pin + num;
      setPin(newPin);
      if (newPin.length === 6) {
        setIsAuthenticating(true);
        setTimeout(() => {
          setIsAuthenticating(false);
          onLogin();
        }, 1000);
      }
    }
  };

  const clearPin = () => setPin('');

  return (
    <div className="min-h-screen flex flex-col bg-white dark:bg-slate-900 transition-colors">
      <div className="flex-1 flex flex-col items-center justify-center p-8">
        <div className="mb-12 text-center animate-in fade-in zoom-in duration-700">
          <div className="text-5xl font-black tracking-tighter font-sans flex items-baseline justify-center mb-2">
              <span className="text-gray-900 dark:text-white">Cardit</span>
              <span className="text-brand-500">Oe'</span>
          </div>
          <p className="text-slate-500 dark:text-slate-400 font-medium text-sm tracking-wide">Secure Savings Identity</p>
        </div>

        {isAuthenticating ? (
          <div className="flex flex-col items-center space-y-4 animate-in fade-in duration-300">
            <div className="relative">
              <div className="absolute inset-0 bg-brand-500 rounded-full blur-xl opacity-20 animate-pulse"></div>
              <Loader2 className="w-16 h-16 text-brand-500 animate-spin relative z-10" />
            </div>
            <p className="text-sm font-black text-slate-400 uppercase tracking-widest">Verifying Identity...</p>
          </div>
        ) : (
          <div className="w-full max-w-xs space-y-12">
            <div className="flex flex-col items-center">
              <button 
                onClick={handleBiometric}
                className="w-24 h-24 bg-brand-50 dark:bg-brand-900/20 rounded-[2.5rem] flex items-center justify-center text-brand-600 dark:text-brand-400 mb-6 shadow-inner active:scale-95 transition-transform"
              >
                <Fingerprint className="w-12 h-12" />
              </button>
              <p className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em]">Tap to unlock</p>
            </div>

            <div className="space-y-6">
              <div className="flex justify-center space-x-3">
                {[...Array(6)].map((_, i) => (
                  <div 
                    key={i} 
                    className={`w-3 h-3 rounded-full transition-all duration-300 ${
                      i < pin.length ? 'bg-brand-500 scale-125' : 'bg-slate-200 dark:bg-slate-700'
                    }`}
                  />
                ))}
              </div>

              <div className="grid grid-cols-3 gap-4">
                {[1, 2, 3, 4, 5, 6, 7, 8, 9, 'C', 0, '⌫'].map((val, i) => (
                  <button 
                    key={i}
                    onClick={() => {
                      if (val === 'C') clearPin();
                      else if (val === '⌫') setPin(pin.slice(0, -1));
                      else typeof val === 'number' && handlePinInput(val);
                    }}
                    className="h-14 flex items-center justify-center bg-slate-50 dark:bg-slate-800 rounded-2xl text-xl font-bold text-slate-900 dark:text-white hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors active:scale-90"
                  >
                    {val}
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-8 pb-12 flex flex-col items-center space-y-4">
        <div className="flex items-center space-x-2 text-slate-400 dark:text-slate-600">
          <ShieldCheck className="w-4 h-4" />
          <span className="text-[10px] font-black uppercase tracking-[0.2em]">Bank-grade Encryption</span>
        </div>
        <button className="text-[11px] font-black text-brand-600 uppercase tracking-widest hover:underline">
          Register New Account
        </button>
      </div>
    </div>
  );
};

export default Login;

