import React, { useState, useEffect, useRef } from 'react';
import { Store } from '../types';
import { Bell, Lock, Unlock, Coins } from 'lucide-react';

interface StoreCardProps {
  store: Store;
  onClick: (store: Store) => void;
}

const StoreCard: React.FC<StoreCardProps> = ({ store, onClick }) => {
  const [animateSuccess, setAnimateSuccess] = useState(false);
  const prevIsLinked = useRef(store.isLinked);

  useEffect(() => {
    // Trigger animation when the card transitions from unlinked to linked
    if (!prevIsLinked.current && store.isLinked) {
        setAnimateSuccess(true);
        const timer = setTimeout(() => setAnimateSuccess(false), 1500);
        return () => clearTimeout(timer);
    }
    prevIsLinked.current = store.isLinked;
  }, [store.isLinked]);

  // Conversion: 100 points = R1.00
  const randValue = (store.loyaltyPoints / 100).toFixed(2);

  const renderCardContent = () => {
    switch(store.id) {
      case 'picknpay':
        return (
          <div className="h-full w-full bg-[#0b1f3f] text-white p-4 relative overflow-hidden border border-white/5">
             <div className="absolute -right-6 -top-6 w-32 h-32 rounded-full border-[16px] border-[#b91c68] opacity-15"></div>

             <div className="relative z-10 flex flex-col h-full justify-between">
