{
  "name": "CarditOe'",
  "description": "A smart savings companion that rounds up your purchases to the nearest Rand, storing the change in your MiCOINBANK wallet. Features a smart receipt assistant powered by Gemini.",
  "requestFramePermissions": [
    "camera",
