import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using gemini-3-flash-preview for balanced performance
const MODEL_NAME = 'gemini-3-flash-preview';
const MAPS_MODEL = 'gemini-2.5-flash-lite-latest'; // Best for maps grounding

export const sendMessageToAssistant = async (
  message: string, 
  imageBase64?: string
): Promise<string> => {
  try {
    const parts: any[] = [];

    if (imageBase64) {
      const cleanBase64 = imageBase64.split(',')[1] || imageBase64;
      parts.push({
        inlineData: {
          mimeType: 'image/jpeg',
          data: cleanBase64
        }
      });
    }

    parts.push({
      text: message || (imageBase64 ? "Analyze this receipt. List the items purchased, total amount, and categorize the spending." : "Hello")
    });

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: { parts: parts },
      config: {
        systemInstruction: `You are CarditOe's Smart Receipt Assistant. 
        Your goal is to help users manage their finances by analyzing receipts and answering questions about their spending habits.
        When analyzing a receipt, extract the Merchant Name, Total Amount (in Rands 'R'), and a list of purchased items.
        Keep responses concise, helpful, and friendly.`,
      }
    });

    return response.text || "I couldn't generate a response. Please try again.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Sorry, I encountered an error processing your request.";
  }
};

export const findNearbyStores = async (
  storeName: string,
  itemName: string,
  lat: number,
  lng: number
): Promise<{ text: string; links: { web?: { uri: string; title: string }; maps?: { uri: string; title: string } }[] }> => {
  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MAPS_MODEL,
      contents: `Find the nearest ${storeName} branches around me. Also, check if they are likely to have "${itemName}" in stock or if there are other ${storeName} locations with better deals nearby.`,
      config: {
        tools: [{ googleMaps: {} }, { googleSearch: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: lat,
              longitude: lng
            }
          }
        },
        systemInstruction: `You are CarditOe's Location Expert. Help users find specific stores and check stock. 
        Provide a list of nearby stores with distances if possible.
        ALWAYS extract the URLs from groundingChunks and provide them in your response.
        Be helpful and concise.`
      }
    });

    const text = response.text || "No information found.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const links = chunks.map((chunk: any) => {
      if (chunk.maps) return { maps: { uri: chunk.maps.uri, title: chunk.maps.title } };
      if (chunk.web) return { web: { uri: chunk.web.uri, title: chunk.web.title } };
      return null;
    }).filter(Boolean);

    return { text, links };
  } catch (error) {
    console.error("Gemini Maps Error:", error);
    return { text: "I couldn't locate nearby stores at the moment.", links: [] };
  }
};

import React, { useState, useEffect } from 'react';
import { Store, Transaction } from '../types';
