      setTransactions(prev => [tx, ...prev]);
  };

  const handleLinkPhysicalCard = (newId: string) => {
      let formattedId = newId;
      if (newId.length === 12) {
          formattedId = `${newId.slice(0, 4)} ${newId.slice(4, 8)} ${newId.slice(8, 12)}`;
      }

      setUser(prev => ({
          ...prev,
          memberId: formattedId,
          isAutoSaveEnabled: false 
      }));
      setActiveTab(AppTab.WALLET);
  };

  // Grocery List Handlers
  const handleAddItemToGrocery = (item: ShoppingListItem) => {
    setShoppingList(prev => {
      const existing = prev.find(i => i.id === item.id && i.storeId === item.storeId);
      if (existing) {
        return prev.map(i => (i.id === item.id && i.storeId === item.storeId) ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, item];
    });
  };

  const handleRemoveItemFromGrocery = (itemId: string, storeId: string) => {
    setShoppingList(prev => prev.filter(i => !(i.id === itemId && i.storeId === storeId)));
  };

  const handleUpdateQuantityGrocery = (itemId: string, storeId: string, delta: number) => {
    setShoppingList(prev => prev.map(i => (i.id === itemId && i.storeId === storeId) ? { ...i, quantity: Math.max(1, i.quantity + delta) } : i));
  };

  const handleSaveList = (name: string) => {
    const total = shoppingList.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const totalSavings = shoppingList.reduce((sum, item) => {
      const savingPerItem = item.oldPrice ? (item.oldPrice - item.price) : 0;
      const cashback = item.cashbackAmount || 0;
      return sum + ((savingPerItem + cashback) * item.quantity);
    }, 0);

    const newList: SavedList = {
      id: Date.now().toString(),
      name,
      date: new Date().toLocaleDateString(),
      items: [...shoppingList],
      total,
      totalSavings
    };
    setSavedLists(prev => [newList, ...prev]);
  };

  const handleLoadList = (list: SavedList) => {
    setShoppingList([...list.items]);
  };

  const handleDeleteSavedList = (listId: string) => {
    setSavedLists(prev => prev.filter(l => l.id !== listId));
  };

  const handleGoBack = () => {
    setActiveTab(AppTab.DASHBOARD);
    setSelectedStore(null);
  };

  const handleLogout = () => {
    setActiveTab(AppTab.LOGIN);
  };

  const renderContent = () => {
    switch (activeTab) {
      case AppTab.LOGIN:
        return <Login onLogin={() => setActiveTab(AppTab.DASHBOARD)} />;
      case AppTab.DASHBOARD:
        return (
          <Dashboard 
            user={user} 
            recentTransactions={transactions} 
            stores={stores}
            onStoreClick={handleStoreClick}
            showBalance={showBalance}
            onToggleBalance={() => setShowBalance(!showBalance)}
          />
        );
      case AppTab.STORE_VIEW:
        if (!selectedStore) return null;
        return (
          <StoreDetail 
            store={selectedStore} 
            transactions={transactions}
            onBack={handleBackFromStore}
            onUpdateStore={handleUpdateStore}
            onUpdateBalance={handleUpdateBalance}
            onAddTransaction={handleAddTransaction}
          />
        );
      case AppTab.WALLET:
        return (
          <WalletView 
            user={user} 
            transactions={transactions}
            onUpdateSettings={handleUpdateSettings}
            onToggleAutoSave={handleToggleAutoSave}
            onUpdateBalance={handleUpdateBalance}
            onAddTransaction={handleAddTransaction}
            onBack={handleGoBack}
            onOpenBuy={() => setActiveTab(AppTab.BUY)}
            onOpenLinkCard={() => setActiveTab(AppTab.LINK_CARD)}
          />
        );
      case AppTab.BUY:
        return (
          <BuyStore 
            user={user}
            onBack={() => setActiveTab(AppTab.WALLET)}
            onUpdateBalance={handleUpdateBalance}
            onAddTransaction={handleAddTransaction}
          />
        );
      case AppTab.LINK_CARD:
        return (
          <LinkPhysicalCard 
            onBack={() => setActiveTab(AppTab.WALLET)}
            onSuccess={handleLinkPhysicalCard}
          />
        );
      case AppTab.GROCERY_LIST:
        return (
          <GroceryAssistant 
            stores={stores}
            shoppingList={shoppingList}
            savedLists={savedLists}
            onAddItem={handleAddItemToGrocery}
            onRemoveItem={handleRemoveItemFromGrocery}
            onUpdateQuantity={handleUpdateQuantityGrocery}
            onSaveList={handleSaveList}
            onLoadList={handleLoadList}
            onDeleteList={handleDeleteSavedList}
          />
        );
      case AppTab.ASSISTANT:
        return <ReceiptAssistant onBack={handleGoBack} />;
      case AppTab.PROFILE:
        return <ProfileView user={user} onLogout={handleLogout} onBack={handleGoBack} />;
      case AppTab.HISTORY:
        return (
          <div className="p-5 pb-20">
            <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-4 px-1">Activity History</h2>
            <div className="space-y-3">
              {transactions.map((tx) => (
                <div key={tx.id} className={`bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 transition-colors ${tx.type === 'CASHOUT' ? 'border-l-4 border-l-slate-400' : ''}`}>
                  <div className="flex justify-between items-center mb-2">
                    <div className="flex items-center space-x-2">
                        {tx.type === 'CASHOUT' && <ArrowUpRight className="w-4 h-4 text-slate-400" />}
                        <span className="font-semibold text-gray-800 dark:text-white">{tx.store}</span>
                    </div>
                    <span className={`text-[10px] font-bold uppercase tracking-wider px-2 py-1 rounded-md ${
                        tx.type === 'CASHBACK' ? 'bg-accent-500/10 text-accent-500' : 
                        tx.type === 'CASHOUT' ? 'bg-slate-100 dark:bg-slate-700 text-gray-500 dark:text-slate-400' :
                        'bg-brand-50 dark:bg-brand-900/30 text-brand-600 dark:text-brand-400'
                    }`}>
                        {tx.type === 'CASHBACK' ? 'Cashback' : tx.type === 'CASHOUT' ? 'Withdrawal' : tx.category}
                    </span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <div className="text-gray-500 dark:text-slate-400">
                      {tx.type === 'CASHBACK' ? (
                          <span>Promo Reward</span>
                      ) : tx.type === 'CASHOUT' ? (
                          <span>Payment / Withdrawal</span>
                      ) : (
                          <span>Paid: R {tx.amount.toFixed(2)}</span>
                      )}
                    </div>
                    <div className={`font-black ${tx.type === 'CASHOUT' ? 'text-gray-900 dark:text-white' : 'text-brand-600 dark:text-brand-400'}`}>
                      {tx.type === 'CASHOUT' ? '-' : tx.type === 'CASHBACK' ? '+' : ''} R {tx.savings.toFixed(2)} {tx.type === 'CASHOUT' ? 'Used' : 'Saved'}
                    </div>
                  </div>
                  <div className="mt-2 text-[10px] text-gray-400 dark:text-slate-500 flex justify-between">
                     <span>{tx.date}</span>
                     {tx.type === 'ROUND_UP' && <span>Rounded from: R {tx.amount.toFixed(2)}</span>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      default:
        return <Login onLogin={() => setActiveTab(AppTab.DASHBOARD)} />;
    }
  };

  return (
    <div className={isDarkMode ? 'dark' : ''}>
      <div className="min-h-screen bg-gray-50 dark:bg-slate-900 font-sans text-slate-900 dark:text-slate-100 flex justify-center transition-colors duration-300">
        {/* Mobile Container Limit */}
        <div className="w-full max-w-lg bg-gray-50 dark:bg-slate-900 min-h-screen relative flex flex-col transition-colors duration-300">

          {/* Top Navbar */}
          {activeTab !== AppTab.STORE_VIEW && activeTab !== AppTab.LOGIN && (
            <header className="bg-white dark:bg-slate-800 px-5 py-4 flex justify-between items-center sticky top-0 z-20 shadow-sm border-b border-transparent dark:border-slate-700 transition-colors">
              <div className="flex items-center space-x-3">
                {activeTab !== AppTab.DASHBOARD && (
                  <button 
                    onClick={handleGoBack}
                    className="p-2 -ml-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full transition-colors text-gray-600 dark:text-slate-300"
                  >
                    <ArrowLeft className="w-5 h-5" />
                  </button>
                )}
                <div 
                  onClick={() => setActiveTab(AppTab.DASHBOARD)} 
                  className="text-xl font-black tracking-tighter font-sans flex items-baseline cursor-pointer"
                >
                    <span className="text-gray-900 dark:text-white">Cardit</span>
                    <span className="text-brand-500">Oe'</span>
                </div>
              </div>
              <div className="flex items-center space-x-4">
                <button 
                  onClick={toggleTheme} 
                  className="p-1 text-gray-600 dark:text-slate-300 hover:text-brand-600 dark:hover:text-brand-400 transition-colors"
                >
                  {isDarkMode ? <Sun className="w-6 h-6" /> : <Moon className="w-6 h-6" />}
                </button>
                <button className="relative p-1">
                    <Bell className="w-6 h-6 text-gray-600 dark:text-slate-300" />
                    <span className="absolute top-0 right-0 w-2.5 h-2.5 bg-brand-500 rounded-full border-2 border-white dark:border-slate-800"></span>
                </button>
                <button 
                  onClick={() => setActiveTab(AppTab.PROFILE)}
                  className={`p-1 rounded-full transition-colors ${activeTab === AppTab.PROFILE ? 'text-brand-600' : 'text-gray-600 dark:text-slate-300'}`}
                >
                    <Menu className="w-6 h-6" />
                </button>
              </div>
            </header>
          )}

          {/* Main Content Area */}
          <main className="flex-1 overflow-y-auto">
            {renderContent()}
          </main>

          {/* Bottom Navigation */}
          {activeTab !== AppTab.STORE_VIEW && activeTab !== AppTab.LOGIN && (
            <nav className="bg-white dark:bg-slate-800 border-t border-gray-200 dark:border-slate-700 fixed bottom-0 w-full max-w-lg pb-safe z-30 transition-colors">
              <div className="flex justify-around items-center h-16">
                <button 
                  onClick={() => setActiveTab(AppTab.DASHBOARD)}
                  className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${activeTab === AppTab.DASHBOARD ? 'text-brand-600 dark:text-brand-400' : 'text-gray-400 dark:text-slate-500'}`}
                >
                  <Home className="w-6 h-6" />
                  <span className="text-[10px] font-medium">Home</span>
                </button>

                <button 
                  onClick={() => setActiveTab(AppTab.WALLET)}
                  className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${activeTab === AppTab.WALLET || activeTab === AppTab.BUY || activeTab === AppTab.LINK_CARD ? 'text-brand-600 dark:text-brand-400' : 'text-gray-400 dark:text-slate-500'}`}
                >
                  <CreditCard className="w-6 h-6" />
                  <span className="text-[10px] font-medium">MiCOINBANK</span>
                </button>

                {/* FAB for Assistant */}
                <div className="relative -top-6">
                    <button 
                      onClick={() => setActiveTab(AppTab.ASSISTANT)}
                      className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg transform transition-transform ${activeTab === AppTab.ASSISTANT ? 'bg-brand-700 scale-110' : 'bg-brand-600 hover:scale-105'} text-white border-4 border-gray-50 dark:border-slate-900`}
                    >
                      <MessageSquare className="w-6 h-6" />
                    </button>
                </div>

                <button 
                  onClick={() => setActiveTab(AppTab.GROCERY_LIST)} 
                  className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${activeTab === AppTab.GROCERY_LIST ? 'text-brand-600 dark:text-brand-400' : 'text-gray-400 dark:text-slate-500'}`}
                >
                  <ShoppingBasket className="w-6 h-6" />
                  <span className="text-[10px] font-medium">List</span>
                </button>

                <button 
                  onClick={() => setActiveTab(AppTab.HISTORY)} 
                  className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${activeTab === AppTab.HISTORY ? 'text-brand-600 dark:text-brand-400' : 'text-gray-400 dark:text-slate-500'}`}
                >
                  <History className="w-6 h-6" />
                  <span className="text-[10px] font-medium">History</span>
                </button>
              </div>
            </nav>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import { ReceiptData, Store } from '../types';
import { X, Share2, Download, ScanLine, CheckCircle, Sparkles, ArrowLeft, Coins, Zap } from 'lucide-react';

interface DigitalReceiptProps {
  data: ReceiptData;
  store: Store;
  onClose: () => void;
}

const DigitalReceipt: React.FC<DigitalReceiptProps> = ({ data, store, onClose }) => {
  const [scanning, setScanning] = useState(true);
  const [scanProgress, setScanProgress] = useState(0);
  const [cashbackFound, setCashbackFound] = useState<number | null>(null);
  const [showNotification, setShowNotification] = useState(false);

  useEffect(() => {
    // Simulate scanning process
    const duration = 2000; // 2 seconds scan
    const interval = 20;
    const steps = duration / interval;
    let currentStep = 0;

    const timer = setInterval(() => {
      currentStep++;
      setScanProgress((currentStep / steps) * 100);

      if (currentStep >= steps) {
        clearInterval(timer);
        setScanning(false);

        // Calculate cashback from promo items
        const cashbackTotal = data.items.reduce((acc, item) => acc + (item.isPromo && item.description !== 'MiCOINBANK ROUND-UP' ? (item.price * 0.1) : 0), 0); 

        if (cashbackTotal > 0) {
          setCashbackFound(cashbackTotal);
          setTimeout(() => setShowNotification(true), 500);
        }
      }
    }, interval);

    return () => clearInterval(timer);
  }, [data]);

  return (
    <div 
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200"
      onClick={onClose}
    >

      {/* Notification Overlay */}
      {showNotification && (
        <div className="absolute top-10 left-0 right-0 flex justify-center z-[60] animate-in slide-in-from-top-5 duration-500 pointer-events-none">
          <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl p-4 flex items-center space-x-4 max-w-xs border-l-4" style={{ borderLeftColor: store.color }}>
             <div className="bg-brand-500/10 p-2 rounded-full">
                <Sparkles className="w-6 h-6 text-brand-500 animate-pulse" />
             </div>
             <div>
                <h4 className="font-bold text-gray-900 dark:text-white text-sm">Auto-Cashback Found!</h4>
                <p className="text-xs text-gray-500 dark:text-slate-300">
                  R {cashbackFound?.toFixed(2)} automatically added to your MiCOIN wallet from {store.name}.
                </p>
             </div>
          </div>
        </div>
      )}

      <div 
        className="relative w-full max-w-md bg-white p-1 rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]"
        onClick={(e) => e.stopPropagation()} 
      >
        {/* Fixed Header with Close Button */}
        <div className="flex items-center justify-between p-4 bg-white border-b border-gray-100 z-50">
            <button 
                onClick={onClose}
                className="flex items-center space-x-2 text-gray-500 hover:text-gray-900 transition-colors py-2"
            >
                <ArrowLeft className="w-5 h-5" />
                <span className="text-sm font-bold uppercase tracking-wider">Back</span>
            </button>
            <div className="flex items-center space-x-2">
                 <div className="text-sm font-black tracking-tighter font-sans flex items-baseline">
                    <span className="text-gray-900">Cardit</span>
                    <span 
                        className="font-black px-0.5 rounded-sm ml-0.5" 
                        style={{ color: store.color, textShadow: `0 0 5px ${store.color}33` }}
                    >Oe'</span>
                </div>
                <div className="w-7 h-7 rounded-full bg-slate-100 flex items-center justify-center text-xs shadow-inner">
                    {store.logo}
                </div>
            </div>
            <button 
                onClick={onClose}
                className="p-2 bg-gray-100 rounded-full hover:bg-gray-200 transition-colors"
            >
                <X className="w-5 h-5 text-gray-600" />
            </button>
        </div>

        {/* Receipt Container (Scrollable) */}
        <div 
            className="overflow-y-auto relative flex-1 font-mono text-xs text-gray-800 leading-tight transition-colors duration-700 pb-10" 
            style={{ 
                fontFamily: '"Courier Prime", "Courier New", monospace',
                backgroundColor: '#ffffff',
                backgroundImage: `radial-gradient(circle at top right, ${store.color}15, transparent 60%), radial-gradient(circle at bottom left, ${store.color}10, transparent 60%)`
            }}
        >

            {/* Watermark */}
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-0 overflow-hidden">
                 <div className="opacity-[0.04] transform -rotate-12 scale-150 flex flex-col items-center" style={{ color: store.color }}>
                     <div className="text-8xl mb-4">{store.logo}</div>
                     <div className="text-6xl font-black uppercase whitespace-nowrap">{store.name}</div>
                 </div>
            </div>

            {/* Scanning Laser Effect */}
            {scanning && (
              <div 
                className="absolute left-0 right-0 h-1 bg-red-500/50 shadow-[0_0_15px_rgba(239,68,68,0.8)] z-20 pointer-events-none transition-all ease-linear"
                style={{ top: `${scanProgress}%` }}
              >
                 <div className="absolute right-0 -top-3 bg-red-600 text-white text-[9px] px-1 py-0.5 rounded font-sans font-bold opacity-80">
                    FINDING SAVINGS...
                 </div>
              </div>
            )}

            {/* Receipt Content */}
            <div className="p-6 pt-10 flex flex-col items-center text-center relative z-10">
                {/* Branding Header */}
                <div className="mb-2 flex flex-col items-center">
                   <div className="text-4xl mb-2">{store.logo}</div>
                   <div className="font-bold text-xl uppercase tracking-tighter">{store.name}</div>
                </div>

                <div className="mb-4 grayscale opacity-80 text-[10px]">
                    <div className="text-xs font-bold uppercase tracking-widest mb-1">{data.merchantName}</div>
                    {data.address.map((line, i) => <div key={i}>{line}</div>)}
                    <div className="mt-2">VAT NO: {data.vatNo}</div>
                    <div>TEL: {data.tel}</div>
                </div>

                <div className="w-full flex justify-between mb-2 border-b border-dashed border-gray-300 pb-2 text-[10px]">
                    <span>CASHIER: {data.cashier}</span>
                    <span>TAX INVOICE</span>
                </div>

                {/* Items List */}
                <div className="w-full space-y-3 mb-4 text-left">
                    {data.items.map((item, idx) => {
                        const isRoundUp = item.description.includes('MiCOINBANK');

                        return (
                            <div key={idx} className={`relative transition-all duration-500 p-1.5 ${isRoundUp ? 'border-2 border-dashed border-brand-500/50 bg-brand-50/20 -mx-1 rounded-lg' : ''}`}>
                                <div className="flex justify-between font-bold text-gray-700">
                                    <span className={`max-w-[80%] uppercase ${isRoundUp ? 'text-brand-700' : ''}`}>{item.description}</span>
                                    <div className="flex items-center">
                                        {!scanning && item.isPromo && !isRoundUp && (
                                            <div className="flex items-center mr-1 animate-bounce">
                                                <Coins className="w-3 h-3 text-accent-500" />
                                            </div>
                                        )}
                                        <span className={`flex-shrink-0 ${isRoundUp ? 'text-brand-600' : ''}`}>{item.total.toFixed(2)}</span>
                                    </div>
                                </div>
                                <div className="flex justify-between text-gray-500 text-[10px]">
                                    <span>{item.quantity} @ {item.price.toFixed(2)}</span>
                                    <span>{item.isPromo ? '*' : ' '}</span>
                                </div>

                                {isRoundUp && (
                                    <div className="flex items-center text-brand-600 font-bold text-[9px] mt-1 font-sans uppercase tracking-[0.1em]">
                                        <Zap className="w-3 h-3 mr-1" />
                                        <span>Saving Confirmed</span>
                                    </div>
                                )}

                                {!scanning && item.isPromo && !isRoundUp && (
                                    <div className="flex items-center text-accent-600 font-bold text-[9px] mt-1 animate-pulse font-sans uppercase tracking-tight">
                                        <Zap className="w-3 h-3 mr-1" />
                                        <span>Cashback Detected</span>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>

                {/* Totals */}
                <div className="w-full border-t border-dashed border-gray-400 pt-3 space-y-1 mb-4">
                    <div className="flex justify-between">
                        <span>SUBTOTAL</span>
                        <span>{(data.total - (data.items.find(i => i.description.includes('MiCOINBANK'))?.total || 0)).toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between text-brand-600 italic">
                        <span>MiCOINBANK ROUND-UP</span>
                        <span>+ {data.items.find(i => i.description.includes('MiCOINBANK'))?.total.toFixed(2) || '0.00'}</span>
                    </div>
                    <div className="flex justify-between text-lg font-bold mt-2 pt-2 border-t border-gray-100">
                        <span>FINAL TOTAL</span>
                        <span>R {data.total.toFixed(2)}</span>
                    </div>
                </div>

                {/* Payment Info */}
                <div className="w-full border-t border-dashed border-gray-400 pt-2 space-y-1 mb-6 text-left text-[10px]">
                    <div className="flex justify-between">
                        <span>{data.tender}</span>
                        <span>{data.total.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between font-bold">
                        <span>CHANGE AT TILL</span>
                        <span>{data.change.toFixed(2)}</span>
                    </div>
                    <div className="mt-4 text-[9px] text-gray-400 break-all text-center">
                        {data.barcode}
                    </div>
                </div>

                {/* Barcode Mock */}
                <div className="w-full h-12 bg-gray-900 mb-2 opacity-90 items-center justify-center flex text-white text-[8px] tracking-[0.4em]">
                    ||| || |||| || | || |||| || |
                </div>
                <div className="text-[10px] text-gray-500">{data.date}  {data.time}</div>

                {/* Footer */}
                <div className="mt-8 text-center max-w-[220px] text-[10px] text-gray-400 uppercase">
                    <p>THANK YOU FOR SHOPPING WITH US</p>
                    <p className="mt-1">RETAIN SLIP FOR RETURNS</p>
                </div>

                {/* Jagged Bottom Decoration */}
                <div className="absolute bottom-0 left-0 w-full h-2 bg-gray-100/20" style={{ clipPath: 'polygon(0% 100%, 5% 0%, 10% 100%, 15% 0%, 20% 100%, 25% 0%, 30% 100%, 35% 0%, 40% 100%, 45% 0%, 50% 100%, 55% 0%, 60% 100%, 65% 0%, 70% 100%, 75% 0%, 80% 100%, 85% 0%, 90% 100%, 95% 0%, 100% 100%)' }}></div>
            </div>
        </div>

        {/* Action Bar */}
        <div className="bg-slate-50 p-4 flex justify-between items-center border-t border-gray-200 shadow-[0_-4px_10px_rgba(0,0,0,0.05)]">
             <div className="flex space-x-6">
                 <button className="flex flex-col items-center text-gray-500 hover:text-brand-600 transition-colors">
                     <Share2 className="w-5 h-5 mb-1" />
                     <span className="text-[10px] font-bold uppercase">Share</span>
                 </button>
                 <button className="flex flex-col items-center text-gray-500 hover:text-brand-600 transition-colors">
                     <Download className="w-5 h-5 mb-1" />
                     <span className="text-[10px] font-bold uppercase">PDF</span>
                 </button>
             </div>
             {cashbackFound && !scanning && (
                 <div className="bg-brand-600 text-white px-4 py-2 rounded-xl text-xs font-black shadow-lg shadow-brand-500/30 flex items-center">
                     <CheckCircle className="w-4 h-4 mr-2" />
                     EARNED R{cashbackFound.toFixed(2)}
                 </div>
             )}
        </div>
      </div>
    </div>
  );
};

