const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.LOGIN);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [stores, setStores] = useState<Store[]>(INITIAL_STORES);
  const [transactions, setTransactions] = useState<Transaction[]>(INITIAL_TRANSACTIONS);
  const [selectedStore, setSelectedStore] = useState<Store | null>(null);
  const [user, setUser] = useState<User>(MOCK_USER);
  const [showBalance, setShowBalance] = useState(true);
  const [viewingReceipt, setViewingReceipt] = useState<Transaction | null>(null);

  const [shoppingList, setShoppingList] = useState<ShoppingListItem[]>([]);
  const [savedLists, setSavedLists] = useState<SavedList[]>([]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleStoreClick = (store: Store) => {
    setSelectedStore(store);
    setActiveTab(AppTab.STORE_VIEW);
  };

  const handleBackFromStore = () => {
    setSelectedStore(null);
    setActiveTab(AppTab.DASHBOARD);
  };

  const handleUpdateStore = (updatedStore: Store) => {
    setStores(stores.map(s => s.id === updatedStore.id ? updatedStore : s));
    setSelectedStore(updatedStore);
  };

  const handleUpdateSettings = (roundUpTarget: number) => {
    setUser({ ...user, roundUpTarget });
  };

  const handleToggleAutoSave = () => {
      setUser(prev => ({ ...prev, isAutoSaveEnabled: !prev.isAutoSaveEnabled }));
  };

  const handleUpdateBalance = (amount: number) => {
      setUser(prev => ({ ...prev, miCoinBalance: prev.miCoinBalance + amount }));
  };

  const handleAddTransaction = (tx: Transaction) => {
      setTransactions(prev => [tx, ...prev]);
  };

  const handleLinkPhysicalCard = (newId: string) => {
      let formattedId = newId;
      if (newId.length === 12) {
          formattedId = `${newId.slice(0, 4)} ${newId.slice(4, 8)} ${newId.slice(8, 12)}`;
      }
      setUser(prev => ({ ...prev, memberId: formattedId, isAutoSaveEnabled: false }));
      setActiveTab(AppTab.WALLET);
  };

  const handleAddItemToGrocery = (item: ShoppingListItem) => {
    setShoppingList(prev => {
      const existing = prev.find(i => i.id === item.id && i.storeId === item.storeId);
      if (existing) {
        return prev.map(i => (i.id === item.id && i.storeId === item.storeId) ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, item];
    });
  };

  const handleRemoveItemFromGrocery = (itemId: string, storeId: string) => {
    setShoppingList(prev => prev.filter(i => !(i.id === itemId && i.storeId === storeId)));
  };

  const handleUpdateQuantityGrocery = (itemId: string, storeId: string, delta: number) => {
    setShoppingList(prev => prev.map(i => (i.id === itemId && i.storeId === storeId) ? { ...i, quantity: Math.max(1, i.quantity + delta) } : i));
  };

  const handleSaveList = (name: string) => {
    const total = shoppingList.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const totalSavings = shoppingList.reduce((sum, item) => {
      const savingPerItem = item.oldPrice ? (item.oldPrice - item.price) : 0;
      const cashback = item.cashbackAmount || 0;
      return sum + ((savingPerItem + cashback) * item.quantity);
    }, 0);

    const newList: SavedList = {
      id: Date.now().toString(),
      name,
      date: new Date().toLocaleDateString(),
      items: [...shoppingList],
      total,
      totalSavings
    };
    setSavedLists(prev => [newList, ...prev]);
  };

  const handleLoadList = (list: SavedList) => {
    setShoppingList([...list.items]);
  };

  const handleDeleteSavedList = (listId: string) => {
    setSavedLists(prev => prev.filter(l => l.id !== listId));
  };

  const handleGoBack = () => {
    setActiveTab(AppTab.DASHBOARD);
    setSelectedStore(null);
  };

  const handleLogout = () => {
    setActiveTab(AppTab.LOGIN);
  };

  const renderContent = () => {
    switch (activeTab) {
      case AppTab.LOGIN:
        return <Login onLogin={() => setActiveTab(AppTab.DASHBOARD)} />;
      case AppTab.DASHBOARD:
        return (
          <Dashboard 
            user={user} 
            recentTransactions={transactions} 
            stores={stores}
            onStoreClick={handleStoreClick}
            showBalance={showBalance}
            onToggleBalance={() => setShowBalance(!showBalance)}
            onViewReceipt={(tx) => setViewingReceipt(tx)}
          />
        );
      case AppTab.STORE_VIEW:
        if (!selectedStore) return null;
        return (
          <StoreDetail 
            store={selectedStore} 
            transactions={transactions}
            onBack={handleBackFromStore}
            onUpdateStore={handleUpdateStore}
            onUpdateBalance={handleUpdateBalance}
            onAddTransaction={handleAddTransaction}
            onViewReceipt={(tx) => setViewingReceipt(tx)}
          />
        );
      case AppTab.WALLET:
        return (
          <WalletView 
            user={user} 
            transactions={transactions}
            onUpdateSettings={handleUpdateSettings}
            onToggleAutoSave={handleToggleAutoSave}
            onUpdateBalance={handleUpdateBalance}
            onAddTransaction={handleAddTransaction}
            onBack={handleGoBack}
            onOpenBuy={() => setActiveTab(AppTab.BUY)}
            onOpenLinkCard={() => setActiveTab(AppTab.LINK_CARD)}
          />
        );
      case AppTab.BUY:
        return (
          <BuyStore 
            user={user}
            onBack={() => setActiveTab(AppTab.WALLET)}
            onUpdateBalance={handleUpdateBalance}
            onAddTransaction={handleAddTransaction}
          />
        );
      case AppTab.LINK_CARD:
        return (
          <LinkPhysicalCard 
            onBack={() => setActiveTab(AppTab.WALLET)}
            onSuccess={handleLinkPhysicalCard}
          />
        );
      case AppTab.GROCERY_LIST:
        return (
          <GroceryAssistant 
            stores={stores}
            shoppingList={shoppingList}
            savedLists={savedLists}
            onAddItem={handleAddItemToGrocery}
            onRemoveItem={handleRemoveItemFromGrocery}
            onUpdateQuantity={handleUpdateQuantityGrocery}
            onSaveList={handleSaveList}
            onLoadList={handleLoadList}
            onDeleteList={handleDeleteSavedList}
          />
        );
      case AppTab.ASSISTANT:
        return <ReceiptAssistant onBack={handleGoBack} />;
      case AppTab.PROFILE:
        return <ProfileView user={user} onLogout={handleLogout} onBack={handleGoBack} />;
      case AppTab.HISTORY:
        return (
          <div className="p-5 pb-20">
            <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-4 px-1">Activity History</h2>
            <div className="space-y-3">
              {transactions.map((tx) => (
                <div 
                    key={tx.id} 
                    onClick={() => tx.receiptData && setViewingReceipt(tx)}
                    className={`bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 transition-colors cursor-pointer active:scale-95 ${tx.type === 'CASHOUT' ? 'border-l-4 border-l-slate-400' : ''}`}
                >
                  <div className="flex justify-between items-center mb-2">
                    <div className="flex items-center space-x-2">
                        {tx.type === 'CASHOUT' && <ArrowUpRight className="w-4 h-4 text-slate-400" />}
                        <span className="font-semibold text-gray-800 dark:text-white">{tx.store}</span>
                    </div>
                    <span className={`text-[10px] font-bold uppercase tracking-wider px-2 py-1 rounded-md ${
                        tx.type === 'CASHBACK' ? 'bg-accent-500/10 text-accent-500' : 
                        tx.type === 'CASHOUT' ? 'bg-slate-100 dark:bg-slate-700 text-gray-500 dark:text-slate-400' :
                        'bg-brand-50 dark:bg-brand-900/30 text-brand-600 dark:text-brand-400'
                    }`}>
                        {tx.type === 'CASHBACK' ? 'Cashback' : tx.type === 'CASHOUT' ? 'Withdrawal' : tx.category}
                    </span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <div className="text-gray-500 dark:text-slate-400 text-xs">
                      {tx.type === 'CASHBACK' ? (
                          <span>Promo Reward</span>
                      ) : tx.type === 'CASHOUT' ? (
                          <span>Payment / Withdrawal</span>
                      ) : (
                          <span>Paid: R {tx.amount.toFixed(2)}</span>
                      )}
                    </div>
                    <div className={`font-black ${tx.type === 'CASHOUT' ? 'text-gray-900 dark:text-white' : 'text-brand-600 dark:text-brand-400'}`}>
                      {tx.type === 'CASHOUT' ? '-' : tx.type === 'CASHBACK' ? '+' : ''} R {tx.savings.toFixed(2)} {tx.type === 'CASHOUT' ? 'Used' : 'Saved'}
                    </div>
                  </div>
                  <div className="mt-2 text-[10px] text-gray-400 dark:text-slate-500 flex justify-between">
                     <span>{tx.date}</span>
                     {tx.type === 'ROUND_UP' && <span>Rounded from: R {tx.amount.toFixed(2)}</span>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      default:
        return <Login onLogin={() => setActiveTab(AppTab.DASHBOARD)} />;
    }
  };

  return (
    <div className={isDarkMode ? 'dark' : ''}>
      <div className="min-h-screen bg-gray-50 dark:bg-slate-900 font-sans text-slate-900 dark:text-slate-100 flex justify-center transition-colors duration-300">
        <div className="w-full max-w-lg bg-gray-50 dark:bg-slate-900 min-h-screen relative flex flex-col transition-colors duration-300">

          {/* Global Receipt Modal */}
          {viewingReceipt && viewingReceipt.receiptData && (
            <DigitalReceipt 
                data={viewingReceipt.receiptData} 
                store={stores.find(s => s.id === viewingReceipt.storeId) || { name: viewingReceipt.store, color: '#22c55e', logo: '💳' } as any} 
                onClose={() => setViewingReceipt(null)} 
            />
          )}

          {/* Top Navbar */}
          {activeTab !== AppTab.STORE_VIEW && activeTab !== AppTab.LOGIN && (
            <header className="bg-white dark:bg-slate-800 px-5 py-4 flex justify-between items-center sticky top-0 z-20 shadow-sm border-b border-transparent dark:border-slate-700 transition-colors">
              <div className="flex items-center space-x-3">
                {activeTab !== AppTab.DASHBOARD && (
                  <button onClick={handleGoBack} className="p-2 -ml-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full transition-colors text-gray-600 dark:text-slate-300">
                    <ArrowLeft className="w-5 h-5" />
                  </button>
                )}
                <div onClick={() => setActiveTab(AppTab.DASHBOARD)} className="text-xl font-black tracking-tighter font-sans flex items-baseline cursor-pointer">
                    <span className="text-gray-900 dark:text-white">Cardit</span>
                    <span className="text-brand-500">Oe'</span>
                </div>
              </div>
              <div className="flex items-center space-x-4">
                <button onClick={toggleTheme} className="p-1 text-gray-600 dark:text-slate-300 hover:text-brand-600 dark:hover:text-brand-400 transition-colors">
                  {isDarkMode ? <Sun className="w-6 h-6" /> : <Moon className="w-6 h-6" />}
                </button>
                <button className="relative p-1">
                    <Bell className="w-6 h-6 text-gray-600 dark:text-slate-300" />
                    <span className="absolute top-0 right-0 w-2.5 h-2.5 bg-brand-500 rounded-full border-2 border-white dark:border-slate-800"></span>
                </button>
                <button onClick={() => setActiveTab(AppTab.PROFILE)} className={`p-1 rounded-full transition-colors ${activeTab === AppTab.PROFILE ? 'text-brand-600' : 'text-gray-600 dark:text-slate-300'}`}>
                    <Menu className="w-6 h-6" />
                </button>
              </div>
            </header>
          )}

          <main className="flex-1 overflow-y-auto">
            {renderContent()}
          </main>

          {activeTab !== AppTab.STORE_VIEW && activeTab !== AppTab.LOGIN && (
            <nav className="bg-white dark:bg-slate-800 border-t border-gray-200 dark:border-slate-700 fixed bottom-0 w-full max-w-lg pb-safe z-30 transition-colors">
              <div className="flex justify-around items-center h-16">
                <button onClick={() => setActiveTab(AppTab.DASHBOARD)} className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${activeTab === AppTab.DASHBOARD ? 'text-brand-600 dark:text-brand-400' : 'text-gray-400 dark:text-slate-500'}`}>
                  <Home className="w-6 h-6" />
                  <span className="text-[10px] font-medium">Home</span>
                </button>
                <button onClick={() => setActiveTab(AppTab.WALLET)} className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${activeTab === AppTab.WALLET || activeTab === AppTab.BUY || activeTab === AppTab.LINK_CARD ? 'text-brand-600 dark:text-brand-400' : 'text-gray-400 dark:text-slate-500'}`}>
                  <CreditCard className="w-6 h-6" />
                  <span className="text-[10px] font-medium">MiCOINBANK</span>
                </button>
                <div className="relative -top-6">
                    <button onClick={() => setActiveTab(AppTab.ASSISTANT)} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg transform transition-transform ${activeTab === AppTab.ASSISTANT ? 'bg-brand-700 scale-110' : 'bg-brand-600 hover:scale-105'} text-white border-4 border-gray-50 dark:border-slate-900`}>
                      <MessageSquare className="w-6 h-6" />
                    </button>
                </div>
                <button onClick={() => setActiveTab(AppTab.GROCERY_LIST)} className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${activeTab === AppTab.GROCERY_LIST ? 'text-brand-600 dark:text-brand-400' : 'text-gray-400 dark:text-slate-500'}`}>
                  <ShoppingBasket className="w-6 h-6" />
                  <span className="text-[10px] font-medium">List</span>
                </button>
                <button onClick={() => setActiveTab(AppTab.HISTORY)} className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${activeTab === AppTab.HISTORY ? 'text-brand-600 dark:text-brand-400' : 'text-gray-400 dark:text-slate-500'}`}>
                  <History className="w-6 h-6" />
                  <span className="text-[10px] font-medium">History</span>
                </button>
              </div>
            </nav>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { User, Transaction, Store } from '../types';
import { TrendingUp, PiggyBank, CreditCard, Plus, Eye, EyeOff, Receipt } from 'lucide-react';
import StoreCard from './StoreCard';

interface DashboardProps {
  user: User;
  recentTransactions: Transaction[];
  stores: Store[];
  onStoreClick: (store: Store) => void;
  showBalance: boolean;
  onToggleBalance: () => void;
  onViewReceipt: (tx: Transaction) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ user, recentTransactions, stores, onStoreClick, showBalance, onToggleBalance, onViewReceipt }) => {
  return (
    <div className="space-y-6 pb-20">
      {/* Header Stats */}
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-white dark:bg-slate-800 p-4 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 transition-colors">
          <div className="flex items-center space-x-2 text-brand-600 dark:text-brand-400 mb-2">
            <PiggyBank className="w-5 h-5" />
            <span className="text-sm font-medium">Total Saved</span>
          </div>
          <p className="text-2xl font-bold text-gray-900 dark:text-white">
             {showBalance ? `R ${user.totalSaved.toFixed(2)}` : 'R ••••'}
          </p>
          <p className="text-xs text-green-600 dark:text-green-400 flex items-center mt-1">
            <TrendingUp className="w-3 h-3 mr-1" /> +12% this month
          </p>
        </div>
        <div className="bg-white dark:bg-slate-800 p-4 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 transition-colors relative">
           <div className="flex items-center justify-between mb-2">
              <div className="flex items-center space-x-2 text-accent-500">
                <CreditCard className="w-5 h-5" />
                <span className="text-sm font-medium">Wallet</span>
              </div>
              <button 
                onClick={onToggleBalance} 
                className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
              >
                 {showBalance ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
              </button>
           </div>
          <p className="text-2xl font-bold text-gray-900 dark:text-white">
             {showBalance ? `R ${user.miCoinBalance.toFixed(2)}` : 'R ••••'}
          </p>
          <p className="text-xs text-gray-500 dark:text-slate-400 mt-1">Available to withdraw</p>
        </div>
      </div>

      {/* My Store Cards Section */}
      <div>
         <div className="flex justify-between items-center mb-3 px-1">
           <h3 className="text-gray-800 dark:text-white font-semibold text-lg">My Stores</h3>
           <button className="text-brand-600 dark:text-brand-400 text-xs font-medium flex items-center bg-brand-50 dark:bg-brand-900/30 px-2 py-1 rounded-lg">
             <Plus className="w-3 h-3 mr-1" /> Add Card
