                className={`bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 flex justify-between items-center transition-all ${tx.receiptData ? 'cursor-pointer active:scale-95 hover:border-brand-200' : ''}`}
            >
