          </p>
          <div className="w-full max-w-xs bg-slate-100 dark:bg-slate-800 h-2 rounded-full overflow-hidden mb-4">
              <div className="h-full bg-brand-500 transition-all duration-500" style={{ width: `${(appStep / 3) * 100}%` }}></div>
          </div>
          <span className="text-[10px] font-black uppercase text-brand-600 tracking-widest">Step {appStep} of 3</span>
      </div>
  );

  const renderRegistration = () => (
    <div className="flex flex-col items-center justify-center h-full p-6 text-center space-y-6 animate-in fade-in zoom-in duration-300">
      {isScanning ? (
          <div className="flex flex-col items-center justify-center space-y-4 py-10">
              <div className="relative w-48 h-48 border-2 border-brand-500 rounded-3xl overflow-hidden flex items-center justify-center bg-black">
                  <div className="absolute top-0 left-0 w-full h-1 bg-red-500 shadow-[0_0_15px_rgba(239,68,68,1)] animate-[scan_1.5s_ease-in-out_infinite]"></div>
                  <p className="text-white/70 text-xs">Align Card Here</p>
              </div>
              <p className="text-gray-600 dark:text-slate-300 animate-pulse">Scanning Loyalty Card...</p>
          </div>
      ) : (
          <>
            <div className="w-24 h-24 rounded-[2rem] bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-4xl shadow-inner mb-4">{store.logo}</div>
            <div>
                <h2 className="text-2xl font-black text-gray-900 dark:text-white mb-2 uppercase tracking-tight">Connect {store.name}</h2>
                <p className="text-gray-500 dark:text-slate-400 text-sm px-4">Link your existing card or register a new one to unlock automatic digital receipts and cashback.</p>
            </div>
            <div className="w-full space-y-3 px-4">
                <button onClick={handleRegister} disabled={isRegistering} className="w-full py-4 rounded-2xl text-white font-black text-sm uppercase tracking-widest shadow-lg hover:opacity-90 transition-opacity flex items-center justify-center" style={{ backgroundColor: store.color }}>
                    {isRegistering ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" />Connecting...</> : <>Link Existing Card</>}
                </button>
                <button onClick={handleScanCard} disabled={isRegistering} className="w-full py-4 rounded-2xl bg-white dark:bg-slate-800 text-gray-700 dark:text-white font-black text-sm uppercase tracking-widest border border-gray-200 dark:border-slate-700 shadow-sm hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors flex items-center justify-center">
                    <QrCode className="w-5 h-5 mr-2 opacity-70" />Scan Plastic Card
