            </div>
          </>
      )}
    </div>
  );

  const renderShop = () => (
    <div className="space-y-4">
      <div className="relative">
        <Search className="absolute left-3 top-3 w-4 h-4 text-gray-400" />
        <input type="text" placeholder={`Search ${store.name} Store...`} className="w-full bg-slate-100 dark:bg-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-brand-500 dark:text-white" />
      </div>
      <div className="grid grid-cols-2 gap-3">
        {store.inventory.map(item => (
          <div key={item.id} className="bg-white dark:bg-slate-800 p-3 rounded-xl border border-slate-100 dark:border-slate-700 shadow-sm relative group">
