import React from 'react';
import { User, Transaction, Store } from '../types';
import { TrendingUp, PiggyBank, CreditCard, Plus, Eye, EyeOff, Receipt, AlertTriangle, ChevronRight } from 'lucide-react';
import StoreCard from './StoreCard';

