                  <AlertTriangle className="w-5 h-5 text-white" />
                </div>
                <div>
                  <h4 className="text-sm font-black text-amber-900 dark:text-amber-100 uppercase tracking-tight">Savings at Risk!</h4>
                  <p className="text-[11px] text-amber-700 dark:text-amber-400 font-medium">You have points expiring in {storesWithExpiry.length} store{storesWithExpiry.length > 1 ? 's' : ''}.</p>
                </div>
              </div>
            </div>
            <div className="bg-white/50 dark:bg-black/20 border-t border-amber-100 dark:border-amber-900/50">
