          <p className="text-xs text-green-600 dark:text-green-400 flex items-center mt-1">
            <TrendingUp className="w-3 h-3 mr-1" /> +12% this month
          </p>
        </div>
        <div className="bg-white dark:bg-slate-800 p-4 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 transition-colors relative">
           <div className="flex items-center justify-between mb-2">
              <div className="flex items-center space-x-2 text-accent-500">
                <CreditCard className="w-5 h-5" />
                <span className="text-sm font-medium">Wallet</span>
              </div>
              <button 
                onClick={onToggleBalance} 
                className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
              >
                 {showBalance ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
              </button>
           </div>
          <p className="text-2xl font-bold text-gray-900 dark:text-white">
             {showBalance ? `R ${user.miCoinBalance.toFixed(2)}` : 'R ••••'}
          </p>
          <p className="text-xs text-gray-500 dark:text-slate-400 mt-1">Available to withdraw</p>
        </div>
      </div>

      {/* My Store Cards Section */}
      <div>
         <div className="flex justify-between items-center mb-3 px-1">
           <h3 className="text-gray-800 dark:text-white font-semibold text-lg">My Stores</h3>
           <button className="text-brand-600 dark:text-brand-400 text-xs font-medium flex items-center bg-brand-50 dark:bg-brand-900/30 px-2 py-1 rounded-lg">
             <Plus className="w-3 h-3 mr-1" /> Add Card
           </button>
         </div>
         <div className="grid grid-cols-2 gap-3">
           {stores.map((store) => (
             <StoreCard key={store.id} store={store} onClick={onStoreClick} />
           ))}
