            <div 
                key={tx.id} 
                onClick={() => tx.receiptData && onViewReceipt(tx)}
                className={`bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 flex justify-between items-center transition-all ${tx.receiptData ? 'cursor-pointer active:scale-95 hover:border-brand-200' : ''}`}
            >
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 rounded-full bg-slate-100 dark:bg-slate-700 flex items-center justify-center text-xl">
                  {tx.category === 'Groceries' ? '🛒' : tx.category === 'Coffee' ? '☕' : '🛍️'}
                </div>
                <div>
                  <div className="flex items-center">
                    <p className="font-semibold text-gray-800 dark:text-white text-sm">{tx.store}</p>
                    {tx.receiptData && <Receipt className="w-3 h-3 ml-1.5 text-slate-300" />}
                  </div>
                  <p className="text-[10px] text-gray-500 dark:text-slate-400">{tx.date}</p>
                </div>
              </div>
              <div className="text-right">
                <p className="font-black text-sm text-brand-600 dark:text-brand-400">+ R {tx.savings.toFixed(2)}</p>
                <span className="text-[9px] text-gray-400 dark:text-slate-500 uppercase font-bold tracking-tighter">Saved Change</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

