import React, { useState, useEffect } from 'react';
import { Store, Transaction } from '../types';
import { ArrowLeft, ShoppingBag, Receipt, Percent, Star, CheckCircle, Clock, Search, AlertTriangle, ChevronRight, Sparkles, Download, ScanLine, QrCode, Loader2, Coins, Zap, UserPlus, ShieldCheck, Gift, X } from 'lucide-react';
import DigitalReceipt from './DigitalReceipt';

interface StoreDetailProps {
  store: Store;
  initialTab?: 'SHOP' | 'RECEIPTS' | 'PROMOS' | 'LOYALTY';
  transactions: Transaction[];
  onBack: () => void;
  onUpdateStore: (updatedStore: Store) => void;
  onUpdateBalance?: (amount: number) => void;
  onAddTransaction?: (tx: Transaction) => void;
  onViewReceipt: (tx: Transaction) => void;
}

type Tab = 'SHOP' | 'RECEIPTS' | 'PROMOS' | 'LOYALTY';

const StoreDetail: React.FC<StoreDetailProps> = ({ store, initialTab, transactions, onBack, onUpdateStore, onUpdateBalance, onAddTransaction, onViewReceipt }) => {
  const [activeTab, setActiveTab] = useState<Tab>(initialTab || 'SHOP');
  const [isRegistering, setIsRegistering] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [isApplying, setIsApplying] = useState(false);
  const [appStep, setAppStep] = useState(0);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    if (initialTab) {
        setActiveTab(initialTab);
        return;
    }

    if (store.isLinked) {
        // Prioritize Loyalty/Expiring points alerts over slips or promos
        if (store.tabAlerts.loyalty > 0 || (store.pointsExpiring || 0) > 0) setActiveTab('LOYALTY');
        else if (store.tabAlerts.slips > 0) setActiveTab('RECEIPTS');
        else if (store.tabAlerts.promos > 0) setActiveTab('PROMOS');
        else setActiveTab('SHOP');
    }
  }, [store.id, store.isLinked, initialTab]);

  const storeTransactions = transactions.filter(t => t.store === store.name || t.storeId === store.id);

  const handleRegister = () => {
    setIsRegistering(true);
    setTimeout(() => {
      onUpdateStore({ ...store, isLinked: true });
      setIsRegistering(false);
    }, 1500);
  };

  const handleScanCard = () => {
      setIsScanning(true);
      setTimeout(() => {
          setIsScanning(false);
          handleRegister();
      }, 2000);
  };

