const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.LOGIN);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [stores, setStores] = useState<Store[]>(INITIAL_STORES);
  const [transactions, setTransactions] = useState<Transaction[]>(INITIAL_TRANSACTIONS);
  const [selectedStore, setSelectedStore] = useState<Store | null>(null);
  const [selectedStoreTab, setSelectedStoreTab] = useState<string | undefined>(undefined);
  const [user, setUser] = useState<User>(MOCK_USER);
  const [showBalance, setShowBalance] = useState(true);
  const [viewingReceipt, setViewingReceipt] = useState<Transaction | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);

  const [shoppingList, setShoppingList] = useState<ShoppingListItem[]>([]);
  const [savedLists, setSavedLists] = useState<SavedList[]>([]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleStoreClick = (store: Store, tab?: string) => {
    setSelectedStore(store);
    setSelectedStoreTab(tab);
    setActiveTab(AppTab.STORE_VIEW);
  };

  const handleGoBack = () => {
    setActiveTab(AppTab.DASHBOARD);
    setSelectedStore(null);
    setSelectedStoreTab(undefined);
    setShowNotifications(false);
  };

  const totalNotifications = stores.reduce((acc, s) => acc + s.notificationCount, 0);

  const renderNotifications = () => (
      <div className="flex flex-col h-full bg-slate-50 dark:bg-slate-900 animate-in slide-in-from-right-10 duration-300">
          <div className="p-5 border-b border-slate-100 dark:border-slate-800 flex items-center bg-white dark:bg-slate-900 sticky top-0 z-10">
              <button onClick={() => setShowNotifications(false)} className="p-2 -ml-2 mr-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full">
                  <ArrowLeft className="w-6 h-6 text-slate-900 dark:text-white" />
              </button>
              <h2 className="text-xl font-bold text-slate-900 dark:text-white">Notifications</h2>
          </div>
          <div className="flex-1 overflow-y-auto p-5 space-y-4 pb-24">
              {stores.filter(s => s.isLinked && s.notificationCount > 0).map(store => (
                  <div key={store.id} className="space-y-3">
                      <div className="flex items-center space-x-2 px-1">
                          <span className="text-xs">{store.logo}</span>
                          <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">{store.name} Alerts</span>
                      </div>

                      {/* Expiring Alert */}
                      {store.pointsExpiring && (
                          <div 
                            onClick={() => { handleStoreClick(store, 'LOYALTY'); setShowNotifications(false); }}
                            className="bg-amber-50 dark:bg-amber-900/20 p-4 rounded-2xl border border-amber-200 dark:border-amber-800 flex items-start space-x-3 cursor-pointer active:scale-95 transition-transform"
                          >
                              <div className="bg-amber-500 p-2 rounded-xl text-white">
                                  <AlertTriangle className="w-5 h-5" />
                              </div>
                              <div className="flex-1">
                                  <p className="text-sm font-bold text-amber-900 dark:text-amber-100">Savings Expiring!</p>
                                  <p className="text-[11px] text-amber-700 dark:text-amber-400">R {(store.pointsExpiring/100).toFixed(2)} in cashback will vanish soon. Use them today.</p>
                                  <div className="mt-2 text-[9px] font-black uppercase text-amber-600 flex items-center">
                                      Spend Points <ChevronRight className="w-3 h-3 ml-1" />
                                  </div>
                              </div>
                          </div>
                      )}

                      {/* Promo Alert */}
                      {store.tabAlerts.promos > 0 && (
                          <div 
                            onClick={() => { handleStoreClick(store, 'PROMOS'); setShowNotifications(false); }}
                            className="bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-100 dark:border-slate-700 flex items-start space-x-3 cursor-pointer active:scale-95 transition-transform shadow-sm"
                          >
                              <div className="bg-brand-500 p-2 rounded-xl text-white">
                                  <Zap className="w-5 h-5" />
                              </div>
                              <div className="flex-1">
                                  <p className="text-sm font-bold text-slate-900 dark:text-white">New Cashback Available</p>
                                  <p className="text-[11px] text-slate-500 dark:text-slate-400">Check out the latest SnapSave deals at {store.name}.</p>
                              </div>
                          </div>
                      )}
                  </div>
              ))}

              <div className="pt-10 flex flex-col items-center opacity-30 grayscale">
                  <Bell className="w-12 h-12 mb-2" />
                  <p className="text-[10px] font-black uppercase tracking-widest">No more alerts</p>
              </div>
          </div>
      </div>
  );

  const renderContent = () => {
    if (showNotifications) return renderNotifications();

    switch (activeTab) {
      case AppTab.LOGIN:
        return <Login onLogin={() => setActiveTab(AppTab.DASHBOARD)} />;
      case AppTab.DASHBOARD:
        return (
          <Dashboard 
            user={user} 
            recentTransactions={transactions} 
            stores={stores}
            onStoreClick={handleStoreClick}
            showBalance={showBalance}
            onToggleBalance={() => setShowBalance(!showBalance)}
            onViewReceipt={(tx) => setViewingReceipt(tx)}
          />
        );
      case AppTab.STORE_VIEW:
        if (!selectedStore) return null;
        return (
          <StoreDetail 
            store={selectedStore} 
            initialTab={selectedStoreTab as any}
            transactions={transactions}
            onBack={handleBackFromStore}
            onUpdateStore={(s) => setStores(stores.map(x => x.id === s.id ? s : x))}
            onViewReceipt={(tx) => setViewingReceipt(tx)}
          />
        );
      case AppTab.WALLET:
        return (
          <WalletView 
            user={user} 
            transactions={transactions}
            onUpdateSettings={(t) => setUser({...user, roundUpTarget: t})}
            onToggleAutoSave={() => setUser({...user, isAutoSaveEnabled: !user.isAutoSaveEnabled})}
            onUpdateBalance={(a) => setUser({...user, miCoinBalance: user.miCoinBalance + a})}
            onAddTransaction={(tx) => setTransactions([tx, ...transactions])}
            onBack={handleGoBack}
          />
        );
      case AppTab.HISTORY:
        return (
            <div className="p-5 pb-24 space-y-4">
                <h2 className="text-xl font-bold text-gray-900 dark:text-white px-1">Activity History</h2>
                {transactions.map(tx => (
                    <div key={tx.id} onClick={() => tx.receiptData && setViewingReceipt(tx)} className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 cursor-pointer">
                        <div className="flex justify-between items-center mb-1">
                            <span className="font-bold text-sm dark:text-white">{tx.store}</span>
                            <span className="text-brand-600 font-black">+ R{tx.savings.toFixed(2)}</span>
                        </div>
                        <p className="text-[10px] text-slate-400">{tx.date} • {tx.category}</p>
                    </div>
                ))}
            </div>
        );
      case AppTab.GROCERY_LIST:
          return <GroceryAssistant stores={stores} shoppingList={shoppingList} savedLists={savedLists} onAddItem={(i) => setShoppingList([...shoppingList, i])} onRemoveItem={(id, sid) => setShoppingList(shoppingList.filter(x => !(x.id === id && x.storeId === sid)))} onUpdateQuantity={(id, sid, d) => setShoppingList(shoppingList.map(x => (x.id === id && x.storeId === sid) ? {...x, quantity: Math.max(1, x.quantity + d)} : x))} onSaveList={(n) => setSavedLists([...savedLists, {id: Date.now().toString(), name: n, date: 'Today', items: [...shoppingList], total: 0, totalSavings: 0}])} onLoadList={(l) => setShoppingList(l.items)} onDeleteList={(id) => setSavedLists(savedLists.filter(x => x.id !== id))} />;
      case AppTab.ASSISTANT:
          return <ReceiptAssistant onBack={handleGoBack} />;
      case AppTab.PROFILE:
          return <ProfileView user={user} onLogout={() => setActiveTab(AppTab.LOGIN)} onBack={handleGoBack} />;
      default:
        return <Dashboard user={user} recentTransactions={transactions} stores={stores} onStoreClick={handleStoreClick} showBalance={showBalance} onToggleBalance={() => setShowBalance(!showBalance)} onViewReceipt={(tx) => setViewingReceipt(tx)} />;
    }
  };

  const handleBackFromStore = () => {
    setSelectedStore(null);
    setSelectedStoreTab(undefined);
    setActiveTab(AppTab.DASHBOARD);
  };

  return (
    <div className={isDarkMode ? 'dark' : ''}>
      <div className="min-h-screen bg-gray-50 dark:bg-slate-900 font-sans text-slate-900 dark:text-slate-100 flex justify-center transition-colors duration-300">
        <div className="w-full max-w-lg bg-gray-50 dark:bg-slate-900 min-h-screen relative flex flex-col transition-colors duration-300">

          {viewingReceipt && viewingReceipt.receiptData && (
            <DigitalReceipt 
                data={viewingReceipt.receiptData} 
                store={stores.find(s => s.id === viewingReceipt.storeId) || { name: viewingReceipt.store, color: '#22c55e', logo: '💳' } as any} 
                onClose={() => setViewingReceipt(null)} 
            />
          )}

          {activeTab !== AppTab.STORE_VIEW && activeTab !== AppTab.LOGIN && (
