import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
const MODEL_NAME = 'gemini-3-flash-preview';

export const sendMessageToAssistant = async (
  message: string, 
  imageBase64?: string
): Promise<string> => {
  try {
    const parts: any[] = [];
    if (imageBase64) {
      const cleanBase64 = imageBase64.split(',')[1] || imageBase64;
      parts.push({
        inlineData: {
          mimeType: 'image/jpeg',
          data: cleanBase64
        }
      });
    }
    parts.push({
      text: message || (imageBase64 ? "Analyze this receipt. List the items purchased, total amount, and categorize the spending." : "Hello")
    });

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: { parts: parts },
      config: {
        systemInstruction: `You are CarditOe's Smart Receipt Assistant. 
        Your goal is to help users manage their finances by analyzing receipts and answering questions about their spending habits.
        When analyzing a receipt, extract the Merchant Name, Total Amount (in Rands 'R'), and a list of purchased items.
        Also, calculate how much "round-up" savings they might have generated (rounding up to the nearest Rand).
        Keep responses concise, helpful, and friendly. Use formatting like bullet points for clarity.`,
      }
    });
    return response.text || "I couldn't generate a response. Please try again.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Sorry, I encountered an error processing your request.";
  }
};

export const findNearbyStoresWithProduct = async (
  storeBrand: string,
  productName: string,
  currentLocation: string
): Promise<{ text: string, links: { title: string, uri: string }[] }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-lite-latest',
      contents: `Find all nearby ${storeBrand} branches around ${currentLocation} and check if they likely stock ${productName}. Provide the specific addresses and links.`,
      config: {
        tools: [{ googleMaps: {} }],
      },
    });

    const text = response.text || "Searching for branches...";
    const links = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter((chunk: any) => chunk.maps)
      ?.map((chunk: any) => ({
        title: chunk.maps.title,
        uri: chunk.maps.uri
      })) || [];

    return { text, links };
  } catch (error) {
    console.error("Maps Search Error:", error);
    return { text: "I couldn't find any nearby branches right now.", links: [] };
  }
};

