  };

  const renderContent = () => {
    switch (activeTab) {
      case AppTab.LOGIN: return <Login onLogin={() => setActiveTab(AppTab.DASHBOARD)} />;
      case AppTab.DASHBOARD: return <Dashboard user={user} recentTransactions={transactions} stores={stores} onStoreClick={handleStoreClick} showBalance={showBalance} onToggleBalance={() => setShowBalance(!showBalance)} onViewReceipt={(tx) => setViewingReceipt(tx)} />;
      case AppTab.STORE_VIEW: return selectedStore ? <StoreDetail store={selectedStore} transactions={transactions} onBack={handleGoBack} onUpdateStore={(s) => setStores(stores.map(x => x.id === s.id ? s : x))} onViewReceipt={(tx) => setViewingReceipt(tx)} /> : null;
      case AppTab.WALLET: return <WalletView user={user} transactions={transactions} onUpdateSettings={(t) => setUser({...user, roundUpTarget: t})} onToggleAutoSave={() => setUser({...user, isAutoSaveEnabled: !user.isAutoSaveEnabled})} onUpdateBalance={(a) => setUser({...user, miCoinBalance: user.miCoinBalance + a})} onAddTransaction={(tx) => setTransactions([tx, ...transactions])} onBack={handleGoBack} />;
