import React, { useEffect, useState } from 'react';
import { ReceiptData, Store } from '../types';
import { X, Share2, Download, CheckCircle, Sparkles, ArrowLeft, Zap, ShieldCheck } from 'lucide-react';

interface DigitalReceiptProps {
  data: ReceiptData;
  store: Store;
  onClose: () => void;
}

const DigitalReceipt: React.FC<DigitalReceiptProps> = ({ data, store, onClose }) => {
  const [scanning, setScanning] = useState(true);
  const [scanProgress, setScanProgress] = useState(0);
  const [cashbackFound, setCashbackFound] = useState<number | null>(null);
  const [showNotification, setShowNotification] = useState(false);

  // Check if this receipt is a withdrawal
  const isWithdrawal = data.items.some(item => 
    item.description.toUpperCase().includes('WITHDRAWAL') || 
    item.description.toUpperCase().includes('PAYOUT')
  );

  useEffect(() => {
    const duration = 2000; 
    const interval = 20;
    const steps = duration / interval;
    let currentStep = 0;

    const timer = setInterval(() => {
      currentStep++;
      setScanProgress((currentStep / steps) * 100);

      if (currentStep >= steps) {
        clearInterval(timer);
        setScanning(false);

        if (!isWithdrawal) {
          const cashbackTotal = data.items.reduce((acc, item) => acc + (item.isPromo && !item.description.includes('MiCOINBANK') ? (item.price * 0.1) : 0), 0); 
          if (cashbackTotal > 0) {
            setCashbackFound(cashbackTotal);
            setTimeout(() => setShowNotification(true), 500);
          }
        }
      }
    }, interval);

    return () => clearInterval(timer);
  }, [data, isWithdrawal]);

  return (
    <div 
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200"
      onClick={onClose}
    >
      {showNotification && (
        <div className="absolute top-10 left-0 right-0 flex justify-center z-[60] animate-in slide-in-from-top-5 duration-500 pointer-events-none">
          <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl p-4 flex items-center space-x-4 max-w-xs border-l-4" style={{ borderLeftColor: store.color }}>
             <div className="bg-brand-500/10 p-2 rounded-full">
                <Sparkles className="w-6 h-6 text-brand-500 animate-pulse" />
             </div>
             <div>
                <h4 className="font-bold text-gray-900 dark:text-white text-sm">Auto-Cashback Found!</h4>
                <p className="text-xs text-gray-500 dark:text-slate-300">R {cashbackFound?.toFixed(2)} added to wallet.</p>
             </div>
          </div>
        </div>
      )}

      <div 
        className="relative w-full max-w-md bg-white p-1 rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]"
        onClick={(e) => e.stopPropagation()} 
      >
        <div className="flex items-center justify-between p-4 bg-white border-b border-gray-100 z-50">
            <button onClick={onClose} className="flex items-center space-x-2 text-gray-500 hover:text-gray-900 py-2">
                <ArrowLeft className="w-5 h-5" />
                <span className="text-xs font-black uppercase tracking-wider">Back</span>
            </button>
            <div className="flex items-center space-x-2">
                 <div className="text-sm font-black tracking-tighter font-sans flex items-baseline">
                    <span className="text-gray-900">Cardit</span>
                    <span className="font-black px-0.5 rounded-sm ml-0.5" style={{ color: store.color }}>Oe'</span>
                </div>
            </div>
            <button onClick={onClose} className="p-2 bg-gray-100 rounded-full hover:bg-gray-200"><X className="w-5 h-5 text-gray-600" /></button>
        </div>

        <div 
            className="overflow-y-auto relative flex-1 font-mono text-xs text-gray-800 leading-tight pb-10" 
            style={{ 
                fontFamily: '"Courier Prime", "Courier New", monospace',
                backgroundColor: '#ffffff',
                backgroundImage: isWithdrawal ? `linear-gradient(to bottom, #f8fafc, #ffffff)` : `radial-gradient(circle at top right, ${store.color}15, transparent 60%)`
            }}
        >
            {scanning && (
              <div 
                className="absolute left-0 right-0 h-1 bg-red-500/50 shadow-[0_0_15px_rgba(239,68,68,0.8)] z-20 pointer-events-none transition-all ease-linear"
                style={{ top: `${scanProgress}%` }}
              />
            )}

            <div className="p-6 pt-10 flex flex-col items-center text-center relative z-10">
                <div className="mb-2 flex flex-col items-center">
                   <div className="text-4xl mb-2">{isWithdrawal ? <div className="text-3xl bg-slate-100 p-3 rounded-full">{store.logo}</div> : store.logo}</div>
                   <div className="font-bold text-xl uppercase tracking-tighter" style={{ color: isWithdrawal ? store.color : 'inherit' }}>
                       {isWithdrawal ? 'CASH DISBURSEMENT' : store.name}
                   </div>
                   {isWithdrawal && <p className="text-[10px] font-black text-slate-500 tracking-[0.3em] mt-1 uppercase">Store Voucher Copy</p>}
                </div>

                <div className="mb-4 grayscale opacity-80 text-[10px] mt-4">
                    <div className="text-xs font-bold uppercase tracking-widest mb-1 font-sans">{data.merchantName}</div>
                    {data.address.map((line, i) => <div key={i}>{line}</div>)}
                    <div className="mt-2">TEL: {data.tel}</div>
                    <div>VAT NO: {data.vatNo}</div>
                </div>

                <div className="w-full flex justify-between mb-4 border-b border-dashed border-gray-300 pb-2 text-[10px]">
                    <span>CASHIER: {data.cashier}</span>
                    <span>{isWithdrawal ? 'VOUCHER NO' : 'TAX INVOICE'}</span>
                </div>

                <div className="w-full space-y-4 mb-4 text-left">
                    {data.items.map((item, idx) => (
                        <div key={idx} className={`relative p-3 rounded-xl ${isWithdrawal ? 'bg-slate-50 border border-slate-200' : item.description.includes('MiCOINBANK') ? 'border-2 border-dashed border-brand-500/50 bg-brand-50/40' : ''}`}>
                            <div className="flex justify-between font-bold text-gray-700">
                                <span className="uppercase text-[10px]">{item.description}</span>
                                <span className="flex-shrink-0">R {item.total.toFixed(2)}</span>
                            </div>
                            <div className="flex justify-between text-gray-500 text-[9px]">
                                <span>{item.quantity} {isWithdrawal ? 'TRANSACTION' : 'UNIT'}</span>
                            </div>
                        </div>
                    ))}
                </div>

                <div className="w-full border-t border-dashed border-gray-400 pt-3 space-y-1 mb-4">
                    <div className="flex justify-between text-lg font-black mt-2 pt-2 border-t border-gray-100">
                        <span>{isWithdrawal ? 'DISBURSED TOTAL' : 'TOTAL'}</span>
                        <span style={isWithdrawal ? { color: store.color } : {}}>R {data.total.toFixed(2)}</span>
                    </div>
                </div>

                <div className="w-full border-t border-dashed border-gray-400 pt-2 text-left text-[10px]">
                    <div className="flex justify-between mb-1">
                        <span>SOURCE ACCOUNT</span>
                        <span>{data.tender}</span>
                    </div>
                    {isWithdrawal && (
                        <div className="bg-slate-900 text-white p-2 mt-4 rounded-lg text-center font-sans">
                            <p className="text-[9px] font-black uppercase tracking-widest mb-1">Security Auth Code</p>
                            <p className="text-xl font-black tracking-[0.5em]">{data.barcode.slice(-6)}</p>
                        </div>
                    )}
                </div>

                <div className="w-full h-10 bg-gray-900 my-6 items-center justify-center flex text-white text-[8px] tracking-[0.4em] overflow-hidden">
                    ||| || |||| || | || |||| || | ||| || |||| || | || |||| || |
                </div>
                <div className="text-[10px] text-gray-500 uppercase">{data.date} • {data.time}</div>
                <p className="text-[8px] mt-4 opacity-50 uppercase tracking-widest leading-relaxed">Please keep this digital slip as proof of payout.<br/>Verified by CarditOe' Merchant Network.</p>
            </div>
        </div>

        <div className="bg-slate-50 p-4 flex justify-between items-center border-t border-gray-200">
             <div className="flex space-x-6 text-gray-400">
                 <button className="flex flex-col items-center">
                     <Share2 className="w-5 h-5 mb-1" />
                     <span className="text-[9px] font-black uppercase">Share</span>
                 </button>
                 <button className="flex flex-col items-center">
                     <Download className="w-5 h-5 mb-1" />
                     <span className="text-[9px] font-black uppercase">Save</span>
                 </button>
             </div>
             {!scanning && (
                 <div className="bg-brand-600 text-white px-4 py-2 rounded-xl text-[10px] font-black shadow-lg flex items-center uppercase tracking-widest">
                     <ShieldCheck className="w-4 h-4 mr-2" />
                     {isWithdrawal ? 'Voucher Verified' : 'Receipt Verified'}
                 </div>
             )}
        </div>
      </div>
    </div>
  );
};

