const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.LOGIN);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [stores, setStores] = useState<Store[]>(INITIAL_STORES);
  const [transactions, setTransactions] = useState<Transaction[]>(INITIAL_TRANSACTIONS);
  const [selectedStore, setSelectedStore] = useState<Store | null>(null);
  const [selectedStoreTab, setSelectedStoreTab] = useState<string | undefined>(undefined);
  const [user, setUser] = useState<User>(MOCK_USER);
  const [showBalance, setShowBalance] = useState(true);
  const [viewingReceipt, setViewingReceipt] = useState<Transaction | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const [shoppingList, setShoppingList] = useState<ShoppingListItem[]>([]);
  const [savedLists, setSavedLists] = useState<SavedList[]>([]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleStoreClick = (store: Store, tab?: string) => {
    setSelectedStore(store);
    setSelectedStoreTab(tab);
    setActiveTab(AppTab.STORE_VIEW);
  };

  const handleGoBack = () => {
    setActiveTab(AppTab.DASHBOARD);
    setSelectedStore(null);
    setSelectedStoreTab(undefined);
    setShowNotifications(false);
  };

  const totalNotifications = stores.reduce((acc, s) => acc + s.notificationCount, 0);

  const renderNotifications = () => (
      <div className="flex flex-col h-full bg-slate-50 dark:bg-slate-900 animate-in slide-in-from-right-10 duration-300">
          <div className="p-5 border-b border-slate-100 dark:border-slate-800 flex items-center bg-white dark:bg-slate-900 sticky top-0 z-10">
              <button onClick={() => setShowNotifications(false)} className="p-2 -ml-2 mr-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full">
                  <ArrowLeft className="w-6 h-6 text-slate-900 dark:text-white" />
              </button>
              <h2 className="text-xl font-bold text-slate-900 dark:text-white">Notifications</h2>
          </div>
          <div className="flex-1 overflow-y-auto p-5 space-y-4 pb-24">
              {stores.filter(s => s.isLinked && s.notificationCount > 0).map(store => (
                  <div key={store.id} className="space-y-3">
                      <div className="flex items-center space-x-2 px-1">
                          <span className="text-xs">{store.logo}</span>
                          <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">{store.name} Alerts</span>
                      </div>
                      {store.pointsExpiring && (
                          <div onClick={() => { handleStoreClick(store, 'LOYALTY'); setShowNotifications(false); }} className="bg-amber-50 dark:bg-amber-900/20 p-4 rounded-2xl border border-amber-200 dark:border-amber-800 flex items-start space-x-3 cursor-pointer active:scale-95 transition-transform">
                              <div className="bg-amber-500 p-2 rounded-xl text-white"><AlertTriangle className="w-5 h-5" /></div>
                              <div className="flex-1">
                                  <p className="text-sm font-bold text-amber-900 dark:text-amber-100">Savings Expiring!</p>
                                  <p className="text-[11px] text-amber-700 dark:text-amber-400">R {(store.pointsExpiring/100).toFixed(2)} in cashback will vanish soon.</p>
                              </div>
                          </div>
                      )}
                      {store.tabAlerts.promos > 0 && (
                          <div onClick={() => { handleStoreClick(store, 'PROMOS'); setShowNotifications(false); }} className="bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-100 dark:border-slate-700 flex items-start space-x-3 cursor-pointer active:scale-95 transition-transform shadow-sm">
                              <div className="bg-brand-500 p-2 rounded-xl text-white"><Zap className="w-5 h-5" /></div>
                              <div className="flex-1">
                                  <p className="text-sm font-bold text-slate-900 dark:text-white">New Cashback Available</p>
                                  <p className="text-[11px] text-slate-500 dark:text-slate-400">Check out the latest deals at {store.name}.</p>
                              </div>
                          </div>
                      )}
                  </div>
              ))}
          </div>
      </div>
  );

  const renderContent = () => {
    if (showNotifications) return renderNotifications();
    switch (activeTab) {
      case AppTab.LOGIN: return <Login onLogin={() => setActiveTab(AppTab.DASHBOARD)} />;
      case AppTab.DASHBOARD: return <Dashboard user={user} recent营Transactions={transactions} stores={stores} onStoreClick={handleStoreClick} showBalance={showBalance} onToggleBalance={() => setShowBalance(!showBalance)} onViewReceipt={(tx) => setViewingReceipt(tx)} />;
      case AppTab.STORE_VIEW: return selectedStore ? <StoreDetail store={selectedStore} initialTab={selectedStoreTab as any} transactions={transactions} onBack={handleBackFromStore} onUpdateStore={(s) => setStores(stores.map(x => x.id === s.id ? s : x))} onViewReceipt={(tx) => setViewingReceipt(tx)} /> : null;
      // Fix: Pass required onViewReceipt prop to WalletView
      case AppTab.WALLET: return <WalletView user={user} transactions={transactions} onUpdateSettings={(t) => setUser({...user, roundUpTarget: t})} onToggleAutoSave={() => setUser({...user, isAutoSaveEnabled: !user.isAutoSaveEnabled})} onUpdateBalance={(a) => setUser({...user, miCoinBalance: user.miCoinBalance + a})} onAddTransaction={(tx) => setTransactions([tx, ...transactions])} onBack={handleGoBack} onViewReceipt={(tx) => setViewingReceipt(tx)} />;
      case AppTab.HISTORY: return <div className="p-5 pb-24"><h2 className="text-xl font-bold mb-4">Activity History</h2>{transactions.map(tx => <div key={tx.id} className="p-4 bg-white mb-2 rounded-xl border">{tx.store} - R{tx.savings.toFixed(2)}</div>)}</div>;
      case AppTab.GROCERY_LIST: return <GroceryAssistant stores={stores} shoppingList={shoppingList} savedLists={savedLists} onAddItem={(i) => setShoppingList([...shoppingList, i])} onRemoveItem={(id, sid) => setShoppingList(shoppingList.filter(x => !(x.id === id && x.storeId === sid)))} onUpdateQuantity={(id, sid, d) => setShoppingList(shoppingList.map(x => (x.id === id && x.storeId === sid) ? {...x, quantity: Math.max(1, x.quantity + d)} : x))} onSaveList={(n) => setSavedLists([...savedLists, {id: Date.now().toString(), name: n, date: 'Today', items: [...shoppingList], total: 0, totalSavings: 0}])} onLoadList={(l) => setShoppingList(l.items)} onDeleteList={(id) => setSavedLists(savedLists.filter(x => x.id !== id))} />;
      case AppTab.ASSISTANT: return <ReceiptAssistant onBack={handleGoBack} />;
      case AppTab.PROFILE: return <ProfileView user={user} onLogout={() => setActiveTab(AppTab.LOGIN)} onBack={handleGoBack} />;
      default: return <Dashboard user={user} recentTransactions={transactions} stores={stores} onStoreClick={handleStoreClick} showBalance={showBalance} onToggleBalance={() => setShowBalance(!showBalance)} onViewReceipt={(tx) => setViewingReceipt(tx)} />;
    }
  };

  const handleBackFromStore = () => {
    setSelectedStore(null);
    setSelectedStoreTab(undefined);
    setActiveTab(AppTab.DASHBOARD);
  };

  return (
    <div className={isDarkMode ? 'dark' : ''}>
      <div className="min-h-screen bg-gray-50 dark:bg-slate-900 font-sans text-slate-900 dark:text-slate-100 flex justify-center">
        <div className="w-full max-w-lg bg-gray-50 dark:bg-slate-900 min-h-screen relative flex flex-col">
          {viewingReceipt && viewingReceipt.receiptData && <DigitalReceipt data={viewingReceipt.receiptData} store={stores.find(s => s.id === viewingReceipt.storeId) || { name: viewingReceipt.store, color: '#22c55e', logo: '💳' } as any} onClose={() => setViewingReceipt(null)} />}
          {activeTab !== AppTab.STORE_VIEW && activeTab !== AppTab.LOGIN && (
            <header className="bg-white dark:bg-slate-800 px-5 py-4 flex justify-between items-center sticky top-0 z-20 shadow-sm border-b dark:border-slate-700">
              <div className="flex items-center space-x-3">
                {(activeTab !== AppTab.DASHBOARD || showNotifications) && <button onClick={handleGoBack} className="p-2 -ml-2 text-gray-600 dark:text-slate-300"><ArrowLeft className="w-5 h-5" /></button>}
                <div onClick={() => setActiveTab(AppTab.DASHBOARD)} className="text-xl font-black tracking-tighter cursor-pointer"><span>Cardit</span><span className="text-brand-500">Oe'</span></div>
              </div>
              <div className="flex items-center space-x-4">
                <button onClick={toggleTheme}>{isDarkMode ? <Sun className="w-6 h-6 text-slate-300" /> : <Moon className="w-6 h-6 text-gray-600" />}</button>
                <button onClick={() => setShowNotifications(true)} className="relative">
                    <Bell className="w-6 h-6 text-gray-600 dark:text-slate-300" />
                    {totalNotifications > 0 && <span className="absolute top-0 right-0 w-4 h-4 bg-brand-500 text-white text-[8px] font-black rounded-full border-2 border-white dark:border-slate-800 flex items-center justify-center animate-bounce">{totalNotifications}</span>}
                </button>
                <button onClick={() => setActiveTab(AppTab.PROFILE)} className="text-gray-600 dark:text-slate-300"><Menu className="w-6 h-6" /></button>
              </div>
            </header>
          )}
          <main className="flex-1 overflow-y-auto">{renderContent()}</main>
          {activeTab !== AppTab.STORE_VIEW && activeTab !== AppTab.LOGIN && (
            <nav className="bg-white dark:bg-slate-800 border-t dark:border-slate-700 fixed bottom-0 w-full max-w-lg h-16 z-30 flex justify-around items-center">
                <button onClick={() => { setActiveTab(AppTab.DASHBOARD); setShowNotifications(false); }} className={`flex-1 flex flex-col items-center ${activeTab === AppTab.DASHBOARD && !showNotifications ? 'text-brand-600' : 'text-gray-400'}`}><Home className="w-6 h-6" /><span className="text-[10px]">Home</span></button>
                <button onClick={() => setActiveTab(AppTab.WALLET)} className={`flex-1 flex flex-col items-center ${activeTab === AppTab.WALLET ? 'text-brand-600' : 'text-gray-400'}`}><CreditCard className="w-6 h-6" /><span className="text-[10px]">Wallet</span></button>
                <div className="relative -top-6"><button onClick={() => setActiveTab(AppTab.ASSISTANT)} className="w-14 h-14 rounded-full bg-brand-600 text-white flex items-center justify-center shadow-lg border-4 border-gray-50 dark:border-slate-900"><MessageSquare className="w-6 h-6" /></button></div>
                <button onClick={() => setActiveTab(AppTab.GROCERY_LIST)} className={`flex-1 flex flex-col items-center ${activeTab === AppTab.GROCERY_LIST ? 'text-brand-600' : 'text-gray-400'}`}><ShoppingBasket className="w-6 h-6" /><span className="text-[10px]">List</span></button>
                <button onClick={() => setActiveTab(AppTab.HISTORY)} className={`flex-1 flex flex-col items-center ${activeTab === AppTab.HISTORY ? 'text-brand-600' : 'text-gray-400'}`}><History className="w-6 h-6" /><span className="text-[10px]">History</span></button>
            </nav>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;

export interface Transaction {
  id: string;
  storeId?: string; // Link to a specific store
  store: string;
  amount: number;
  roundedAmount?: number; // Optional, only for purchases
  savings: number; // The difference or cashback amount
  date: string;
  category: string;
  items?: string[]; // Simple list for dashboard
  receiptData?: ReceiptData; // Full detailed receipt
  type: 'PURCHASE' | 'ROUND_UP' | 'CASHBACK' | 'CASHOUT';
}

export interface ReceiptItem {
  description: string;
  quantity: number;
  price: number;
  total: number;
  isPromo?: boolean; // Triggers cashback
  promoDescription?: string;
}

export interface ReceiptData {
  merchantName: string;
  address: string[];
  vatNo: string;
  tel: string;
  cashier: string;
  items: ReceiptItem[];
  subtotal: number;
  vat: number;
  total: number;
  tender: string;
  change: number;
  barcode: string;
  date: string;
  time: string;
}

export interface User {
  name: string;
  memberId: string; // Dynamic ID for the digital/physical card
  miCoinBalance: number;
  totalSaved: number;
  roundUpTarget: number; // 1 to 20 (Round up to nearest X)
  isAutoSaveEnabled: boolean; // Toggle for MiCOINBANK feature
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  isThinking?: boolean;
  image?: string; // Base64 string for display
}

export interface Product {
  id: string;
  name: string;
  price: number;
  oldPrice?: number;
  inStock: boolean;
  image?: string;
  category: string;
  cashbackAmount?: number; // New: For SnapSave feature
}

export interface ShoppingListItem extends Product {
  storeId: string;
  storeName: string;
  storeColor: string;
  quantity: number;
}

export interface SavedList {
  id: string;
  name: string;
  date: string;
  items: ShoppingListItem[];
  total: number;
  totalSavings: number;
}

export interface StoreBranch {
  id: string;
  name: string;
  province: string;
  city: string;
  address: string;
  inventoryIds: string[];
}

export interface Store {
  id: string;
  name: string;
  color: string; // Tailwind bg class or hex
  logo: string; // Emoji or URL
  isLinked: boolean;
  loyaltyPoints: number;
  pointsExpiring?: number;
  notificationCount: number; // Total notifications
  tabAlerts: {
    shop: number;
    slips: number;
    promos: number; // Cashback/Deals
    loyalty: number;
  };
  promos: Product[];
  inventory: Product[];
  branches?: StoreBranch[];
}

export enum AppTab {
  LOGIN = 'LOGIN',
  DASHBOARD = 'DASHBOARD',
  WALLET = 'WALLET',
  ASSISTANT = 'ASSISTANT',
  HISTORY = 'HISTORY',
  STORE_VIEW = 'STORE_VIEW',
  GROCERY_LIST = 'GROCERY_LIST',
  BUY = 'BUY',
  LINK_CARD = 'LINK_CARD',
  PROFILE = 'PROFILE'
}

import React, { useState, useEffect, useMemo } from 'react';
import { User, Transaction, ReceiptData } from '../types';
import WalletCard from './WalletCard';
import { Settings, Banknote, Coins, CheckCircle, X, ShoppingBag, QrCode, Timer, ArrowLeft, Target, History, ChevronRight, ShieldCheck, Zap, Loader2 } from 'lucide-react';

interface WalletViewProps {
  user: User;
  transactions: Transaction[];
  onUpdateSettings: (target: number) => void;
  onUpdateBalance: (amount: number) => void;
  onAddTransaction: (tx: Transaction) => void;
  onToggleAutoSave: () => void;
  onBack?: () => void;
  onOpenBuy?: () => void;
  onOpenLinkCard?: () => void;
  onViewReceipt: (tx: Transaction) => void;
}

type WithdrawType = 'STORE' | null;
type DateFilter = 'ALL' | '7D' | '30D' | 'THIS_MONTH';

const WalletView: React.FC<WalletViewProps> = ({ user, transactions, onUpdateSettings, onUpdateBalance, onAddTransaction, onToggleAutoSave, onBack, onOpenBuy, onOpenLinkCard, onViewReceipt }) => {
  const [withdrawType, setWithdrawType] = useState<WithdrawType>(null);
  const [amount, setAmount] = useState<string>('');
  const [processing, setProcessing] = useState(false);
  const [generatedToken, setGeneratedToken] = useState<string | null>(null);
  const [tokenExpiry, setTokenExpiry] = useState<number | null>(null);
  const [timeLeft, setTimeLeft] = useState<string>('30:00');
  const [isRotating, setIsRotating] = useState(false);

  const [isDetailedActivityOpen, setIsDetailedActivityOpen] = useState(false);
  const [activeDateFilter, setActiveDateFilter] = useState<DateFilter>('ALL');

  const MIN_WITHDRAWAL = 20;
  const ROTATION_INTERVAL_MS = 30 * 60 * 1000;

  const walletActivity = useMemo(() => {
    return transactions.filter(tx => 
        tx.type === 'CASHOUT' || tx.type === 'ROUND_UP' || tx.type === 'CASHBACK'
    );
  }, [transactions]);

  useEffect(() => {
    if (!generatedToken || !tokenExpiry) return;
    const interval = setInterval(() => {
      const now = Date.now();
      const diff = tokenExpiry - now;
      if (diff <= 0) {
        const newToken = Math.floor(10000 + Math.random() * 90000).toString();
        setIsRotating(true);
        setGeneratedToken(newToken);
        setTokenExpiry(Date.now() + ROTATION_INTERVAL_MS);
        setTimeout(() => setIsRotating(false), 1000);
      } else {
        const mins = Math.floor(diff / 60000);
        const secs = Math.floor((diff % 60000) / 1000);
        setTimeLeft(`${mins}:${secs.toString().padStart(2, '0')}`);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [generatedToken, tokenExpiry]);

  const activeThreshold = user.roundUpTarget || 1; 

  const handleWithdraw = () => {
      if (!amount) return;
      const withdrawAmount = parseFloat(amount);
      if (withdrawAmount < MIN_WITHDRAWAL || withdrawAmount > user.miCoinBalance) return;

      setProcessing(true);
      const token = Math.floor(10000 + Math.random() * 90000).toString();

      setTimeout(() => {
          const now = new Date();
          const timeStr = now.toLocaleTimeString('en-ZA', { hour: '2-digit', minute: '2-digit' });
          const dateStr = now.toLocaleDateString('en-ZA', { day: '2-digit', month: 'short' });

          // Generate a digital receipt that looks like a store payout slip
          const withdrawalReceipt: ReceiptData = {
            merchantName: "SHOPRITE MIDDELBURG MALL",
            address: ["Corner Fontein & Dr Beyers Naude", "Middelburg Mall, 1050"],
            vatNo: "4000123456",
            tel: "013 243 1122",
            cashier: "TILL-04-PAYOUT",
            date: now.toLocaleDateString(),
            time: timeStr,
            barcode: "99" + Math.random().toString().slice(2, 12),
            tender: "CarditOe WALLET",
            change: 0.00,
            items: [
                { description: "CASH WITHDRAWAL / Payout", quantity: 1, price: withdrawAmount, total: withdrawAmount }
            ],
            subtotal: withdrawAmount,
            vat: 0.00,
            total: withdrawAmount
          };

          const cashoutTx: Transaction = {
              id: Date.now().toString(),
              storeId: 'shoprite',
              store: 'Shoprite Payout',
              amount: 0,
              savings: withdrawAmount,
              date: `${dateStr}, ${timeStr}`,
              category: 'Withdrawal',
              type: 'CASHOUT',
              receiptData: withdrawalReceipt
          };

          onAddTransaction(cashoutTx);
          onUpdateBalance(-withdrawAmount);
          setProcessing(false);
          setGeneratedToken(token);
          setTokenExpiry(Date.now() + ROTATION_INTERVAL_MS);
      }, 2000);
  };

  const handleCloseToken = () => {
      setGeneratedToken(null);
      setTokenExpiry(null);
      setWithdrawType(null);
      setAmount('');
  };

  const thresholdOptions = [1, 2, 5, 10];

  if (isDetailedActivityOpen) {
      return (
          <div className="min-h-full flex flex-col bg-white dark:bg-slate-900 animate-in slide-in-from-right-10 duration-300">
              <div className="bg-white dark:bg-slate-900 p-5 sticky top-0 z-50 border-b border-slate-100 dark:border-slate-800">
                  <div className="flex items-center justify-between mb-6">
                      <div className="flex items-center space-x-3">
                        <button onClick={() => setIsDetailedActivityOpen(false)} className="p-3 -ml-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
                            <ArrowLeft className="w-6 h-6 text-gray-900 dark:text-white" />
                        </button>
                        <h2 className="text-xl font-bold text-gray-900 dark:text-white">Wallet History</h2>
                      </div>
                      <div className="bg-brand-50 dark:bg-brand-900/30 px-3 py-1 rounded-full text-[10px] font-black text-brand-600 dark:text-brand-400 uppercase tracking-widest">
                          {walletActivity.length} Events
                      </div>
                  </div>
                  <div className="flex space-x-2 overflow-x-auto scrollbar-hide pb-2">
                      {['ALL', '7D', '30D', 'THIS_MONTH'].map((id) => (
                          <button key={id} onClick={() => setActiveDateFilter(id as DateFilter)} className={`whitespace-nowrap px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeDateFilter === id ? 'bg-brand-600 text-white shadow-lg' : 'bg-slate-100 dark:bg-slate-800 text-slate-500'}`}>
                            {id === 'ALL' ? 'All Time' : id}
                          </button>
                      ))}
                  </div>
              </div>

              <div className="flex-1 overflow-y-auto p-5 pb-24">
                  <div className="space-y-4">
                      {walletActivity.map((tx) => (
                          <div 
                            key={tx.id} 
                            onClick={() => tx.receiptData && onViewReceipt(tx)}
                            className="bg-white dark:bg-slate-800 p-5 rounded-[2rem] border border-slate-100 dark:border-slate-700 flex items-center justify-between shadow-sm transition-transform active:scale-95 cursor-pointer hover:border-brand-300"
                          >
                              <div className="flex items-center space-x-4">
                                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${tx.type === 'CASHOUT' ? 'bg-slate-100 text-slate-500' : 'bg-brand-50 text-brand-600'}`}>
                                      {tx.type === 'CASHOUT' ? <Banknote className="w-6 h-6" /> : <Coins className="w-6 h-6" />}
                                  </div>
                                  <div className="text-left">
                                      <p className="font-black text-sm text-gray-900 dark:text-white uppercase tracking-tight">{tx.store}</p>
                                      <div className="flex items-center space-x-2 text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">
                                          <span>{tx.date}</span>
                                          {tx.receiptData && <span className="text-brand-500 ml-1 font-black">View Digital Slip</span>}
                                      </div>
                                  </div>
                              </div>
                              <div className="text-right">
                                  <p className={`font-black text-lg ${tx.type === 'CASHOUT' ? 'text-gray-900 dark:text-white' : 'text-brand-600'}`}>
                                      {tx.type === 'CASHOUT' ? '-' : '+'} R {tx.savings.toFixed(2)}
                                  </p>
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      );
  }

  if (generatedToken && withdrawType === 'STORE') {
      return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/95 backdrop-blur-md animate-in fade-in duration-300" onClick={handleCloseToken}>
            <div className="w-full max-w-sm relative" onClick={(e) => e.stopPropagation()}>
                <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden relative max-h-[85vh] flex flex-col">
                    <div className="bg-stone-900 p-6 text-center pt-8 pb-10 relative overflow-hidden flex-shrink-0">
                        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-brand-400 via-brand-500 to-brand-400"></div>
                        <button onClick={handleCloseToken} className="absolute top-6 right-6 p-2 bg-white/10 rounded-full text-white hover:bg-white/20 z-50"><X className="w-5 h-5" /></button>
                        <h3 className="text-white font-black text-xl uppercase tracking-[0.2em] mb-1">Store Payout</h3>
                        <p className="text-stone-400 text-[10px] uppercase tracking-wider">Present to Cashier</p>
                    </div>
                    <div className="overflow-y-auto flex-1 p-8 pt-4 pb-12 text-center bg-white">
                        <div className="mb-6 text-center">
                            <div className="inline-flex items-center space-x-2 bg-green-50 text-green-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest mb-4">
                                <CheckCircle className="w-3 h-3" />
                                <span>Digital Slip Generated</span>
                            </div>
                            <div className="flex items-baseline justify-center text-stone-900">
                                <span className="text-xl font-medium mr-1">R</span>
                                <span className="text-5xl font-black tracking-tight">{parseFloat(amount || '0').toFixed(2)}</span>
                            </div>
                        </div>
                        <div className="flex justify-center mb-8 relative">
                            <div className={`bg-white p-5 rounded-3xl border-2 border-stone-900 shadow-xl transition-all ${isRotating ? 'scale-95 blur-sm' : ''}`}>
                                <QrCode className="w-40 h-40 text-stone-900" />
                            </div>
                        </div>
                        <div className="mb-8">
                            <div className="flex items-center justify-center space-x-2 mb-4">
                                <div className="flex items-center space-x-1.5 bg-brand-50 px-3 py-1 rounded-full text-brand-600 font-black text-[10px] shadow-sm">
                                    <Timer className="w-3 h-3" />
                                    <span>REFRESHES IN {timeLeft}</span>
                                </div>
                            </div>
                            <div className={`flex justify-center space-x-2 transition-all duration-500 ${isRotating ? 'scale-110 blur-md' : ''}`}>
                                {generatedToken.split('').map((digit, i) => (
                                    <div key={i} className="w-11 h-16 flex items-center justify-center bg-stone-50 rounded-xl border-2 border-stone-100 text-3xl font-black text-stone-900 shadow-sm">{digit}</div>
                                ))}
                            </div>
                        </div>
                        <button onClick={handleCloseToken} className="w-full py-4 bg-brand-600 text-white rounded-2xl font-black text-sm uppercase tracking-[0.1em] shadow-xl active:scale-95 transition-transform">
                            Finish & View History
                        </button>
                    </div>
                </div>
            </div>
        </div>
      );
  }

  if (withdrawType) {
      const currentAmount = parseFloat(amount || '0');
      const isInvalidAmount = currentAmount < MIN_WITHDRAWAL;
      const hasInsufficientFunds = currentAmount > user.miCoinBalance;
      return (
          <div className="min-h-full p-5 pb-36 flex flex-col bg-white dark:bg-slate-900 animate-in slide-in-from-bottom-10">
               <div className="flex justify-between items-center mb-6">
                  <div className="flex items-center space-x-3">
                    <button onClick={() => setWithdrawType(null)} className="p-3 -ml-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
                        <ArrowLeft className="w-6 h-6 text-gray-900 dark:text-white" />
                    </button>
                    <h2 className="text-xl font-bold text-gray-900 dark:text-white">Store Cashout</h2>
                  </div>
              </div>
              <div className="flex-1">
                  <label className="block text-[10px] font-black text-gray-400 dark:text-slate-500 mb-2 uppercase tracking-widest">Payout Amount</label>
                  <div className="relative group">
                      <span className="absolute left-4 top-5 text-2xl text-gray-400 font-bold group-focus-within:text-brand-500 transition-colors">R</span>
                      <input type="number" value={amount} onChange={(e) => setAmount(e.target.value)} className="w-full p-5 pl-10 bg-slate-50 dark:bg-slate-800 rounded-3xl border border-slate-200 dark:border-slate-700 outline-none focus:ring-2 focus:ring-brand-500 text-3xl font-mono dark:text-white font-black transition-all shadow-sm" placeholder="0.00" autoFocus />
                  </div>
                  <div className="flex justify-between items-start mt-4 px-1">
                    {isInvalidAmount && amount ? <p className="text-[10px] text-red-500 font-black uppercase bg-red-50 px-3 py-1 rounded-lg">Minimum is R{MIN_WITHDRAWAL}</p> : <span></span>}
                    <div className="text-right"><p className="text-sm font-black text-gray-900 dark:text-white">Avail: R {user.miCoinBalance.toFixed(2)}</p></div>
                  </div>
              </div>
              <div className="mt-8">
                <button disabled={!amount || isInvalidAmount || hasInsufficientFunds || processing} onClick={handleWithdraw} className="w-full py-5 bg-brand-600 disabled:bg-slate-200 dark:disabled:bg-slate-800 text-white rounded-3xl font-black shadow-2xl shadow-brand-500/20 text-lg transition-all active:scale-[0.98]">
                    {processing ? 'Generating Slip...' : 'Confirm Store Payout'}
                </button>
              </div>
          </div>
      );
  }

  return (
    <div className="flex flex-col h-full pb-24">
      <div className="p-5 space-y-6">
        <div className="flex justify-between items-center">
             <div className="flex items-center space-x-3">
                {onBack && <button onClick={onBack} className="p-3 -ml-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors text-gray-400"><ArrowLeft className="w-6 h-6" /></button>}
                <h2 className="text-2xl font-bold text-gray-900 dark:text-white">MiCOINBANK</h2>
             </div>
        </div>
        <WalletCard user={user} />
        <div className="grid grid-cols-3 gap-3">
            {[
                { id: 'STORE', icon: Banknote, label: 'Cashout', sub: 'At Till', color: 'from-brand-50', text: 'text-brand-600', action: () => setWithdrawType('STORE') },
                { id: 'BUY', icon: ShoppingBag, label: 'Buy', sub: 'Services', color: 'from-orange-50', text: 'text-orange-500', action: onOpenBuy },
                { id: 'LINK', icon: ShieldCheck, label: 'Link', sub: 'Lost Card', color: 'from-blue-50', text: 'text-blue-500', action: onOpenLinkCard },
            ].map((btn) => (
                <div key={btn.id} className="bg-white dark:bg-slate-800 p-1 rounded-[1.8rem] shadow-sm border border-slate-100 dark:border-slate-700">
                    <button onClick={btn.action} className={`w-full flex flex-col items-center p-4 rounded-[1.4rem] bg-gradient-to-br ${btn.color} to-white dark:from-slate-800 dark:to-slate-800/50 hover:opacity-80 transition-all group`}>
                        <div className={`w-10 h-10 bg-white dark:bg-slate-700 rounded-xl flex items-center justify-center shadow-sm mb-3 group-hover:scale-110 transition-transform ${btn.text}`}>
                            <btn.icon className="w-5 h-5" />
                        </div>
                        <div className="text-center">
                            <span className="font-black text-xs text-gray-900 dark:text-white block tracking-tight leading-none mb-1">{btn.label}</span>
                            <span className="text-[8px] text-gray-500 dark:text-slate-400 font-bold uppercase">{btn.sub}</span>
                        </div>
                    </button>
                </div>
            ))}
        </div>
        <div className="bg-white dark:bg-slate-800 p-1.5 rounded-[2rem] shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden">
            <button onClick={() => setIsDetailedActivityOpen(true)} className="w-full flex items-center justify-between p-5 rounded-[1.6rem] hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors group">
                <div className="flex items-center">
                    <div className="w-14 h-14 bg-brand-500/10 dark:bg-brand-500/20 text-brand-600 dark:text-brand-400 rounded-2xl flex items-center justify-center mr-5 shadow-sm group-hover:scale-110 transition-transform"><History className="w-7 h-7" /></div>
                    <div className="text-left">
                        <div className="flex items-center space-x-2">
                            <span className="font-black text-xl text-gray-900 dark:text-white block tracking-tight">Wallet Activity</span>
                            <div className="bg-brand-50 dark:bg-brand-900/30 px-2 py-0.5 rounded-lg text-[10px] font-black text-brand-600 dark:text-brand-400">{walletActivity.length}</div>
                        </div>
                        <span className="text-xs text-gray-500 dark:text-slate-400 font-medium">View slips & savings details</span>
                    </div>
                </div>
                <div className="w-10 h-10 rounded-full bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-600 shadow-sm flex items-center justify-center group-hover:bg-brand-500 group-hover:text-white transition-all"><ChevronRight className="w-5 h-5" /></div>
            </button>
        </div>
      </div>
    </div>
  );
};

export default WalletView;

import React, { useEffect, useState } from 'react';
import { ReceiptData, Store } from '../types';
import { X, Share2, Download, CheckCircle, Sparkles, ArrowLeft, Zap, ShieldCheck } from 'lucide-react';

interface DigitalReceiptProps {
  data: ReceiptData;
  store: Store;
  onClose: () => void;
}

const DigitalReceipt: React.FC<DigitalReceiptProps> = ({ data, store, onClose }) => {
  const [scanning, setScanning] = useState(true);
  const [scanProgress, setScanProgress] = useState(0);
  const [cashbackFound, setCashbackFound] = useState<number | null>(null);
  const [showNotification, setShowNotification] = useState(false);

  const isWithdrawal = data.items.some(item => 
    item.description.toUpperCase().includes('WITHDRAWAL') || 
    item.description.toUpperCase().includes('PAYOUT')
  );

  useEffect(() => {
    const duration = 2000; 
    const interval = 20;
    const steps = duration / interval;
    let currentStep = 0;

    const timer = setInterval(() => {
      currentStep++;
      setScanProgress((currentStep / steps) * 100);

      if (currentStep >= steps) {
        clearInterval(timer);
        setScanning(false);

        if (!isWithdrawal) {
          const cashbackTotal = data.items.reduce((acc, item) => acc + (item.isPromo && !item.description.includes('MiCOINBANK') ? (item.price * 0.1) : 0), 0); 
          if (cashbackTotal > 0) {
            setCashbackFound(cashbackTotal);
            setTimeout(() => setShowNotification(true), 500);
          }
        }
      }
    }, interval);

    return () => clearInterval(timer);
  }, [data, isWithdrawal]);

  return (
    <div 
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200"
      onClick={onClose}
    >
      {showNotification && (
        <div className="absolute top-10 left-0 right-0 flex justify-center z-[60] animate-in slide-in-from-top-5 duration-500 pointer-events-none">
          <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl p-4 flex items-center space-x-4 max-w-xs border-l-4" style={{ borderLeftColor: store.color }}>
             <div className="bg-brand-500/10 p-2 rounded-full">
                <Sparkles className="w-6 h-6 text-brand-500 animate-pulse" />
             </div>
             <div>
                <h4 className="font-bold text-gray-900 dark:text-white text-sm">Auto-Cashback Found!</h4>
                <p className="text-xs text-gray-500 dark:text-slate-300">R {cashbackFound?.toFixed(2)} added to wallet.</p>
             </div>
          </div>
        </div>
      )}

      <div 
        className="relative w-full max-w-md bg-white p-1 rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]"
        onClick={(e) => e.stopPropagation()} 
      >
        <div className="flex items-center justify-between p-4 bg-white border-b border-gray-100 z-50">
            <button onClick={onClose} className="flex items-center space-x-2 text-gray-500 hover:text-gray-900 py-2">
                <ArrowLeft className="w-5 h-5" />
                <span className="text-xs font-black uppercase tracking-wider">Back</span>
            </button>
            <div className="flex items-center space-x-2">
                 <div className="text-sm font-black tracking-tighter font-sans flex items-baseline">
                    <span className="text-gray-900">Cardit</span>
                    <span className="font-black px-0.5 rounded-sm ml-0.5" style={{ color: store.color }}>Oe'</span>
                </div>
            </div>
            <button onClick={onClose} className="p-2 bg-gray-100 rounded-full hover:bg-gray-200"><X className="w-5 h-5 text-gray-600" /></button>
        </div>

        <div 
            className="overflow-y-auto relative flex-1 font-mono text-xs text-gray-800 leading-tight pb-10" 
            style={{ 
                fontFamily: '"Courier Prime", "Courier New", monospace',
                backgroundColor: '#ffffff',
                backgroundImage: isWithdrawal ? 'none' : `radial-gradient(circle at top right, ${store.color}15, transparent 60%)`
            }}
        >
            {scanning && (
              <div 
                className="absolute left-0 right-0 h-1 bg-red-500/50 shadow-[0_0_15px_rgba(239,68,68,0.8)] z-20 pointer-events-none transition-all ease-linear"
                style={{ top: `${scanProgress}%` }}
              />
            )}

            <div className="p-6 pt-10 flex flex-col items-center text-center relative z-10">
                <div className="mb-2 flex flex-col items-center">
                   <div className="text-4xl mb-2">{isWithdrawal ? <div className="text-3xl bg-slate-100 p-3 rounded-full">{store.logo}</div> : store.logo}</div>
                   <div className="font-bold text-xl uppercase tracking-tighter">
                       {isWithdrawal ? 'CASH DISBURSEMENT VOUCHER' : store.name}
                   </div>
                   {isWithdrawal && <p className="text-[10px] font-black text-slate-500 tracking-[0.3em] mt-1 uppercase">Merchant Payout Copy</p>}
                </div>

                <div className="mb-4 grayscale opacity-80 text-[10px] mt-4">
                    <div className="text-xs font-bold uppercase tracking-widest mb-1">{data.merchantName}</div>
                    {data.address.map((line, i) => <div key={i}>{line}</div>)}
                </div>

                <div className="w-full flex justify-between mb-4 border-b border-dashed border-gray-300 pb-2 text-[10px]">
                    <span>CASHIER: {data.cashier}</span>
                    <span>{isWithdrawal ? 'VOUCHER NO' : 'TAX INVOICE'}</span>
                </div>

                <div className="w-full space-y-4 mb-4 text-left">
                    {data.items.map((item, idx) => (
                        <div key={idx} className={`relative p-2 rounded-xl ${isWithdrawal ? 'bg-slate-50 border border-slate-200' : item.description.includes('MiCOINBANK') ? 'border-2 border-dashed border-brand-500/50 bg-brand-50/40' : ''}`}>
                            <div className="flex justify-between font-bold text-gray-700">
                                <span className="uppercase text-[10px]">{item.description}</span>
                                <span className="flex-shrink-0">{item.total.toFixed(2)}</span>
                            </div>
                            <div className="flex justify-between text-gray-500 text-[9px]">
                                <span>{item.quantity} UNIT</span>
                            </div>
                        </div>
                    ))}
                </div>

                <div className="w-full border-t border-dashed border-gray-400 pt-3 space-y-1 mb-4">
                    <div className="flex justify-between text-lg font-bold mt-2 pt-2 border-t border-gray-100">
                        <span>TOTAL {isWithdrawal ? 'PAID OUT' : ''}</span>
                        <span>R {data.total.toFixed(2)}</span>
                    </div>
                </div>

                <div className="w-full border-t border-dashed border-gray-400 pt-2 text-left text-[10px]">
