            <p className="text-[10px] text-white/80 uppercase tracking-widest mb-1 font-black">Points Balance</p>
            <h3 className="text-5xl font-mono font-bold mb-1 tracking-tighter">{store.loyaltyPoints} <span className="text-lg font-sans font-normal text-white/70">pts</span></h3>
            <div className="flex items-center text-amber-300 font-bold text-lg mb-4"><Coins className="w-5 h-5 mr-2" />R {(store.loyaltyPoints/100).toFixed(2)}</div>
            <div className="mt-4 pt-4 border-t border-white/10 flex items-center justify-between">
                <div className="flex items-center space-x-2">
                    <div className="w-2 h-2 rounded-full bg-green-400 animate-pulse"></div>
                    <span className="text-[9px] font-black uppercase tracking-widest text-white/60">Digital Card Active</span>
                </div>
            </div>
        </div>

        {store.pointsExpiring && store.pointsExpiring > 0 && (
            <div className="bg-white dark:bg-slate-800 p-5 rounded-3xl border-2 border-dashed border-amber-500/50 shadow-lg shadow-amber-500/10 animate-in slide-in-from-bottom-5 duration-500">
                <div className="flex items-center space-x-4 mb-4">
                    <div className="bg-amber-100 dark:bg-amber-900/40 p-3 rounded-2xl">
                        <AlertTriangle className="w-6 h-6 text-amber-600 animate-pulse" />
