      case AppTab.STORE_VIEW: return selectedStore ? <StoreDetail store={selectedStore} initialTab={selectedStoreTab as any} transactions={transactions} onBack={handleBackFromStore} onUpdateStore={(s) => setStores(stores.map(x => x.id === s.id ? s : x))} onViewReceipt={(tx) => setViewingReceipt(tx)} /> : null;
      case AppTab.WALLET: return <WalletView user={user} transactions={transactions} stores={stores} onUpdateSettings={(t) => setUser({...user, roundUpTarget: t})} onToggleAutoSave={() => setUser({...user, isAutoSaveEnabled: !user.isAutoSaveEnabled})} onUpdateBalance={(a) => setUser({...user, miCoinBalance: user.miCoinBalance + a})} onAddTransaction={(tx) => setTransactions([tx, ...transactions])} onBack={handleGoBack} onViewReceipt={(tx) => setViewingReceipt(tx)} />;
