interface WalletCardProps {
  user: User;
  onOpenLinkCard?: () => void;
}

type ViewMode = 'qr' | 'barcode';

const WalletCard: React.FC<WalletCardProps> = ({ user, onOpenLinkCard }) => {
  const [isFlipped, setIsFlipped] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [viewMode, setViewMode] = useState<ViewMode>('qr');

  const openModal = (e: React.MouseEvent, mode: ViewMode) => {
    e.stopPropagation(); 
    setViewMode(mode);
    setModalOpen(true);
  };

  const handleFlipToFront = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsFlipped(false);
  };

  const handleFlipToBack = () => {
    if (!modalOpen) {
      setIsFlipped(true);
    }
  };

  // Realistic Barcode Strip Component
  const BarcodeVisual = ({ large = false }: { large?: boolean }) => (
    <div className={`flex items-center space-x-[1px] bg-white p-1 rounded-sm ${large ? 'h-24 w-full px-4' : 'h-10 w-full px-2 opacity-90'}`}>
      {[...Array(large ? 80 : 50)].map((_, i) => (
        <div 
          key={i} 
          className="bg-black h-full flex-1" 
          style={{ 
            maxWidth: large ? '4px' : '2px',
            opacity: Math.random() > 0.15 ? 1 : 0 
          }}
        ></div>
      ))}
    </div>
  );

  return (
    <>
