                              </p>
                          </div>
                          <ChevronRight className="w-5 h-5 text-slate-300" />
                      </button>
                  ))}
                  {linkedStores.length === 0 && (
                      <div className="text-center py-10 bg-slate-50 dark:bg-slate-800 rounded-[2rem] border-2 border-dashed border-slate-200">
                          <CreditCard className="w-10 h-10 mx-auto mb-3 text-slate-300" />
                          <p className="text-sm font-bold text-slate-500">Link a store card first to cashout.</p>
                      </div>
                  )}
              </div>
          </div>
      );
  }

  if (withdrawState === 'ENTER_AMOUNT') {
      const currentAmount = parseFloat(amount || '0');
      const isInvalidAmount = currentAmount < MIN_WITHDRAWAL;
      const hasInsufficientFunds = currentAmount > user.miCoinBalance;
      return (
          <div className="min-h-full p-5 pb-36 flex flex-col bg-white dark:bg-slate-900 animate-in slide-in-from-right-10">
               <div className="flex justify-between items-center mb-6">
                  <div className="flex items-center space-x-3">
                    <button onClick={() => setWithdrawState('SELECT_STORE')} className="p-3 -ml-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full">
                        <ArrowLeft className="w-6 h-6 text-gray-900 dark:text-white" />
                    </button>
                    <h2 className="text-xl font-bold text-gray-900 dark:text-white">Enter Payout</h2>
                  </div>
              </div>
              <div className="bg-slate-50 dark:bg-slate-800 p-6 rounded-[2.5rem] mb-8 border border-slate-100 dark:border-slate-700 flex items-center">
                  <div className="w-14 h-14 bg-white dark:bg-slate-700 rounded-2xl flex items-center justify-center text-3xl mr-5 shadow-sm">
                      {selectedStore?.logo}
                  </div>
                  <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Collecting From</p>
                      <h4 className="text-lg font-black text-slate-900 dark:text-white uppercase tracking-tight">{selectedStore?.name}</h4>
                  </div>
              </div>
              <div className="flex-1">
                  <label className="block text-[10px] font-black text-gray-400 dark:text-slate-500 mb-2 uppercase tracking-widest">Payout Amount</label>
                  <div className="relative group">
                      <span className="absolute left-4 top-5 text-2xl text-gray-400 font-bold group-focus-within:text-brand-500 transition-colors">R</span>
                      <input type="number" value={amount} onChange={(e) => setAmount(e.target.value)} className="w-full p-5 pl-10 bg-slate-50 dark:bg-slate-800 rounded-3xl border border-slate-200 dark:border-slate-700 outline-none focus:ring-2 focus:ring-brand-500 text-3xl font-mono dark:text-white font-black transition-all" placeholder="0.00" autoFocus />
                  </div>
                  <div className="flex justify-between items-start mt-4 px-1">
                    {isInvalidAmount && amount ? <p className="text-[10px] text-red-500 font-black uppercase bg-red-50 px-3 py-1 rounded-lg">Minimum is R{MIN_WITHDRAWAL}</p> : <span></span>}
                    <div className="text-right"><p className="text-sm font-black text-gray-900 dark:text-white">Avail: R {user.miCoinBalance.toFixed(2)}</p></div>
                  </div>
              </div>
              <div className="mt-8">
                <button disabled={!amount || isInvalidAmount || hasInsufficientFunds || processing} onClick={handleWithdraw} className="w-full py-5 bg-brand-600 disabled:bg-slate-200 dark:disabled:bg-slate-800 disabled:text-slate-400 text-white rounded-3xl font-black shadow-2xl shadow-brand-500/20 text-lg transition-all active:scale-[0.98] flex items-center justify-center"
                >
                    {processing ? <><Loader2 className="w-5 h-5 mr-2 animate-spin" /> Issuing Digital Slip...</> : 'Confirm Cashout Slip'}
                </button>
              </div>
          </div>
      );
  }

  return (
    <div className="flex flex-col h-full pb-24">
      <div className="p-5 space-y-6">
        <div className="flex justify-between items-center">
             <div className="flex items-center space-x-3">
                {onBack && <button onClick={onBack} className="p-3 -ml-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors text-gray-400"><ArrowLeft className="w-6 h-6" /></button>}
                <h2 className="text-2xl font-bold text-gray-900 dark:text-white">MiCOINBANK</h2>
             </div>
        </div>
        <WalletCard user={user} onOpenLinkCard={onOpenLinkCard} />
        <div className="grid grid-cols-3 gap-3">
            {[
                { id: 'STORE', icon: Banknote, label: 'Cashout', sub: 'At Till', color: 'from-brand-50', text: 'text-brand-600', action: () => setWithdrawState('SELECT_STORE') },
                { id: 'BUY', icon: ShoppingBag, label: 'Buy', sub: 'Services', color: 'from-orange-50', text: 'text-orange-500', action: onOpenBuy },
                { id: 'LINK', icon: ShieldCheck, label: 'Link', sub: 'Lost Card', color: 'from-blue-50', text: 'text-blue-500', action: onOpenLinkCard },
            ].map((btn) => (
                <div key={btn.id} className="bg-white dark:bg-slate-800 p-1 rounded-[1.8rem] shadow-sm border border-slate-100 dark:border-slate-700">
                    <button onClick={btn.action} className={`w-full flex flex-col items-center p-4 rounded-[1.4rem] bg-gradient-to-br ${btn.color} to-white dark:from-slate-800 dark:to-slate-800/50 hover:opacity-80 transition-all group`}>
                        <div className={`w-10 h-10 bg-white dark:bg-slate-700 rounded-xl flex items-center justify-center shadow-sm mb-3 group-hover:scale-110 transition-transform ${btn.text}`}>
                            <btn.icon className="w-5 h-5" />
                        </div>
                        <div className="text-center">
                            <span className="font-black text-xs text-gray-900 dark:text-white block tracking-tight leading-none mb-1">{btn.label}</span>
                            <span className="text-[8px] text-gray-500 dark:text-slate-400 font-bold uppercase">{btn.sub}</span>
                        </div>
                    </button>
                </div>
            ))}
        </div>
        <div className="bg-white dark:bg-slate-800 p-1.5 rounded-[2rem] shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden">
            <button onClick={() => setIsDetailedActivityOpen(true)} className="w-full flex items-center justify-between p-5 rounded-[1.6rem] hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors group">
                <div className="flex items-center">
                    <div className="w-14 h-14 bg-brand-500/10 dark:bg-brand-500/20 text-brand-600 dark:text-brand-400 rounded-2xl flex items-center justify-center mr-5 shadow-sm group-hover:scale-110 transition-transform"><History className="w-7 h-7" /></div>
                    <div className="text-left">
                        <div className="flex items-center space-x-2">
                            <span className="font-black text-xl text-gray-900 dark:text-white block tracking-tight">Wallet Activity</span>
                            <div className="bg-brand-50 dark:bg-brand-900/30 px-2 py-0.5 rounded-lg text-[10px] font-black text-brand-600 dark:text-brand-400">{walletActivity.length}</div>
                        </div>
                        <span className="text-xs text-gray-500 dark:text-slate-400 font-medium">View slips & savings details</span>
                    </div>
                </div>
                <div className="w-10 h-10 rounded-full bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-600 shadow-sm flex items-center justify-center group-hover:bg-brand-500 group-hover:text-white transition-all"><ChevronRight className="w-5 h-5" /></div>
            </button>
        </div>
        <div className="bg-white dark:bg-slate-800 p-7 rounded-[2rem] shadow-sm border border-slate-100 dark:border-slate-700">
            <div className="flex justify-between items-center mb-8">
                <h3 className="font-black text-gray-900 dark:text-white flex items-center text-lg uppercase tracking-tight">
                    <Settings className="w-5 h-5 mr-3 text-brand-500" /> Auto-Save Engine
                </h3>
                <button onClick={onToggleAutoSave} className={`relative inline-flex h-7 w-13 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-brand-500 ${user.isAutoSaveEnabled ? 'bg-brand-500' : 'bg-slate-200 dark:bg-slate-700'}`}>
                    <span className={`inline-block h-5 w-5 transform rounded-full bg-white shadow-md transition-transform duration-200 ${user.isAutoSaveEnabled ? 'translate-x-7' : 'translate-x-1'}`} />
                </button>
            </div>
            <div className={`transition-all duration-300 ${user.isAutoSaveEnabled ? 'opacity-100' : 'opacity-40 grayscale pointer-events-none'}`}>
                <div className="mb-8">
                    <div className="flex justify-between items-start mb-4">
                        <div>
                            <p className="text-sm text-gray-900 dark:text-slate-200 font-black uppercase tracking-tight">Threshold</p>
                            <p className="text-[10px] text-gray-500 dark:text-slate-400 mt-1 font-medium">Round up to the nearest R{activeThreshold}</p>
                        </div>
                        <div className="bg-brand-50 dark:bg-brand-900/40 px-3 py-1.5 rounded-xl border border-brand-100 dark:border-brand-800 flex items-center">
                            <Target className="w-3 h-3 mr-2 text-brand-500" />
                            <span className="text-lg font-black text-brand-600 dark:text-brand-400">R {activeThreshold.toFixed(2)}</span>
                        </div>
                    </div>
                    <div className="flex bg-slate-100 dark:bg-slate-700 p-1 rounded-2xl space-x-1 mb-4">
                        {thresholdOptions.map((val) => (
                            <button key={val} onClick={() => onUpdateSettings(val)} className={`flex-1 py-3 rounded-xl text-xs font-black transition-all ${activeThreshold === val ? 'bg-white dark:bg-slate-600 text-brand-600 shadow-sm' : 'text-gray-400'}`}>R{val}</button>
                        ))}
                    </div>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default WalletView;

import React, { useState, useEffect, useMemo } from 'react';
import { Store, Transaction, StoreBranch, Product } from '../types';
import { ArrowLeft, ShoppingBag, Receipt, Percent, Star, Clock, Search, AlertTriangle, ChevronRight, Sparkles, Loader2, Coins, Zap, UserPlus, ShieldCheck, X, CreditCard, MapPin, Check } from 'lucide-react';

interface StoreDetailProps {
  store: Store;
  initialTab?: 'SHOP' | 'RECEIPTS' | 'PROMOS' | 'LOYALTY';
  transactions: Transaction[];
  onBack: () => void;
  onUpdateStore: (updatedStore: Store) => void;
  onUpdateBalance?: (amount: number) => void;
  onAddTransaction?: (tx: Transaction) => void;
  onViewReceipt: (tx: Transaction) => void;
}

type Tab = 'SHOP' | 'RECEIPTS' | 'PROMOS' | 'LOYALTY';

const StoreDetail: React.FC<StoreDetailProps> = ({ store, initialTab, transactions, onBack, onUpdateStore, onUpdateBalance, onAddTransaction, onViewReceipt }) => {
  const [activeTab, setActiveTab] = useState<Tab>(initialTab || 'SHOP');
  const [isRegistering, setIsRegistering] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [branchSearchQuery, setBranchSearchQuery] = useState('');
  const [selectedBranch, setSelectedBranch] = useState<StoreBranch | null>(store.branches?.[0] || null);
  const [showBranchPicker, setShowBranchPicker] = useState(false);

  useEffect(() => {
    if (initialTab) {
        setActiveTab(initialTab);
        return;
    }

    if (store.isLinked) {
        if (store.tabAlerts.loyalty > 0 || (store.pointsExpiring || 0) > 0) setActiveTab('LOYALTY');
        else if (store.tabAlerts.slips > 0) setActiveTab('RECEIPTS');
        else if (store.tabAlerts.promos > 0) setActiveTab('PROMOS');
        else setActiveTab('SHOP');
    }
  }, [store.id, store.isLinked, initialTab]);

  const storeTransactions = transactions.filter(t => t.store === store.name || t.storeId === store.id || t.store.includes(store.name));

  const handleRegister = () => {
    setIsRegistering(true);
    setTimeout(() => {
      onUpdateStore({ ...store, isLinked: true });
      setIsRegistering(false);
    }, 2000);
  };

  const getAlertCount = (id: string) => {
    if (id === 'RECEIPTS') return store.tabAlerts.slips;
    if (id === 'PROMOS') return store.tabAlerts.promos;
    if (id === 'LOYALTY') return store.tabAlerts.loyalty + ((store.pointsExpiring || 0) > 0 ? 1 : 0);
    return 0;
  };

  // Cross-branch product searching logic
  const crossBranchProducts = useMemo(() => {
    if (!store.branches) return [];

    let allFound: { product: Product, branch: StoreBranch }[] = [];

    store.branches.forEach(branch => {
        store.inventory.forEach(item => {
            // Check if item name or category matches search
            const matchesSearch = item.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                                 item.category.toLowerCase().includes(searchQuery.toLowerCase());

            // Check if this branch actually stocks this item
            const isStocked = branch.inventoryIds.includes(item.id);

            if (matchesSearch && isStocked) {
                allFound.push({ product: item, branch: branch });
            }
        });
    });

    return allFound;
  }, [store.inventory, store.branches, searchQuery]);

  const filteredBranches = useMemo(() => {
    if (!store.branches) return [];
    return store.branches.filter(b => 
        b.name.toLowerCase().includes(branchSearchQuery.toLowerCase()) || 
        b.city.toLowerCase().includes(branchSearchQuery.toLowerCase()) ||
        b.address.toLowerCase().includes(branchSearchQuery.toLowerCase())
    );
  }, [store.branches, branchSearchQuery]);

  const renderUnlinkedView = () => (
    <div className="flex-1 flex flex-col p-6 animate-in fade-in slide-in-from-bottom-5 duration-700">
        <div className="bg-white dark:bg-slate-800 rounded-[2.5rem] p-8 text-center border border-slate-100 dark:border-slate-700 shadow-xl relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-2" style={{ backgroundColor: store.color }}></div>
            <div className="w-20 h-20 mx-auto bg-slate-50 dark:bg-slate-700 rounded-3xl flex items-center justify-center text-4xl mb-6 shadow-inner">
                {store.logo}
            </div>
            <h3 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tight mb-2">Link {store.name} Card</h3>
            <p className="text-slate-500 dark:text-slate-400 text-sm mb-8 leading-relaxed">
                Connect your {store.name} loyalty account to see digital receipts, track points, and get automatic cashback in your CarditOe' wallet.
            </p>

            <button 
                onClick={handleRegister}
                disabled={isRegistering}
                className="w-full py-5 bg-slate-900 dark:bg-brand-600 text-white rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl active:scale-95 transition-all flex items-center justify-center"
            >
                {isRegistering ? (
                    <><Loader2 className="w-5 h-5 mr-3 animate-spin" /> Verifying Member ID...</>
                ) : (
                    <><UserPlus className="w-5 h-5 mr-3" /> Link Loyalty Card</>
                )}
            </button>
        </div>
    </div>
  );

  const renderBranchPicker = () => (
    <div className="fixed inset-0 z-[60] bg-black/60 backdrop-blur-sm flex items-end animate-in fade-in duration-300">
        <div className="w-full max-w-lg mx-auto bg-white dark:bg-slate-900 rounded-t-[3rem] p-6 shadow-2xl animate-in slide-in-from-bottom-10 duration-500">
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Select Branch</h3>
                <button onClick={() => setShowBranchPicker(false)} className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-500"><X className="w-5 h-5" /></button>
            </div>

            <div className="relative mb-6">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                <input 
                    type="text"
                    value={branchSearchQuery}
                    onChange={(e) => setBranchSearchQuery(e.target.value)}
                    placeholder="Search locations (e.g. Durban, Mall...)"
                    className="w-full py-4 pl-12 pr-4 bg-slate-50 dark:bg-slate-800 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500 dark:text-white text-sm"
                />
            </div>

            <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 scrollbar-hide">
                {filteredBranches.map(branch => (
                    <button 
                        key={branch.id}
                        onClick={() => {
                            setSelectedBranch(branch);
                            setShowBranchPicker(false);
                        }}
                        className={`w-full p-4 rounded-2xl border flex items-center justify-between transition-all ${selectedBranch?.id === branch.id ? 'bg-brand-50 border-brand-200 dark:bg-brand-900/20 dark:border-brand-800' : 'bg-white dark:bg-slate-800 border-slate-100 dark:border-slate-700'}`}
                    >
                        <div className="flex items-center space-x-4">
                            <div className={`p-3 rounded-xl ${selectedBranch?.id === branch.id ? 'bg-brand-500 text-white' : 'bg-slate-100 dark:bg-slate-700 text-slate-400'}`}>
                                <MapPin className="w-5 h-5" />
                            </div>
                            <div className="text-left">
                                <p className="font-bold text-slate-900 dark:text-white text-sm uppercase">{branch.name}</p>
                                <p className="text-[10px] text-slate-500 dark:text-slate-400 font-medium">{branch.address}, {branch.city}</p>
                            </div>
                        </div>
                        {selectedBranch?.id === branch.id && <Check className="w-5 h-5 text-brand-600" />}
                    </button>
                ))}
            </div>
        </div>
    </div>
  );

  const renderLoyalty = () => (
    <div className="space-y-6">
        <div className="rounded-3xl p-6 text-white shadow-xl relative overflow-hidden" style={{ backgroundColor: store.color }}>
            <div className="absolute top-0 right-0 w-48 h-48 bg-white opacity-10 rounded-full -mr-12 -mt-12"></div>
            <p className="text-[10px] text-white/80 uppercase tracking-widest mb-1 font-black">Points Balance</p>
            <h3 className="text-5xl font-mono font-bold mb-1 tracking-tighter">{store.loyaltyPoints} <span className="text-lg font-sans font-normal text-white/70">pts</span></h3>
            <div className="flex items-center text-amber-300 font-bold text-lg mb-4"><Coins className="w-5 h-5 mr-2" />R {(store.loyaltyPoints/100).toFixed(2)}</div>
        </div>
    </div>
  );

  const renderShop = () => {
    return (
      <div className="space-y-4">
        <div className="relative">
          <Search className="absolute left-3 top-3 w-4 h-4 text-gray-400" />
          <input 
            type="text" 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder={`Search ${store.name} items across all branches...`} 
            className="w-full bg-slate-100 dark:bg-slate-700 rounded-xl pl-10 pr-10 py-2.5 text-sm outline-none focus:ring-2 focus:ring-brand-500 dark:text-white transition-all" 
          />
        </div>

        {searchQuery && (
            <div className="px-1">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Availability Results ({crossBranchProducts.length})</p>
                <div className="grid grid-cols-2 gap-3">
                    {crossBranchProducts.map(({ product, branch }, idx) => (
                        <div key={`${product.id}-${branch.id}`} className="bg-white dark:bg-slate-800 p-3 rounded-xl border border-slate-100 dark:border-slate-700 shadow-sm relative group flex flex-col">
                            <div className="h-24 w-full bg-slate-50 dark:bg-slate-700 rounded-lg mb-2 flex items-center justify-center text-2xl">{product.image || '📦'}</div>
                            <h4 className="font-bold text-xs text-gray-800 dark:text-white line-clamp-1">{product.name}</h4>
                            <div className="flex items-center text-[8px] text-slate-500 font-black uppercase mt-1 mb-2">
                                <MapPin className="w-2 h-2 mr-1 text-brand-500" />
                                <span className="truncate">{branch.name}</span>
                            </div>
                            <div className="flex justify-between items-end mt-auto">
                                <span className="font-black text-sm" style={{ color: store.color }}>R {product.price.toFixed(2)}</span>
                                <button className="w-6 h-6 rounded-lg flex items-center justify-center text-white shadow-sm" style={{ backgroundColor: store.color }}><ShoppingBag className="w-3 h-3" /></button>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        )}

        {!searchQuery && (
            <div className="grid grid-cols-2 gap-3">
                {store.inventory.filter(i => selectedBranch?.inventoryIds.includes(i.id)).map(item => (
                    <div key={item.id} className="bg-white dark:bg-slate-800 p-3 rounded-xl border border-slate-100 dark:border-slate-700 shadow-sm relative group">
                        <div className="h-24 w-full bg-slate-50 dark:bg-slate-700 rounded-lg mb-3 flex items-center justify-center text-2xl">{item.image || '📦'}</div>
                        <h4 className="font-medium text-sm text-gray-800 dark:text-white line-clamp-2">{item.name}</h4>
                        <div className="flex justify-between items-end mt-2">
                            <span className="font-bold" style={{ color: store.color }}>R {item.price.toFixed(2)}</span>
                            <button className="w-6 h-6 rounded-full flex items-center justify-center text-white" style={{ backgroundColor: store.color }}>+</button>
                        </div>
                    </div>
                ))}
            </div>
        )}
      </div>
    );
  };

  const renderReceipts = () => (
    <div className="space-y-3">
       {storeTransactions.length === 0 ? (
           <div className="text-center py-20 text-slate-400">
               <Receipt className="w-12 h-12 mx-auto mb-3 opacity-20" />
               <p className="text-sm font-medium">No digital slips found for this store yet.</p>
           </div>
       ) : (
           storeTransactions.map(tx => (
              <div key={tx.id} onClick={() => tx.receiptData && onViewReceipt(tx)} className={`bg-white dark:bg-slate-800 p-4 rounded-xl border-l-4 shadow-sm relative overflow-hidden transition-all active:scale-95 ${tx.receiptData ? 'cursor-pointer hover:shadow-md' : ''}`} style={{ borderLeftColor: store.color }}>
                <div className="flex justify-between items-start mb-2">
                   <div>
                      <h4 className="font-bold text-gray-900 dark:text-white text-sm">{tx.store}</h4>
                      <p className="text-[10px] text-gray-500 dark:text-slate-400">{tx.date}</p>
                   </div>
                   <div className="text-right">
                      <span className="block font-bold text-base dark:text-white">R {tx.amount > 0 ? tx.amount.toFixed(2) : tx.savings.toFixed(2)}</span>
                      <span className="text-[10px] font-black uppercase tracking-tighter" style={{ color: store.color }}>
                        {tx.type === 'CASHOUT' ? 'Voucher Payout' : `Saved R${tx.savings.toFixed(2)}`}
                      </span>
                   </div>
                </div>
                <div className="border-t border-dashed border-gray-200 dark:border-slate-700 my-2"></div>
                <div className="mt-3 flex justify-between items-center">
                    <span className="text-[9px] bg-slate-100 dark:bg-slate-700 text-gray-400 px-2 py-0.5 rounded uppercase font-bold">Verified Transaction</span>
                    <button className="text-[10px] font-black uppercase flex items-center tracking-widest" style={{ color: store.color }}>View Slip <ChevronRight className="w-3 h-3 ml-0.5" /></button>
                </div>
              </div>
           ))
       )}
    </div>
  );

  return (
    <div className="flex flex-col h-full bg-gray-50 dark:bg-slate-900 relative">
      {showBranchPicker && renderBranchPicker()}

      <div className="relative text-white p-6 pb-10 rounded-b-[2.5rem] shadow-lg transition-colors" style={{ backgroundColor: store.color }}>
         <div className="flex justify-between items-center mb-4">
            <button onClick={onBack} className="p-2 bg-white/20 backdrop-blur-sm rounded-full hover:bg-white/30"><ArrowLeft className="w-5 h-5 text-white" /></button>
            <div className="text-lg font-black tracking-tighter font-sans flex items-baseline"><span>Cardit</span><span className="text-white/70">Oe'</span></div>
            <div className="w-9 h-9 bg-white/20 rounded-full flex items-center justify-center backdrop-blur-sm border border-white/30">{store.logo}</div>
         </div>
         <div className="mt-2 flex justify-between items-end">
            <div>
                <h1 className="text-2xl font-bold">{store.name}</h1>
                <button 
                    onClick={() => setShowBranchPicker(true)}
                    className="text-white/80 text-xs flex items-center mt-1 bg-white/10 px-2 py-1 rounded-lg hover:bg-white/20 transition-all"
                >
                    <MapPin className="w-3 h-3 mr-1" /> {selectedBranch?.name || 'Select Branch'}
                    <ChevronRight className="w-3 h-3 ml-1 rotate-90" />
                </button>
            </div>
            <div className="text-right">
                <p className="text-[10px] font-black uppercase text-white/50 tracking-widest">Balance</p>
                <p className="text-lg font-black">R {(store.loyaltyPoints/100).toFixed(2)}</p>
            </div>
         </div>
      </div>

      {store.isLinked ? (
          <>
            <div className="px-6 -mt-8">
                <div className="bg-white dark:bg-slate-800 rounded-xl shadow-md p-1.5 flex justify-between items-center">
                    {[
                        { id: 'SHOP', icon: ShoppingBag, label: 'Shop' },
                        { id: 'RECEIPTS', icon: Receipt, label: 'Slips' },
                        { id: 'PROMOS', icon: Percent, label: 'Cashback' },
                        { id: 'LOYALTY', icon: Star, label: 'Points' },
                    ].map((tab) => {
                        const alertCount = getAlertCount(tab.id);
                        return (
                            <button 
                                key={tab.id} 
                                onClick={() => setActiveTab(tab.id as Tab)} 
                                className={`flex-1 flex flex-col items-center py-2 rounded-lg transition-all relative ${activeTab === tab.id ? 'bg-slate-100 dark:bg-slate-700 shadow-sm' : 'text-gray-400 dark:text-slate-500'}`} 
                                style={activeTab === tab.id ? { color: store.color } : {}}
                            >
                                <div className="relative">
                                    <tab.icon className="w-5 h-5 mb-0.5" />
                                    {alertCount > 0 && (
                                        <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white dark:border-slate-800 animate-pulse"></span>
                                    )}
                                </div>
                                <span className="text-[10px] font-medium">{tab.label}</span>
                            </button>
                        );
                    })}
                </div>
            </div>
            <div className="flex-1 overflow-y-auto p-5 pb-20">
                {activeTab === 'SHOP' && renderShop()}
                {activeTab === 'RECEIPTS' && renderReceipts()}
                {activeTab === 'PROMOS' && (
                    <div className="space-y-4">
                        <div className="p-4 rounded-xl text-white shadow-lg relative overflow-hidden" style={{ background: `linear-gradient(to right, ${store.color}, ${store.color}dd)` }}>
                            <h3 className="text-xl font-bold">Auto-Cash Back</h3>
                            <p className="text-sm opacity-90 leading-tight">No booking needed. Detected automatically when you scan any {store.name} slip.</p>
                        </div>
                        <div className="grid grid-cols-1 gap-3">
                            {store.promos.map(item => (
                                <div key={item.id} className="flex bg-white dark:bg-slate-800 p-3 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden relative">
                                    <div className="w-20 h-20 bg-slate-100 dark:bg-slate-700 rounded-xl flex-shrink-0 flex items-center justify-center text-3xl">{item.image}</div>
                                    <div className="ml-3 flex-1 flex flex-col justify-between py-1">
                                        <h4 className="font-bold text-gray-800 dark:text-white text-sm leading-tight">{item.name}</h4>
                                        <div className="flex justify-between items-end mt-2">
                                            <span className="font-black text-lg dark:text-white">R {item.price.toFixed(2)}</span>
                                            <div className="flex items-center text-accent-600 dark:text-accent-500">
                                                <Sparkles className="w-3 h-3 mr-1" />
                                                <span className="text-[10px] font-black">R{item.cashbackAmount?.toFixed(0)} BACK</span>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
                {activeTab === 'LOYALTY' && renderLoyalty()}
            </div>
          </>
      ) : renderUnlinkedView()}
    </div>
  );
};

export default StoreDetail;

import React, { useState, useEffect, useMemo } from 'react';
import { Store, Transaction, StoreBranch, Product } from '../types';
import { ArrowLeft, ShoppingBag, Receipt, Percent, Star, Clock, Search, AlertTriangle, ChevronRight, Sparkles, Loader2, Coins, Zap, UserPlus, ShieldCheck, X, CreditCard, MapPin, Check, Filter } from 'lucide-react';

interface StoreDetailProps {
  store: Store;
  initialTab?: 'SHOP' | 'RECEIPTS' | 'PROMOS' | 'LOYALTY';
  transactions: Transaction[];
  onBack: () => void;
  onUpdateStore: (updatedStore: Store) => void;
  onUpdateBalance?: (amount: number) => void;
  onAddTransaction?: (tx: Transaction) => void;
  onViewReceipt: (tx: Transaction) => void;
}

type Tab = 'SHOP' | 'RECEIPTS' | 'PROMOS' | 'LOYALTY';

const StoreDetail: React.FC<StoreDetailProps> = ({ store, initialTab, transactions, onBack, onUpdateStore, onUpdateBalance, onAddTransaction, onViewReceipt }) => {
  const [activeTab, setActiveTab] = useState<Tab>(initialTab || 'SHOP');
  const [isRegistering, setIsRegistering] = useState(false);
  const [itemSearchQuery, setItemSearchQuery] = useState('');
  const [branchSearchQuery, setBranchSearchQuery] = useState('');
  const [selectedBranch, setSelectedBranch] = useState<StoreBranch | null>(store.branches?.[0] || null);

  useEffect(() => {
    if (initialTab) {
        setActiveTab(initialTab);
        return;
    }

    if (store.isLinked) {
        if (store.tabAlerts.loyalty > 0 || (store.pointsExpiring || 0) > 0) setActiveTab('LOYALTY');
        else if (store.tabAlerts.slips > 0) setActiveTab('RECEIPTS');
        else if (store.tabAlerts.promos > 0) setActiveTab('PROMOS');
        else setActiveTab('SHOP');
    }
  }, [store.id, store.isLinked, initialTab]);

  const storeTransactions = transactions.filter(t => t.store === store.name || t.storeId === store.id || t.store.includes(store.name));

  const handleRegister = () => {
    setIsRegistering(true);
    setTimeout(() => {
      onUpdateStore({ ...store, isLinked: true });
      setIsRegistering(false);
    }, 2000);
  };

  const getAlertCount = (id: string) => {
    if (id === 'RECEIPTS') return store.tabAlerts.slips;
    if (id === 'PROMOS') return store.tabAlerts.promos;
    if (id === 'LOYALTY') return store.tabAlerts.loyalty + ((store.pointsExpiring || 0) > 0 ? 1 : 0);
    return 0;
  };

  // Logic to search for items across ALL branches of this brand
  const crossBranchProductResults = useMemo(() => {
    if (!itemSearchQuery.trim()) return [];

    let results: { product: Product, branch: StoreBranch }[] = [];
    const branchesToSearch = store.branches || [];

    branchesToSearch.forEach(branch => {
      store.inventory.forEach(item => {
        const matchesQuery = item.name.toLowerCase().includes(itemSearchQuery.toLowerCase()) || 
                            item.category.toLowerCase().includes(itemSearchQuery.toLowerCase());

        const isAvailableAtBranch = branch.inventoryIds.includes(item.id);

        if (matchesQuery && isAvailableAtBranch) {
          results.push({ product: item, branch: branch });
        }
      });
    });

    return results;
  }, [itemSearchQuery, store.inventory, store.branches]);

  const filteredBranches = useMemo(() => {
    if (!store.branches) return [];
    return store.branches.filter(b => 
        b.name.toLowerCase().includes(branchSearchQuery.toLowerCase()) || 
        b.city.toLowerCase().includes(branchSearchQuery.toLowerCase()) ||
        b.address.toLowerCase().includes(branchSearchQuery.toLowerCase())
    );
  }, [store.branches, branchSearchQuery]);

  const renderShop = () => {
    return (
      <div className="flex flex-col h-full relative">
        {/* TOP: Branch Search Section */}
        <div className="mb-6 space-y-3">
          <div className="flex items-center justify-between px-1">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Find Store Location</h3>
            <div className="flex items-center text-[10px] font-bold text-brand-600 bg-brand-50 px-2 py-0.5 rounded-full">
              <MapPin className="w-2.5 h-2.5 mr-1" />
              <span>{selectedBranch?.city || 'Region'}</span>
            </div>
          </div>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input 
              type="text" 
              value={branchSearchQuery}
              onChange={(e) => setBranchSearchQuery(e.target.value)}
              placeholder={`Search ${store.name} locations (e.g. Durban)...`} 
              className="w-full bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-xl pl-10 pr-4 py-3 text-sm outline-none focus:ring-2 focus:ring-brand-500 dark:text-white shadow-sm"
            />
          </div>

          {/* Branch Chips/Quick Select */}
          {branchSearchQuery && (
            <div className="flex flex-col space-y-2 mt-2 animate-in slide-in-from-top-2 duration-300">
              {filteredBranches.map(branch => (
                <button 
                  key={branch.id}
                  onClick={() => {
                    setSelectedBranch(branch);
                    setBranchSearchQuery('');
                  }}
                  className={`flex items-center justify-between p-3 rounded-xl border text-left transition-all ${selectedBranch?.id === branch.id ? 'bg-brand-50 border-brand-200' : 'bg-white dark:bg-slate-800 border-slate-100'}`}
                >
                  <div className="flex items-center space-x-3">
                    <div className="w-8 h-8 rounded-lg bg-slate-100 flex items-center justify-center text-slate-400">
                      <MapPin className="w-4 h-4" />
                    </div>
                    <div>
                      <p className="text-xs font-bold text-slate-900 dark:text-white uppercase tracking-tight">{branch.name}</p>
                      <p className="text-[9px] text-slate-500">{branch.address}</p>
                    </div>
                  </div>
                  {selectedBranch?.id === branch.id && <Check className="w-4 h-4 text-brand-600" />}
                </button>
              ))}
            </div>
          )}
        </div>

        {/* MIDDLE: Results Content */}
        <div className="flex-1 pb-24">
          {itemSearchQuery ? (
            <div className="space-y-4">
               <div className="flex items-center justify-between px-1">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Global Brand Search: "{itemSearchQuery}"</p>
                <span className="text-[10px] font-bold text-slate-500 bg-slate-100 px-2 py-0.5 rounded-full">{crossBranchProductResults.length} Found</span>
               </div>

               <div className="grid grid-cols-1 gap-3">
                  {crossBranchProductResults.map(({ product, branch }, idx) => (
                    <div 
                      key={`${product.id}-${branch.id}`} 
                      className="bg-white dark:bg-slate-800 p-3 rounded-[1.5rem] border border-slate-100 dark:border-slate-700 shadow-sm flex items-center group active:scale-[0.98] transition-all"
                    >
                      <div className="w-16 h-16 bg-slate-50 dark:bg-slate-700 rounded-2xl flex items-center justify-center text-2xl mr-4 flex-shrink-0">
                        {product.image || '📦'}
                      </div>
                      <div className="flex-1">
                        <div className="flex justify-between items-start">
                          <h4 className="font-bold text-sm text-gray-800 dark:text-white">{product.name}</h4>
                          <span className="font-black text-sm" style={{ color: store.color }}>R {product.price.toFixed(2)}</span>
                        </div>
                        <div className="flex items-center mt-1 space-x-2">
                           <div className="flex items-center text-[9px] font-black uppercase text-brand-600 bg-brand-50 px-2 py-0.5 rounded-md">
                              <MapPin className="w-2.5 h-2.5 mr-1" />
                              {branch.name}
                           </div>
                           {product.inStock ? (
                             <span className="text-[9px] text-green-500 font-bold uppercase tracking-wider">In Stock</span>
                           ) : (
                             <span className="text-[9px] text-red-400 font-bold uppercase tracking-wider">Out of Stock</span>
                           )}
                        </div>
                      </div>
                      <button className="ml-3 w-10 h-10 rounded-xl flex items-center justify-center text-white shadow-sm" style={{ backgroundColor: store.color }}>
                        <PlusIcon className="w-5 h-5" />
                      </button>
                    </div>
                  ))}

                  {crossBranchProductResults.length === 0 && (
                    <div className="text-center py-10 opacity-40">
                      <ShoppingBag className="w-12 h-12 mx-auto mb-2" />
                      <p className="text-xs font-bold uppercase">No items found across branches</p>
                    </div>
                  )}
               </div>
            </div>
          ) : (
            <div className="space-y-4">
              <div className="flex items-center justify-between px-1">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">In Stock at {selectedBranch?.name || 'Store'}</p>
                <button className="text-[10px] font-black text-brand-600 uppercase tracking-widest">View All</button>
              </div>
              <div className="grid grid-cols-2 gap-3">
                {store.inventory.filter(i => selectedBranch?.inventoryIds.includes(i.id)).map(item => (
                    <div key={item.id} className="bg-white dark:bg-slate-800 p-3 rounded-[2rem] border border-slate-100 dark:border-slate-700 shadow-sm relative group active:scale-95 transition-all">
                        <div className="h-28 w-full bg-slate-50 dark:bg-slate-700 rounded-2xl mb-3 flex items-center justify-center text-3xl shadow-inner group-hover:scale-105 transition-transform">{item.image || '📦'}</div>
                        <h4 className="font-black text-xs text-gray-800 dark:text-white line-clamp-1 px-1">{item.name}</h4>
                        <div className="flex justify-between items-center mt-3 px-1">
                            <span className="font-black text-sm" style={{ color: store.color }}>R {item.price.toFixed(2)}</span>
                            <button className="w-8 h-8 rounded-full flex items-center justify-center text-white shadow-lg" style={{ backgroundColor: store.color }}>
                                <PlusIcon className="w-4 h-4" />
                            </button>
                        </div>
                    </div>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* BOTTOM: Floating Item Search Bar */}
        <div className="fixed bottom-20 left-1/2 -translate-x-1/2 w-full max-w-sm px-4 z-40">
           <div className="bg-white/80 dark:bg-slate-800/80 backdrop-blur-xl rounded-full p-2 border border-white/20 dark:border-slate-700 shadow-2xl flex items-center">
              <div className="w-10 h-10 rounded-full bg-slate-100 dark:bg-slate-700 flex items-center justify-center text-slate-400 mr-2 flex-shrink-0">
                 <Search className="w-5 h-5" />
              </div>
              <input 
                type="text" 
                value={itemSearchQuery}
                onChange={(e) => setItemSearchQuery(e.target.value)}
                placeholder="Search items (e.g. Milk, Bread...)" 
                className="flex-1 bg-transparent border-none outline-none py-2 text-sm font-bold dark:text-white placeholder-slate-400"
              />
              {itemSearchQuery && (
                <button onClick={() => setItemSearchQuery('')} className="p-2 text-slate-300 hover:text-slate-500">
                  <X className="w-4 h-4" />
                </button>
              )}
              <div className="w-10 h-10 rounded-full flex items-center justify-center text-white ml-2 shadow-lg" style={{ backgroundColor: store.color }}>
                 <Filter className="w-4 h-4" />
              </div>
           </div>
        </div>
      </div>
    );
  };

  const renderLoyalty = () => (
    <div className="space-y-6">
        <div className="rounded-[2.5rem] p-8 text-white shadow-xl relative overflow-hidden" style={{ backgroundColor: store.color }}>
            <div className="absolute top-0 right-0 w-48 h-48 bg-white opacity-10 rounded-full -mr-12 -mt-12"></div>
            <p className="text-[10px] text-white/80 uppercase tracking-widest mb-1 font-black">Points Balance</p>
            <h3 className="text-5xl font-mono font-bold mb-2 tracking-tighter">{store.loyaltyPoints} <span className="text-lg font-sans font-normal text-white/70">pts</span></h3>
            <div className="flex items-center text-amber-300 font-bold text-lg mb-4"><Coins className="w-5 h-5 mr-2" />R {(store.loyaltyPoints/100).toFixed(2)}</div>

            <div className="bg-white/10 backdrop-blur-md rounded-2xl p-4 border border-white/10">
               <div className="flex items-center justify-between mb-2">
                 <span className="text-[10px] font-black uppercase tracking-widest">Next Tier Progress</span>
                 <span className="text-[10px] font-bold">75%</span>
               </div>
               <div className="w-full h-1.5 bg-black/20 rounded-full overflow-hidden">
                 <div className="h-full bg-white rounded-full" style={{ width: '75%' }}></div>
               </div>
            </div>
        </div>
    </div>
  );

  const renderReceipts = () => (
    <div className="space-y-4">
       {storeTransactions.length === 0 ? (
           <div className="text-center py-20 text-slate-400">
               <Receipt className="w-12 h-12 mx-auto mb-3 opacity-20" />
               <p className="text-sm font-medium">No digital slips found for this store yet.</p>
           </div>
       ) : (
           storeTransactions.map(tx => (
              <div key={tx.id} onClick={() => tx.receiptData && onViewReceipt(tx)} className={`bg-white dark:bg-slate-800 p-5 rounded-[2rem] border-l-4 shadow-sm relative overflow-hidden transition-all active:scale-95 ${tx.receiptData ? 'cursor-pointer hover:shadow-md' : ''}`} style={{ borderLeftColor: store.color }}>
                <div className="flex justify-between items-start mb-2">
                   <div>
                      <h4 className="font-black text-slate-900 dark:text-white text-sm uppercase tracking-tight">{tx.store}</h4>
                      <p className="text-[10px] text-slate-500 dark:text-slate-400 font-bold uppercase tracking-widest">{tx.date}</p>
                   </div>
                   <div className="text-right">
                      <span className="block font-black text-lg dark:text-white">R {tx.amount > 0 ? tx.amount.toFixed(2) : tx.savings.toFixed(2)}</span>
                      <span className="text-[10px] font-black uppercase tracking-tighter" style={{ color: store.color }}>
                        {tx.type === 'CASHOUT' ? 'Voucher Payout' : `Saved R${tx.savings.toFixed(2)}`}
                      </span>
                   </div>
                </div>
                <div className="border-t border-dashed border-slate-100 dark:border-slate-700 my-4"></div>
                <div className="flex justify-between items-center">
                    <span className="text-[9px] bg-slate-50 dark:bg-slate-700 text-slate-400 px-3 py-1 rounded-full uppercase font-black tracking-widest">Auth: 228492</span>
                    <button className="text-[10px] font-black uppercase flex items-center tracking-widest" style={{ color: store.color }}>View Slip <ChevronRight className="w-3 h-3 ml-0.5" /></button>
                </div>
              </div>
           ))
       )}
    </div>
  );

  return (
    <div className="flex flex-col h-full bg-slate-50 dark:bg-slate-900 relative">
      {/* Dynamic Header */}
      <div className="relative text-white p-6 pb-12 rounded-b-[3rem] shadow-xl transition-colors" style={{ backgroundColor: store.color }}>
         <div className="absolute inset-0 opacity-10 pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle at 20% 20%, white, transparent 50%)' }}></div>
         <div className="flex justify-between items-center mb-6 relative z-10">
            <button onClick={onBack} className="p-3 bg-white/20 backdrop-blur-lg rounded-2xl hover:bg-white/30 transition-all active:scale-90"><ArrowLeft className="w-5 h-5 text-white" /></button>
            <div className="text-lg font-black tracking-tighter font-sans flex items-baseline"><span>Cardit</span><span className="text-white/70">Oe'</span></div>
            <div className="w-11 h-11 bg-white rounded-2xl flex items-center justify-center shadow-lg border-2 border-white/20 text-xl">{store.logo}</div>
         </div>
         <div className="mt-2 flex justify-between items-end relative z-10">
            <div>
                <h1 className="text-3xl font-black uppercase tracking-tight leading-none">{store.name}</h1>
                <div className="flex items-center mt-2 space-x-2">
                    <div className="bg-white/20 backdrop-blur-md px-3 py-1 rounded-full flex items-center">
                        <MapPin className="w-3 h-3 mr-1.5" />
                        <span className="text-[10px] font-black uppercase tracking-widest">{selectedBranch?.name || 'Main Branch'}</span>
                    </div>
                    {store.isLinked && (
                        <div className="bg-green-500/20 backdrop-blur-md px-3 py-1 rounded-full flex items-center border border-green-500/30">
                            <ShieldCheck className="w-3 h-3 mr-1.5" />
                            <span className="text-[10px] font-black uppercase tracking-widest">Linked</span>
                        </div>
                    )}
                </div>
            </div>
            <div className="text-right">
                <p className="text-[10px] font-black uppercase text-white/50 tracking-[0.2em] mb-1">Total Points</p>
