                                            <h4 className="font-black text-slate-900 dark:text-white text-sm leading-tight uppercase tracking-tight">{item.name}</h4>
                                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">{item.category}</p>
