               <div className="grid grid-cols-1 gap-3">
                  {globalBrandSearchResults.map(({ product, branch }, idx) => (
                    <div 
                      key={`${product.id}-${branch.id}`} 
                      className="bg-white dark:bg-slate-800 p-4 rounded-[1.8rem] border border-slate-100 dark:border-slate-700 shadow-sm flex items-center group active:scale-[0.98] transition-all"
                    >
