                        <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-white dark:bg-slate-600 rounded-full flex items-center justify-center shadow-sm border border-slate-200">
                            <span className="text-[8px]">{store.logo}</span>
                        </div>
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex justify-between items-start mb-0.5">
