                        <div className="flex flex-col space-y-1">
                           <div className="flex items-center text-[9px] font-black uppercase text-slate-500 truncate">
                              <MapPin className="w-2.5 h-2.5 mr-1 text-brand-500" />
                              {branch.name}
                           </div>
                           <div className="flex items-center space-x-2">
                             <div className="w-2 h-2 rounded-full bg-green-500"></div>
                             <span className="text-[8px] text-slate-400 font-bold uppercase tracking-wider">In Stock Ready to collect</span>
                           </div>
                        </div>
                      </div>
                      <button 
                        className="ml-4 w-11 h-11 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-brand-500/10 active:scale-90 transition-transform" 
                        style={{ backgroundColor: store.color }}
                      >
                        <Plus className="w-5 h-5" />
                      </button>
                    </div>
                  ))}
               </div>

               {globalBrandSearchResults.length === 0 && (
                 <div className="flex flex-col items-center justify-center py-12 text-slate-300">
                   <Search className="w-12 h-12 mb-3 opacity-20" />
                   <p className="text-[10px] font-black uppercase tracking-[0.2em]">No brand stock found</p>
                 </div>
               )}
