                    <h3 className="text-sm font-black text-slate-800 dark:text-white uppercase tracking-tight">Available at {selectedBranch?.name || 'this branch'}</h3>
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-0.5">Showing local inventory only</p>
                </div>
                <div className="w-10 h-10 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center text-slate-400">
