      <h3 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tight mb-2">Link Your Card</h3>
      <p className="text-slate-500 dark:text-slate-400 text-sm mb-10 max-w-xs leading-relaxed">
