      <button 
        onClick={handleRegister}
        disabled={isRegistering}
        className="w-full py-5 bg-brand-600 text-white rounded-[2rem] font-black text-sm uppercase tracking-widest shadow-xl shadow-brand-500/20 active:scale-95 transition-all flex items-center justify-center"
