import React, { useState, useMemo } from 'react';
import { Store, ShoppingListItem, Product, SavedList } from '../types';
import { Search, Plus, Minus, Trash2, ShoppingCart, TrendingDown, Check, X, Save, FolderOpen, ArrowLeft, ShoppingBasket, Filter } from 'lucide-react';

interface GroceryAssistantProps {
  stores: Store[];
  shoppingList: ShoppingListItem[];
  savedLists: SavedList[];
  onAddItem: (item: ShoppingListItem) => void;
  onRemoveItem: (itemId: string, storeId: string) => void;
  onUpdateQuantity: (itemId: string, storeId: string, delta: number) => void;
  onSaveList: (name: string) => void;
  onLoadList: (list: SavedList) => void;
  onDeleteList: (listId: string) => void;
}

interface SearchResult extends Product {
  storeId: string;
  storeName: string;
  storeColor: string;
  storeLogo: string;
}

const GroceryAssistant: React.FC<GroceryAssistantProps> = ({ 
  stores, 
  shoppingList, 
  savedLists,
  onAddItem, 
  onRemoveItem, 
  onUpdateQuantity,
  onSaveList,
  onLoadList,
  onDeleteList
}) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [viewingSaved, setViewingSaved] = useState(false);
  const [isNamingList, setIsNamingList] = useState(false);
  const [newListName, setNewListName] = useState('');

  const allProducts: SearchResult[] = useMemo(() => {
    let products: SearchResult[] = [];
    stores.forEach(store => {
      const storeItems = [...store.promos, ...store.inventory];
      const mappedItems = storeItems.map(item => ({
        ...item,
        storeId: store.id,
        storeName: store.name,
        storeColor: store.color,
        storeLogo: store.logo
      }));
      products = [...products, ...mappedItems];
    });
    return products;
  }, [stores]);

  const searchResults = useMemo(() => {
    if (!searchQuery.trim()) return [];

    const lowerQuery = searchQuery.toLowerCase();
    return allProducts
      .filter(p => p.name.toLowerCase().includes(lowerQuery) || p.category.toLowerCase().includes(lowerQuery))
      .sort((a, b) => a.price - b.price);
  }, [searchQuery, allProducts]);

  const totalCost = shoppingList.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalSavings = shoppingList.reduce((sum, item) => {
    const savingPerItem = item.oldPrice ? (item.oldPrice - item.price) : 0;
    const cashback = item.cashbackAmount || 0;
    return sum + ((savingPerItem + cashback) * item.quantity);
  }, 0);

  const handleAddItem = (result: SearchResult) => {
    const itemToAdd: ShoppingListItem = {
      ...result,
      quantity: 1
    };
    onAddItem(itemToAdd);
    setSearchQuery('');
  };

  const handleSaveConfirm = () => {
      if (newListName.trim()) {
          onSaveList(newListName);
          setNewListName('');
          setIsNamingList(false);
      }
  };

  if (viewingSaved) {
      return (
          <div className="flex flex-col h-full bg-slate-50 dark:bg-slate-900 pb-20">
              <div className="bg-white dark:bg-slate-800 p-5 shadow-sm border-b border-gray-200 dark:border-slate-700 sticky top-0 z-10 flex items-center">
                  <button onClick={() => setViewingSaved(false)} className="mr-3 p-2 bg-slate-100 dark:bg-slate-700 rounded-full">
                      <ArrowLeft className="w-5 h-5 text-gray-600 dark:text-white" />
                  </button>
                  <h2 className="text-xl font-bold text-gray-900 dark:text-white">My Saved Lists</h2>
              </div>
              <div className="p-4 space-y-3 overflow-y-auto">
                  {savedLists.length === 0 ? (
                      <div className="text-center py-20 text-slate-300">
                          <FolderOpen className="w-16 h-16 mx-auto mb-3 opacity-20" />
                          <p className="text-xs font-black uppercase tracking-widest">No saved lists yet</p>
                      </div>
                  ) : (
                      savedLists.map(list => (
                          <div key={list.id} className="bg-white dark:bg-slate-800 p-5 rounded-[2rem] shadow-sm border border-slate-100 dark:border-slate-700">
                              <div className="flex justify-between items-start mb-4">
                                  <div>
                                      <h4 className="font-black text-slate-900 dark:text-white uppercase tracking-tight">{list.name}</h4>
                                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{list.date} • {list.items.length} items</p>
                                  </div>
                                  <button onClick={() => onDeleteList(list.id)} className="text-slate-300 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
                              </div>
                              <div className="flex justify-between items-center bg-slate-50 dark:bg-slate-700/50 p-4 rounded-2xl mb-4">
                                  <span className="font-black text-gray-800 dark:text-white">R {list.total.toFixed(2)}</span>
                                  <span className="text-[10px] font-black text-green-600 uppercase tracking-widest">Saved R{list.totalSavings.toFixed(2)}</span>
                              </div>
                              <button onClick={() => { onLoadList(list); setViewingSaved(false); }} className="w-full py-4 bg-brand-600 text-white rounded-2xl text-xs font-black uppercase tracking-widest shadow-lg">Load List</button>
                          </div>
                      ))
                  )}
              </div>
          </div>
      );
  }

  return (
    <div className="flex flex-col h-full bg-slate-50 dark:bg-slate-900 pb-20 relative">
      <div className="bg-white dark:bg-slate-800 p-6 shadow-sm border-b border-gray-200 dark:border-slate-700 sticky top-0 z-10 flex justify-between items-center">
        <div>
            <h2 className="text-xl font-black text-gray-900 dark:text-white uppercase tracking-tight">Smart List</h2>
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Compare & Save Change</p>
        </div>
        <button onClick={() => setViewingSaved(true)} className="p-3 bg-brand-50 dark:bg-brand-900/30 rounded-2xl text-brand-600 dark:text-brand-400"><FolderOpen className="w-5 h-5" /></button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 pb-48">
        {searchQuery.trim() ? (
          <div className="space-y-4 animate-in fade-in slide-in-from-bottom-5">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Brand Comparison ({searchResults.length} Matches)</h3>
            <div className="grid grid-cols-1 gap-3">
