              </div>
              <p className="text-[8px] opacity-40 uppercase font-bold tracking-widest">Incl. Cashback</p>
            </div>
          </div>
        </div>
      )}

      {/* SEARCH BAR AT BOTTOM (CONSISTENT) */}
      <div className="fixed bottom-20 left-1/2 -translate-x-1/2 w-full max-w-sm px-4 z-40">
           <div className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-2xl rounded-full p-2 border border-slate-100 dark:border-slate-700 shadow-[0_20px_50px_rgba(0,0,0,0.15)] flex items-center transition-all focus-within:ring-4 focus-within:ring-brand-500/20">
              <div className="w-11 h-11 rounded-full bg-slate-50 dark:bg-slate-800 flex items-center justify-center text-slate-400 mr-2 flex-shrink-0 transition-colors">
                 <Search className="w-5 h-5" />
              </div>
              <input 
                type="text" 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Find milk, bread, eggs..." 
                className="flex-1 bg-transparent border-none outline-none py-2 text-sm font-black uppercase tracking-tight dark:text-white placeholder-slate-400"
              />
              {searchQuery && (
                <button onClick={() => setSearchQuery('')} className="w-8 h-8 flex items-center justify-center text-slate-300 hover:text-slate-500 mr-2"><X className="w-5 h-5" /></button>
              )}
              <div className="w-11 h-11 rounded-full bg-brand-600 flex items-center justify-center text-white shadow-lg transition-transform active:scale-90">
                 <Filter className="w-5 h-5" />
              </div>
           </div>
      </div>
    </div>
  );
};

