      case AppTab.WALLET: return <WalletView user={user} transactions={transactions} stores={stores} onUpdateSettings={(t) => setUser({...user, roundUpTarget: t})} onToggleAutoSave={() => setUser({...user, isAutoSaveEnabled: !user.isAutoSaveEnabled})} onUpdateBalance={(a) => setUser({...user, miCoinBalance: user.miCoinBalance + a})} onAddTransaction={(tx) => setTransactions([tx, ...transactions])} onBack={handleGoBack} onOpenBuy={() => setActiveTab(AppTab.BUY)} onOpenLinkCard={() => setActiveTab(AppTab.LINK_CARD)} onViewReceipt={(tx) => setViewingReceipt(tx)} />;
      case AppTab.HISTORY: return <div className="p-5 pb-24"><h2 className="text-xl font-bold mb-4">Activity History</h2>{transactions.map(tx => <div key={tx.id} className="p-4 bg-white mb-2 rounded-xl border flex justify-between items-center cursor-pointer hover:bg-slate-50" onClick={() => tx.receiptData && setViewingReceipt(tx)}><div className="flex-1"><div><span className="font-bold">{tx.store}</span><span className="text-[10px] text-slate-400 ml-2 uppercase font-black">{tx.type}</span></div><div className="text-xs text-slate-500">{tx.date}</div></div><div className="font-black">R {tx.savings.toFixed(2)}</div></div>)}</div>;
      case AppTab.GROCERY_LIST: return <GroceryAssistant stores={stores} shoppingList={shoppingList} savedLists={savedLists} onAddItem={(i) => setShoppingList([...shoppingList, i])} onRemoveItem={(id, sid) => setShoppingList(shoppingList.filter(x => !(x.id === id && x.storeId === sid)))} onUpdateQuantity={(id, sid, d) => setShoppingList(shoppingList.map(x => (x.id === id && x.storeId === sid) ? {...x, quantity: Math.max(1, x.quantity + d)} : x))} onSaveList={(n) => setSavedLists([...savedLists, {id: Date.now().toString(), name: n, date: 'Today', items: [...shoppingList], total: 0, totalSavings: 0}])} onLoadList={(l) => setShoppingList(l.items)} onDeleteList={(id) => setSavedLists(savedLists.filter(x => x.id !== id))} />;
      case AppTab.ASSISTANT: return <ReceiptAssistant onBack={handleGoBack} />;
      case AppTab.BUY: return <BuyStore user={user} onBack={handleGoBack} onUpdateBalance={(a) => setUser({...user, miCoinBalance: user.miCoinBalance + a})} onAddTransaction={(tx) => setTransactions([tx, ...transactions])} />;
      case AppTab.LINK_CARD: return <LinkPhysicalCard onBack={handleGoBack} onSuccess={(num) => { setUser({...user, memberId: num}); handleGoBack(); }} />;
      case AppTab.PROFILE: return <ProfileView user={user} onLogout={() => setActiveTab(AppTab.LOGIN)} onBack={handleGoBack} />;
      default: return <Dashboard user={user} recentTransactions={transactions} stores={stores} onStoreClick={handleStoreClick} onAddCard={() => setActiveTab(AppTab.LINK_CARD)} showBalance={showBalance} onToggleBalance={() => setShowBalance(!showBalance)} onViewReceipt={(tx) => setViewingReceipt(tx)} />;
    }
  };

  const handleBackFromStore = () => {
    setSelectedStore(null);
    setSelectedStoreTab(undefined);
    setActiveTab(AppTab.DASHBOARD);
  };

  return (
    <div className={isDarkMode ? 'dark' : ''}>
      <div className="min-h-screen bg-gray-50 dark:bg-slate-900 font-sans text-slate-900 dark:text-slate-100 flex justify-center">
        <div className="w-full max-w-lg bg-gray-50 dark:bg-slate-900 min-h-screen relative flex flex-col">
          {viewingReceipt && viewingReceipt.receiptData && <DigitalReceipt data={viewingReceipt.receiptData} store={stores.find(s => s.id === viewingReceipt.storeId) || { name: viewingReceipt.store, color: '#475569', logo: '💳' } as any} onClose={() => setViewingReceipt(null)} />}
          {activeTab !== AppTab.STORE_VIEW && activeTab !== AppTab.LOGIN && (
            <header className="bg-white dark:bg-slate-800 px-5 py-4 flex justify-between items-center sticky top-0 z-20 shadow-sm border-b dark:border-slate-700">
              <div className="flex items-center space-x-3">
                {(activeTab !== AppTab.DASHBOARD || showNotifications) && <button onClick={handleGoBack} className="p-2 -ml-2 text-gray-600 dark:text-slate-300"><ArrowLeft className="w-5 h-5" /></button>}
                <div onClick={() => setActiveTab(AppTab.DASHBOARD)} className="text-xl font-black tracking-tighter cursor-pointer"><span>Cardit</span><span className="text-brand-500">Oe'</span></div>
              </div>
              <div className="flex items-center space-x-4">
                <button onClick={toggleTheme}>{isDarkMode ? <Sun className="w-6 h-6 text-slate-300" /> : <Moon className="w-6 h-6 text-gray-600" />}</button>
                <button onClick={() => setShowNotifications(true)} className="relative">
                    <Bell className="w-6 h-6 text-gray-600 dark:text-slate-300" />
                    {totalNotifications > 0 && <span className="absolute top-0 right-0 w-4 h-4 bg-brand-500 text-white text-[8px] font-black rounded-full border-2 border-white dark:border-slate-800 flex items-center justify-center animate-bounce">{totalNotifications}</span>}
                </button>
                <button onClick={() => setActiveTab(AppTab.PROFILE)} className="text-gray-600 dark:text-slate-300"><Menu className="w-6 h-6" /></button>
              </div>
            </header>
          )}
          <main className="flex-1 overflow-y-auto">{renderContent()}</main>
          {activeTab !== AppTab.STORE_VIEW && activeTab !== AppTab.LOGIN && (
            <nav className="bg-white dark:bg-slate-800 border-t dark:border-slate-700 fixed bottom-0 w-full max-w-lg h-16 z-30 flex justify-around items-center">
                <button onClick={() => { setActiveTab(AppTab.DASHBOARD); setShowNotifications(false); }} className={`flex-1 flex flex-col items-center ${activeTab === AppTab.DASHBOARD && !showNotifications ? 'text-brand-600' : 'text-gray-400'}`}><Home className="w-6 h-6" /><span className="text-[10px]">Home</span></button>
                <button onClick={() => setActiveTab(AppTab.WALLET)} className={`flex-1 flex flex-col items-center ${activeTab === AppTab.WALLET ? 'text-brand-600' : 'text-gray-400'}`}><CreditCard className="w-6 h-6" /><span className="text-[10px]">Wallet</span></button>
                <div className="relative -top-6"><button onClick={() => setActiveTab(AppTab.ASSISTANT)} className="w-14 h-14 rounded-full bg-brand-600 text-white flex items-center justify-center shadow-lg border-4 border-gray-50 dark:border-slate-900"><MessageSquare className="w-6 h-6" /></button></div>
                <button onClick={() => setActiveTab(AppTab.GROCERY_LIST)} className={`flex-1 flex flex-col items-center ${activeTab === AppTab.GROCERY_LIST ? 'text-brand-600' : 'text-gray-400'}`}><ShoppingBasket className="w-6 h-6" /><span className="text-[10px]">List</span></button>
                <button onClick={() => setActiveTab(AppTab.HISTORY)} className={`flex-1 flex flex-col items-center ${activeTab === AppTab.HISTORY ? 'text-brand-600' : 'text-gray-400'}`}><History className="w-6 h-6" /><span className="text-[10px]">History</span></button>
            </nav>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Store, Transaction, StoreBranch, Product } from '../types';
import { ArrowLeft, ShoppingBag, Receipt, Percent, Star, Clock, Search, AlertTriangle, ChevronRight, Sparkles, Loader2, Coins, Zap, UserPlus, ShieldCheck, X, CreditCard, MapPin, Check, Filter, Lock, Plus } from 'lucide-react';
import { CARDITOE_GLOBAL_PROMOS } from '../App';

interface StoreDetailProps {
  store: Store;
  initialTab?: 'SHOP' | 'RECEIPTS' | 'PROMOS' | 'LOYALTY';
  transactions: Transaction[];
  onBack: () => void;
  onUpdateStore: (updatedStore: Store) => void;
  onUpdateBalance?: (amount: number) => void;
  onAddTransaction?: (tx: Transaction) => void;
  onViewReceipt: (tx: Transaction) => void;
}

type Tab = 'SHOP' | 'RECEIPTS' | 'PROMOS' | 'LOYALTY';

const StoreDetail: React.FC<StoreDetailProps> = ({ store, initialTab, transactions, onBack, onUpdateStore, onUpdateBalance, onAddTransaction, onViewReceipt }) => {
  const [activeTab, setActiveTab] = useState<Tab>(initialTab || 'SHOP');
  const [isRegistering, setIsRegistering] = useState(false);
  const [itemSearchQuery, setItemSearchQuery] = useState('');
  const [branchSearchQuery, setBranchSearchQuery] = useState('');
  const [selectedBranch, setSelectedBranch] = useState<StoreBranch | null>(store.branches?.[0] || null);

  useEffect(() => {
    if (initialTab) {
        setActiveTab(initialTab);
        return;
    }

    if (store.isLinked) {
        if (store.tabAlerts.loyalty > 0 || (store.pointsExpiring || 0) > 0) setActiveTab('LOYALTY');
        else if (store.tabAlerts.slips > 0) setActiveTab('RECEIPTS');
        else if (store.tabAlerts.promos > 0) setActiveTab('PROMOS');
        else setActiveTab('SHOP');
    }
  }, [store.id, store.isLinked, initialTab]);

  const storeTransactions = transactions.filter(t => t.store === store.name || t.storeId === store.id || t.store.includes(store.name));

  const handleRegister = () => {
    setIsRegistering(true);
    setTimeout(() => {
      onUpdateStore({ ...store, isLinked: true });
      setIsRegistering(false);
    }, 2000);
  };

  const getAlertCount = (id: string) => {
    if (id === 'RECEIPTS') return store.tabAlerts.slips;
    if (id === 'PROMOS') return store.tabAlerts.promos + CARDITOE_GLOBAL_PROMOS.length;
    if (id === 'LOYALTY') return store.tabAlerts.loyalty + ((store.pointsExpiring || 0) > 0 ? 1 : 0);
    return 0;
  };

  const globalBrandSearchResults = useMemo(() => {
    if (!itemSearchQuery.trim()) return [];

    let allResults: { product: Product, branch: StoreBranch }[] = [];
    const brandBranches = store.branches || [];

    brandBranches.forEach(branch => {
      store.inventory.forEach(item => {
        const matchesQuery = item.name.toLowerCase().includes(itemSearchQuery.toLowerCase()) || 
                            item.category.toLowerCase().includes(itemSearchQuery.toLowerCase());

        const isAvailableAtThisBranch = branch.inventoryIds.includes(item.id);

        if (matchesQuery && isAvailableAtThisBranch) {
          allResults.push({ product: item, branch: branch });
        }
      });
    });

    return allResults;
  }, [itemSearchQuery, store.inventory, store.branches]);

  const filteredBranches = useMemo(() => {
    if (!store.branches) return [];
    return store.branches.filter(b => 
        b.name.toLowerCase().includes(branchSearchQuery.toLowerCase()) || 
        b.city.toLowerCase().includes(branchSearchQuery.toLowerCase()) ||
        b.address.toLowerCase().includes(branchSearchQuery.toLowerCase())
    );
  }, [store.branches, branchSearchQuery]);

  const renderShop = () => {
    return (
      <div className="flex flex-col h-full relative">
        <div className="mb-6 space-y-3">
          <div className="flex items-center justify-between px-1">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Branch Location</h3>
            {selectedBranch && (
              <div className="flex items-center text-[10px] font-bold text-brand-600 bg-brand-50 px-2 py-0.5 rounded-full">
                <Check className="w-2.5 h-2.5 mr-1" />
                <span>Checked In</span>
              </div>
            )}
          </div>
          <div className="relative group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-brand-500 transition-colors" />
            <input 
              type="text" 
              value={branchSearchQuery}
              onChange={(e) => setBranchSearchQuery(e.target.value)}
              placeholder={`Search ${store.name} branches...`} 
              className="w-full bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl pl-11 pr-4 py-4 text-sm outline-none focus:ring-2 focus:ring-brand-500 dark:text-white shadow-sm transition-all"
            />
          </div>

          {branchSearchQuery && (
            <div className="bg-white dark:bg-slate-800 rounded-[2rem] border border-slate-100 dark:border-slate-700 shadow-xl overflow-hidden animate-in slide-in-from-top-2 duration-300 max-h-[280px] overflow-y-auto scrollbar-hide">
              {filteredBranches.map(branch => (
                <button 
                  key={branch.id}
                  onClick={() => {
                    setSelectedBranch(branch);
                    setBranchSearchQuery('');
                  }}
                  className={`w-full flex items-center justify-between p-4 border-b border-slate-50 dark:border-slate-700 last:border-0 hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors ${selectedBranch?.id === branch.id ? 'bg-brand-50/50 dark:bg-brand-900/10' : ''}`}
                >
                  <div className="flex items-center space-x-3 text-left">
                    <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${selectedBranch?.id === branch.id ? 'bg-brand-500 text-white' : 'bg-slate-100 dark:bg-slate-700 text-slate-400'}`}>
                      <MapPin className="w-5 h-5" />
                    </div>
                    <div>
                      <p className="text-xs font-black text-slate-900 dark:text-white uppercase tracking-tight">{branch.name}</p>
                      <p className="text-[9px] text-slate-500 dark:text-slate-400 font-medium">{branch.city}, {branch.province}</p>
                    </div>
                  </div>
                  {selectedBranch?.id === branch.id && <div className="w-6 h-6 rounded-full bg-brand-500 text-white flex items-center justify-center"><Check className="w-4 h-4" /></div>}
                </button>
              ))}
            </div>
          )}
        </div>

        <div className="flex-1 pb-32">
          {itemSearchQuery ? (
            <div className="space-y-4 animate-in fade-in duration-300">
               <div className="flex items-center justify-between px-1">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Brand Stock Results ({globalBrandSearchResults.length})</p>
               </div>
               <div className="grid grid-cols-1 gap-3">
                  {globalBrandSearchResults.map(({ product, branch }) => (
                    <div key={`${product.id}-${branch.id}`} className="bg-white dark:bg-slate-800 p-4 rounded-[1.8rem] border border-slate-100 dark:border-slate-700 shadow-sm flex items-center group active:scale-[0.98] transition-all">
                      <div className="w-16 h-16 bg-slate-50 dark:bg-slate-700 rounded-2xl flex items-center justify-center text-3xl mr-4 flex-shrink-0 relative">
                        {product.image || '📦'}
                        <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-white rounded-full flex items-center justify-center shadow-sm border border-slate-200">
                            <span className="text-[8px]">{store.logo}</span>
                        </div>
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex justify-between items-start mb-0.5">
                          <h4 className="font-black text-xs text-gray-800 dark:text-white truncate uppercase tracking-tight">{product.name}</h4>
                          <span className="font-black text-sm ml-2 flex-shrink-0" style={{ color: store.color }}>R {product.price.toFixed(2)}</span>
                        </div>
                        <div className="flex flex-col space-y-1">
                           <div className="flex items-center text-[9px] font-black uppercase text-slate-500 truncate">
                              <MapPin className="w-2.5 h-2.5 mr-1 text-brand-500" />
                              {branch.name}
                           </div>
                        </div>
                      </div>
                      <button className="ml-4 w-10 h-10 rounded-2xl flex items-center justify-center text-white shadow-lg active:scale-90 transition-transform" style={{ backgroundColor: store.color }}><Plus className="w-5 h-5" /></button>
                    </div>
                  ))}
               </div>
            </div>
          ) : (
            <div className="space-y-6">
              <div className="flex items-center justify-between px-1">
                <div>
                    <h3 className="text-sm font-black text-slate-800 dark:text-white uppercase tracking-tight">At {selectedBranch?.name || 'this branch'}</h3>
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-0.5">Current Store Stock</p>
                </div>
                <div className="w-10 h-10 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center text-slate-400"><Filter className="w-4 h-4" /></div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                {store.inventory.filter(i => selectedBranch?.inventoryIds.includes(i.id)).map(item => (
                    <div key={item.id} className="bg-white dark:bg-slate-800 p-4 rounded-[2.2rem] border border-slate-100 dark:border-slate-700 shadow-sm relative group active:scale-95 transition-all">
                        <div className="h-32 w-full bg-slate-50 dark:bg-slate-700 rounded-3xl mb-4 flex items-center justify-center text-4xl shadow-inner group-hover:scale-105 transition-transform">{item.image || '📦'}</div>
                        <h4 className="font-black text-xs text-gray-800 dark:text-white line-clamp-1 px-1 uppercase tracking-tight">{item.name}</h4>
                        <div className="flex justify-between items-center mt-4 px-1">
                            <span className="font-black text-sm" style={{ color: store.color }}>R {item.price.toFixed(2)}</span>
                            <button className="w-10 h-10 rounded-2xl flex items-center justify-center text-white shadow-lg" style={{ backgroundColor: store.color }}><Plus className="w-5 h-5" /></button>
                        </div>
                    </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <div className="fixed bottom-24 left-1/2 -translate-x-1/2 w-full max-w-sm px-4 z-40">
           <div className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-2xl rounded-full p-2 border border-white/20 dark:border-slate-700 shadow-[0_20px_50px_rgba(0,0,0,0.15)] flex items-center transition-all focus-within:ring-4 focus-within:ring-brand-500/20">
              <div className="w-11 h-11 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-slate-400 mr-2 flex-shrink-0 transition-colors">
                 <Search className="w-5 h-5" />
              </div>
              <input 
                type="text" 
                value={itemSearchQuery}
                onChange={(e) => setItemSearchQuery(e.target.value)}
                placeholder="Search items globally..." 
                className="flex-1 bg-transparent border-none outline-none py-2 text-sm font-black uppercase tracking-tight dark:text-white placeholder-slate-400"
              />
              {itemSearchQuery && (
                <button onClick={() => setItemSearchQuery('')} className="w-8 h-8 flex items-center justify-center text-slate-300 hover:text-slate-500 transition-colors mr-2"><X className="w-5 h-5" /></button>
              )}
              <div className="w-11 h-11 rounded-full flex items-center justify-center text-white shadow-lg transition-transform active:scale-90" style={{ backgroundColor: store.color }}>
                 <ShoppingBag className="w-5 h-5" />
              </div>
           </div>
        </div>
      </div>
    );
  };

  const renderLoyalty = () => (
    <div className="space-y-6">
        {/* RESTORED EXPIRY ALERT */}
        {(store.pointsExpiring || 0) > 0 && (
          <div className="bg-amber-50 dark:bg-amber-900/20 p-5 rounded-[2.5rem] border border-amber-200 dark:border-amber-800 flex items-start space-x-4 animate-in slide-in-from-top-4 duration-500">
            <div className="w-12 h-12 bg-amber-500 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-amber-500/20 animate-pulse">
              <AlertTriangle className="w-6 h-6" />
            </div>
            <div className="flex-1">
              <h4 className="text-sm font-black text-amber-900 dark:text-amber-100 uppercase tracking-tight">Points Expiring!</h4>
              <p className="text-[11px] text-amber-700 dark:text-amber-400 font-bold uppercase tracking-widest mt-0.5">
                R {(store.pointsExpiring! / 100).toFixed(2)} will be lost soon.
              </p>
              <button className="mt-3 text-[10px] font-black text-amber-600 bg-amber-100 px-3 py-1.5 rounded-full uppercase tracking-widest">Use Now</button>
            </div>
          </div>
        )}

        <div className="rounded-[2.5rem] p-8 text-white shadow-xl relative overflow-hidden" style={{ backgroundColor: store.color }}>
            <div className="absolute top-0 right-0 w-48 h-48 bg-white opacity-10 rounded-full -mr-12 -mt-12"></div>
            <p className="text-[10px] text-white/80 uppercase tracking-widest mb-1 font-black">Points Balance</p>
            <h3 className="text-5xl font-mono font-bold mb-2 tracking-tighter">{store.loyaltyPoints} <span className="text-lg font-sans font-normal text-white/70">pts</span></h3>
            <div className="flex items-center text-amber-300 font-bold text-lg mb-4"><Coins className="w-5 h-5 mr-2" />R {(store.loyaltyPoints/100).toFixed(2)}</div>

            <div className="bg-white/10 backdrop-blur-md rounded-2xl p-4 border border-white/10">
               <div className="flex items-center justify-between mb-2">
                 <span className="text-[10px] font-black uppercase tracking-widest">Next Tier Progress</span>
                 <span className="text-[10px] font-bold">75%</span>
               </div>
               <div className="w-full h-1.5 bg-black/20 rounded-full overflow-hidden">
                 <div className="h-full bg-white rounded-full" style={{ width: '75%' }}></div>
               </div>
            </div>
        </div>
    </div>
  );

  const renderReceipts = () => (
    <div className="space-y-4 pb-20">
       {storeTransactions.length === 0 ? (
           <div className="text-center py-20 text-slate-400">
               <Receipt className="w-12 h-12 mx-auto mb-3 opacity-20" />
               <p className="text-sm font-medium">No digital slips found.</p>
           </div>
       ) : (
           storeTransactions.map(tx => (
              <div key={tx.id} onClick={() => tx.receiptData && onViewReceipt(tx)} className="bg-white dark:bg-slate-800 p-5 rounded-[2rem] border-l-4 shadow-sm relative overflow-hidden transition-all active:scale-95 cursor-pointer hover:shadow-md" style={{ borderLeftColor: store.color }}>
                <div className="flex justify-between items-start mb-2">
                   <div>
                      <h4 className="font-black text-slate-900 dark:text-white text-sm uppercase tracking-tight">{tx.store}</h4>
                      <p className="text-[10px] text-slate-500 dark:text-slate-400 font-bold uppercase tracking-widest">{tx.date}</p>
                   </div>
                   <div className="text-right">
                      <span className="block font-black text-lg dark:text-white">R {tx.amount > 0 ? tx.amount.toFixed(2) : tx.savings.toFixed(2)}</span>
                      <span className="text-[10px] font-black uppercase tracking-tighter" style={{ color: store.color }}>
                        {tx.type === 'CASHOUT' ? 'Voucher' : `Saved R${tx.savings.toFixed(2)}`}
                      </span>
                   </div>
                </div>
                <div className="border-t border-dashed border-slate-100 dark:border-slate-700 my-4"></div>
                <div className="flex justify-between items-center">
                    <span className="text-[9px] bg-slate-50 dark:bg-slate-700 text-slate-400 px-3 py-1 rounded-full uppercase font-black">Auth: 228492</span>
                    <button className="text-[10px] font-black uppercase flex items-center" style={{ color: store.color }}>View Slip <ChevronRight className="w-3 h-3 ml-0.5" /></button>
                </div>
              </div>
           ))
       )}
    </div>
