                        <MapPin className="w-4 h-4 mr-2" />
                        <span className="text-[11px] font-black uppercase tracking-widest">{selectedBranch?.name || 'Near You'}</span>
                    </div>
                </div>
            </div>
            <div className="text-right">
                <p className="text-[11px] font-black uppercase text-white/50 tracking-[0.3em] mb-1">Loyalty Points</p>
                <p className="text-3xl font-black font-mono tracking-tighter">{store.loyaltyPoints}</p>
            </div>
         </div>
      </div>

      {store.isLinked ? (
          <>
            <div className="px-6 -mt-10 relative z-20">
                <div className="bg-white/80 dark:bg-slate-800/80 backdrop-blur-2xl rounded-[3rem] shadow-2xl p-2.5 flex justify-between items-center border-2 border-white/20 dark:border-slate-700">
                    {[
                        { id: 'SHOP', icon: ShoppingBag, label: 'Shop' },
                        { id: 'RECEIPTS', icon: Receipt, label: 'Slips' },
                        { id: 'PROMOS', icon: Percent, label: 'Deals' },
                        { id: 'LOYALTY', icon: Star, label: 'Points' },
                    ].map((tab) => {
                        const alertCount = getAlertCount(tab.id);
                        return (
                            <button key={tab.id} onClick={() => { setActiveTab(tab.id as Tab); }} className={`flex-1 flex flex-col items-center py-4 rounded-[2.5rem] transition-all relative active:scale-90 ${activeTab === tab.id ? 'bg-white dark:bg-slate-700 shadow-xl' : 'text-slate-400 dark:text-slate-500'}`} style={activeTab === tab.id ? { color: store.color } : {}}>
                                <div className="relative mb-1">
                                    <tab.icon className="w-6 h-6" />
                                    {alertCount > 0 && <span className="absolute -top-1 -right-1 w-3.5 h-3.5 bg-red-500 rounded-full border-2 border-white dark:border-slate-800 animate-pulse"></span>}
                                </div>
                                <span className="text-[10px] font-black uppercase tracking-widest leading-none">{tab.label}</span>
                            </button>
                        );
                    })}
                </div>
            </div>
            <div className="flex-1 overflow-y-auto p-6">
                {activeTab === 'PROMOS' ? renderPromos() : <div className="flex items-center justify-center h-40 text-slate-300 uppercase font-black tracking-widest text-xs">Viewing {activeTab} Tab</div>}
            </div>
          </>
      ) : <div className="flex flex-col items-center justify-center p-12 text-center h-full"><Lock className="w-16 h-16 text-slate-300 mb-6" /><h3 className="text-2xl font-black uppercase tracking-tight mb-2">Private Store</h3><p className="text-sm text-slate-400 mb-10">Link your {store.name} card to see deals.</p><button onClick={handleRegister} className="w-full py-5 bg-brand-600 text-white rounded-[2rem] font-black uppercase tracking-widest shadow-xl">Connect Card</button></div>}
    </div>
  );
};

