const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.LOGIN);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [stores, setStores] = useState<Store[]>(INITIAL_STORES);
  const [transactions, setTransactions] = useState<Transaction[]>(INITIAL_TRANSACTIONS);
  const [selectedStore, setSelectedStore] = useState<Store | null>(null);
  const [selectedStoreTab, setSelectedStoreTab] = useState<string | undefined>(undefined);
  const [user, setUser] = useState<User>(MOCK_USER);
  const [showBalance, setShowBalance] = useState(true);
  const [viewingReceipt, setViewingReceipt] = useState<Transaction | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const [shoppingList, setShoppingList] = useState<ShoppingListItem[]>([]);
  const [savedLists, setSavedLists] = useState<SavedList[]>([]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleStoreClick = (store: Store, tab?: string) => {
    setSelectedStore(store);
    setSelectedStoreTab(tab);
    setActiveTab(AppTab.STORE_VIEW);
  };

  const handleGoBack = () => {
    setActiveTab(AppTab.DASHBOARD);
    setSelectedStore(null);
    setSelectedStoreTab(undefined);
    setShowNotifications(false);
  };

  const totalNotifications = stores.reduce((acc, s) => acc + s.notificationCount, 0) + CARDITOE_GLOBAL_PROMOS.length;

  const renderNotifications = () => (
      <div className="flex flex-col h-full bg-slate-50 dark:bg-slate-900 animate-in slide-in-from-right-10 duration-300">
          <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center bg-white dark:bg-slate-900 sticky top-0 z-10">
              <button onClick={() => setShowNotifications(false)} className="p-3 -ml-3 mr-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full">
                  <ArrowLeft className="w-6 h-6 text-slate-900 dark:text-white" />
              </button>
              <h2 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Updates</h2>
          </div>
          <div className="flex-1 overflow-y-auto p-6 space-y-8 pb-24">
              {/* CarditOe Originals */}
              <div className="space-y-4">
                  <div className="flex items-center space-x-2 px-1">
                      <div className="w-2.5 h-2.5 rounded-full bg-brand-500 animate-pulse"></div>
                      <span className="text-[10px] font-black uppercase tracking-widest text-brand-600">CarditOe Boosts</span>
                  </div>
                  {CARDITOE_GLOBAL_PROMOS.map(promo => (
                      <div key={promo.id} className="bg-white dark:bg-slate-800 p-5 rounded-[2.2rem] border-2 border-brand-100 dark:border-brand-900/30 flex items-start space-x-4 shadow-xl shadow-brand-500/5">
                          <div className="bg-brand-500 p-3 rounded-2xl text-white shadow-lg shadow-brand-500/30 text-2xl">
                              {promo.image}
                          </div>
                          <div className="flex-1">
                              <div className="flex justify-between items-center">
                                  <p className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-tight">{promo.name}</p>
                                  <div className="bg-brand-50 px-2 py-0.5 rounded-lg">
                                    <Star className="w-3 h-3 text-brand-600 fill-brand-600" />
                                  </div>
                              </div>
                              <p className="text-[11px] text-slate-500 dark:text-slate-400 font-bold mt-1 leading-relaxed">{promo.promoDescription}</p>
                          </div>
                      </div>
                  ))}
              </div>

              {/* Store Alerts */}
              {stores.filter(s => s.isLinked && s.notificationCount > 0).map(store => (
                  <div key={store.id} className="space-y-4">
                      <div className="flex items-center space-x-2 px-1">
                          <span className="text-lg">{store.logo}</span>
                          <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">{store.name}</span>
                      </div>
                      {store.pointsExpiring && (
                          <div onClick={() => { handleStoreClick(store, 'LOYALTY'); setShowNotifications(false); }} className="bg-amber-50 dark:bg-amber-900/20 p-5 rounded-[2.2rem] border border-amber-200 dark:border-amber-800 flex items-start space-x-4 cursor-pointer active:scale-95 transition-all shadow-sm">
