  const renderContent = () => {
    if (showNotifications) return renderNotifications();
    switch (activeTab) {
      case AppTab.LOGIN: return <Login onLogin={() => setActiveTab(AppTab.DASHBOARD)} />;
      case AppTab.DASHBOARD: return <Dashboard user={user} recentTransactions={transactions} stores={stores} onStoreClick={handleStoreClick} onAddCard={() => setActiveTab(AppTab.LINK_CARD)} showBalance={showBalance} onToggleBalance={() => setShowBalance(!showBalance)} onViewReceipt={(tx) => setViewingReceipt(tx)} />;
      // Fix: replacing undefined handleBackFromStore with the existing handleGoBack function.
      case AppTab.STORE_VIEW: return selectedStore ? <StoreDetail store={selectedStore} initialTab={selectedStoreTab as any} transactions={transactions} onBack={handleGoBack} onUpdateStore={(s) => setStores(stores.map(x => x.id === s.id ? s : x))} onViewReceipt={(tx) => setViewingReceipt(tx)} /> : null;
      case AppTab.WALLET: return <WalletView user={user} transactions={transactions} stores={stores} onUpdateSettings={(t) => setUser({...user, roundUpTarget: t})} onToggleAutoSave={() => setUser({...user, isAutoSaveEnabled: !user.isAutoSaveEnabled})} onUpdateBalance={(a) => setUser({...user, miCoinBalance: user.miCoinBalance + a})} onAddTransaction={(tx) => setTransactions([tx, ...transactions])} onBack={handleGoBack} onOpenBuy={() => setActiveTab(AppTab.BUY)} onOpenLinkCard={() => setActiveTab(AppTab.LINK_CARD)} onViewReceipt={(tx) => setViewingReceipt(tx)} />;
      case AppTab.HISTORY: return <div className="p-6 pb-24 space-y-6"><h2 className="text-2xl font-black uppercase tracking-tight">Past Wins</h2>{transactions.map(tx => <div key={tx.id} className="p-5 bg-white dark:bg-slate-800 mb-4 rounded-[2rem] border border-slate-100 dark:border-slate-700 flex justify-between items-center cursor-pointer hover:shadow-lg transition-all" onClick={() => tx.receiptData && setViewingReceipt(tx)}><div className="flex-1"><div><span className="font-black text-sm uppercase tracking-tight">{tx.store}</span><span className="text-[10px] text-slate-400 ml-3 uppercase font-black tracking-widest">{tx.type}</span></div><div className="text-[10px] text-slate-500 font-bold uppercase mt-1">{tx.date}</div></div><div className="font-black text-brand-600 text-lg">R {tx.savings.toFixed(2)}</div></div>)}</div>;
      case AppTab.GROCERY_LIST: return <GroceryAssistant stores={stores} shoppingList={shoppingList} savedLists={savedLists} onAddItem={(i) => setShoppingList([...shoppingList, i])} onRemoveItem={(id, sid) => setShoppingList(shoppingList.filter(x => !(x.id === id && x.storeId === sid)))} onUpdateQuantity={(id, sid, d) => setShoppingList(shoppingList.map(x => (x.id === id && x.storeId === sid) ? {...x, quantity: Math.max(1, x.quantity + d)} : x))} onSaveList={(n) => setSavedLists([...savedLists, {id: Date.now().toString(), name: n, date: 'Today', items: [...shoppingList], total: 0, totalSavings: 0}])} onLoadList={(l) => setShoppingList(l.items)} onDeleteList={(id) => setSavedLists(savedLists.filter(x => x.id !== id))} />;
      case AppTab.ASSISTANT: return <ReceiptAssistant onBack={handleGoBack} />;
      case AppTab.BUY: return <BuyStore user={user} onBack={handleGoBack} onUpdateBalance={(a) => setUser({...user, miCoinBalance: user.miCoinBalance + a})} onAddTransaction={(tx) => setTransactions([tx, ...transactions])} />;
      case AppTab.LINK_CARD: return <LinkPhysicalCard onBack={handleGoBack} onSuccess={(num) => { setUser({...user, memberId: num}); handleGoBack(); }} />;
      case AppTab.PROFILE: return <ProfileView user={user} onLogout={() => setActiveTab(AppTab.LOGIN)} onBack={handleGoBack} />;
      default: return <Dashboard user={user} recentTransactions={transactions} stores={stores} onStoreClick={handleStoreClick} onAddCard={() => setActiveTab(AppTab.LINK_CARD)} showBalance={showBalance} onToggleBalance={() => setShowBalance(!showBalance)} onViewReceipt={(tx) => setViewingReceipt(tx)} />;
    }
  };

  return (
    <div className={isDarkMode ? 'dark' : ''}>
      <div className="min-h-screen bg-gray-50 dark:bg-slate-900 font-sans text-slate-900 dark:text-slate-100 flex justify-center">
        <div className="w-full max-w-lg bg-gray-50 dark:bg-slate-900 min-h-screen relative flex flex-col">
          {viewingReceipt && viewingReceipt.receiptData && <DigitalReceipt data={viewingReceipt.receiptData} store={stores.find(s => s.id === viewingReceipt.storeId) || { name: viewingReceipt.store, color: '#475569', logo: '💳' } as any} onClose={() => setViewingReceipt(null)} />}
          {activeTab !== AppTab.STORE_VIEW && activeTab !== AppTab.LOGIN && (
            <header className="bg-white dark:bg-slate-800 px-6 py-5 flex justify-between items-center sticky top-0 z-20 shadow-sm border-b dark:border-slate-700">
              <div className="flex items-center space-x-4">
                {(activeTab !== AppTab.DASHBOARD || showNotifications) && <button onClick={handleGoBack} className="p-3 -ml-3 text-gray-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full transition-all"><ArrowLeft className="w-6 h-6" /></button>}
                <div onClick={() => setActiveTab(AppTab.DASHBOARD)} className="text-2xl font-black tracking-tighter cursor-pointer flex items-baseline"><span>Cardit</span><span className="text-brand-500">Oe'</span></div>
              </div>
              <div className="flex items-center space-x-3">
                <button onClick={toggleTheme} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-2xl transition-all">{isDarkMode ? <Sun className="w-6 h-6 text-slate-300" /> : <Moon className="w-6 h-6 text-gray-600" />}</button>
                <button onClick={() => setShowNotifications(true)} className="relative p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-2xl transition-all">
                    <Bell className="w-6 h-6 text-gray-600 dark:text-slate-300" />
                    {totalNotifications > 0 && <span className="absolute top-1 right-1 w-4 h-4 bg-red-500 text-white text-[8px] font-black rounded-full border-2 border-white dark:border-slate-800 flex items-center justify-center animate-bounce">{totalNotifications}</span>}
                </button>
                <button onClick={() => setActiveTab(AppTab.PROFILE)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-2xl transition-all text-gray-600 dark:text-slate-300"><Menu className="w-6 h-6" /></button>
              </div>
            </header>
          )}
          <main className="flex-1 overflow-y-auto">{renderContent()}</main>
          {activeTab !== AppTab.STORE_VIEW && activeTab !== AppTab.LOGIN && (
            <nav className="bg-white/80 dark:bg-slate-800/80 backdrop-blur-xl border-t dark:border-slate-700 fixed bottom-0 w-full max-w-lg h-20 z-30 flex justify-around items-center px-4">
                <button onClick={() => { setActiveTab(AppTab.DASHBOARD); setShowNotifications(false); }} className={`flex-1 flex flex-col items-center justify-center h-full space-y-1 transition-all active:scale-90 ${activeTab === AppTab.DASHBOARD && !showNotifications ? 'text-brand-600' : 'text-gray-400'}`}><Home className="w-7 h-7" /><span className="text-[10px] font-black uppercase tracking-widest">Home</span></button>
                <button onClick={() => setActiveTab(AppTab.WALLET)} className={`flex-1 flex flex-col items-center justify-center h-full space-y-1 transition-all active:scale-90 ${activeTab === AppTab.WALLET ? 'text-brand-600' : 'text-gray-400'}`}><CreditCard className="w-7 h-7" /><span className="text-[10px] font-black uppercase tracking-widest">Wallet</span></button>
                <div className="relative -top-8"><button onClick={() => setActiveTab(AppTab.ASSISTANT)} className="w-16 h-16 rounded-[2rem] bg-brand-600 text-white flex items-center justify-center shadow-xl shadow-brand-500/30 border-4 border-gray-50 dark:border-slate-900 active:scale-90 transition-all"><MessageSquare className="w-7 h-7" /></button></div>
                <button onClick={() => setActiveTab(AppTab.GROCERY_LIST)} className={`flex-1 flex flex-col items-center justify-center h-full space-y-1 transition-all active:scale-90 ${activeTab === AppTab.GROCERY_LIST ? 'text-brand-600' : 'text-gray-400'}`}><ShoppingBasket className="w-7 h-7" /><span className="text-[10px] font-black uppercase tracking-widest">List</span></button>
                <button onClick={() => setActiveTab(AppTab.HISTORY)} className={`flex-1 flex flex-col items-center justify-center h-full space-y-1 transition-all active:scale-90 ${activeTab === AppTab.HISTORY ? 'text-brand-600' : 'text-gray-400'}`}><History className="w-7 h-7" /><span className="text-[10px] font-black uppercase tracking-widest">Slips</span></button>
            </nav>
          )}
        </div>
      </div>
    </div>
  );
};

